        sp->encodepfunc = fpDiff;
        /*
         * Override default encoding method with one that does the
         * predictor stuff.
         */
        if (tif->tif_encoderow != PredictorEncodeRow)
        {
            sp->encoderow = tif->tif_encoderow;
            tif->tif_encoderow = PredictorEncodeRow;
            sp->encodestrip = tif->tif_encodestrip;
            tif->tif_encodestrip = PredictorEncodeTile;
            sp->encodetile = tif->tif_encodetile;
            tif->tif_encodetile = PredictorEncodeTile;
        }
        /*
         * The data should not be swapped outside of the floating
         * point predictor, the differentiation routine should return
         * bytes in the native order.
         */
        if (tif->tif_flags & TIFF_SWAB)
        {
            tif->tif_postdecode = _TIFFNoPostDecode;
        }
    }

    return 1;
}

static int fpAcc(TIFF *tif, uint8_t *cp0, tmsize_t cc)
{
    tmsize_t stride = PredictorState(tif)->stride;
    uint32_t bps = tif->tif_dir.td_bitspersample / 8;
    tmsize_t wc = cc / bps;
    tmsize_t count = cc;
    uint8_t *cp = cp0;
    uint8_t *tmp;

    if (cc % (bps * stride) != 0)
    {
        TIFFErrorExtR(tif, "fpAcc", "%s", "cc%(bps*stride))!=0");
        return 0;
    }

    tmp = (uint8_t *)_TIFFmallocExt(tif, cc);
    if (!tmp)
        return 0;

    if (stride == 1)
    {
        /* Optimization of general case */
#define OP                                                                     \
    do                                                                         \
    {                                                                          \
        cp[1] = (uint8_t)((cp[1] + cp[0]) & 0xff);                             \
        ++cp;                                                                  \
    } while (0)
        for (; count > 8; count -= 8)
        {
            OP;
            OP;
            OP;
            OP;
            OP;
            OP;
            OP;
            OP;
        }
        for (; count > 1; count -= 1)
        {
            OP;
        }
#undef OP
    }
    else
    {
        while (count > stride)
        {
            REPEAT4(stride, cp[stride] = (uint8_t)((cp[stride] + cp[0]) & 0xff);
                    cp++)
            count -= stride;
        }
    }

    _TIFFmemcpy(tmp, cp0, cc);
    cp = (uint8_t *)cp0;
    count = 0;

#if defined(__x86_64__) || defined(_M_X64)
    if (bps == 4)
    {
        /* Optimization of general case */
        for (; count + 15 < wc; count += 16)
        {
            /* Interlace 4*16 byte values */

            __m128i xmm0 =
                _mm_loadu_si128((const __m128i *)(tmp + count + 3 * wc));
            __m128i xmm1 =
                _mm_loadu_si128((const __m128i *)(tmp + count + 2 * wc));
            __m128i xmm2 =
                _mm_loadu_si128((const __m128i *)(tmp + count + 1 * wc));
            __m128i xmm3 =
                _mm_loadu_si128((const __m128i *)(tmp + count + 0 * wc));
            /* (xmm0_0, xmm1_0, xmm0_1, xmm1_1, xmm0_2, xmm1_2, ...) */
            __m128i tmp0 = _mm_unpacklo_epi8(xmm0, xmm1);
            /* (xmm0_8, xmm1_8, xmm0_9, xmm1_9, xmm0_10, xmm1_10, ...) */
            __m128i tmp1 = _mm_unpackhi_epi8(xmm0, xmm1);
            /* (xmm2_0, xmm3_0, xmm2_1, xmm3_1, xmm2_2, xmm3_2, ...) */
            __m128i tmp2 = _mm_unpacklo_epi8(xmm2, xmm3);
            /* (xmm2_8, xmm3_8, xmm2_9, xmm3_9, xmm2_10, xmm3_10, ...) */
            __m128i tmp3 = _mm_unpackhi_epi8(xmm2, xmm3);
            /* (xmm0_0, xmm1_0, xmm2_0, xmm3_0, xmm0_1, xmm1_1, xmm2_1, xmm3_1,
             * ...) */
            __m128i tmp2_0 = _mm_unpacklo_epi16(tmp0, tmp2);
            __m128i tmp2_1 = _mm_unpackhi_epi16(tmp0, tmp2);
            __m128i tmp2_2 = _mm_unpacklo_epi16(tmp1, tmp3);
            __m128i tmp2_3 = _mm_unpackhi_epi16(tmp1, tmp3);
            _mm_storeu_si128((__m128i *)(cp + 4 * count + 0 * 16), tmp2_0);
            _mm_storeu_si128((__m128i *)(cp + 4 * count + 1 * 16), tmp2_1);
            _mm_storeu_si128((__m128i *)(cp + 4 * count + 2 * 16), tmp2_2);
            _mm_storeu_si128((__m128i *)(cp + 4 * count + 3 * 16), tmp2_3);
        }
    }
#endif

    for (; count < wc; count++)
    {
        uint32_t byte;
        for (byte = 0; byte < bps; byte++)
        {
#if WORDS_BIGENDIAN
            cp[bps * count + byte] = tmp[byte * wc + count];
#else
            cp[bps * count + byte] = tmp[(bps - byte - 1) * wc + count];
#endif
        }
    }
    _TIFFfreeExt(tif, tmp);
    return 1;
}

/*   since the behavior of "overflows" is defined (wrap over) */
/* - when storing into the byte stream, we explicitly mask with 0xff so */
/*   as to make icc -check=conversions happy (not necessary by the standard) */

TIFF_NOSANITIZE_UNSIGNED_INT_OVERFLOW
static int horAcc8(TIFF *tif, uint8_t *cp0, tmsize_t cc)
{
    tmsize_t stride = PredictorState(tif)->stride;

    uint8_t *cp = cp0;
    if ((cc % stride) != 0)
    {
        TIFFErrorExtR(tif, "horAcc8", "%s", "(cc%stride)!=0");
        return 0;
    }

    if (cc > stride)
    {
        /*
         * Pipeline the most common cases.
         */
        if (stride == 1)
        {
            uint32_t acc = cp[0];
            tmsize_t i = stride;
            for (; i < cc - 3; i += 4)
            {
                cp[i + 0] = (uint8_t)((acc += cp[i + 0]) & 0xff);
                cp[i + 1] = (uint8_t)((acc += cp[i + 1]) & 0xff);
                cp[i + 2] = (uint8_t)((acc += cp[i + 2]) & 0xff);
                cp[i + 3] = (uint8_t)((acc += cp[i + 3]) & 0xff);
            }
            for (; i < cc; i++)
            {
                cp[i + 0] = (uint8_t)((acc += cp[i + 0]) & 0xff);
            }
        }
        else if (stride == 3)
        {
            uint32_t cr = cp[0];
            uint32_t cg = cp[1];
            uint32_t cb = cp[2];
            tmsize_t i = stride;
            for (; i < cc; i += stride)
            {
                cp[i + 0] = (uint8_t)((cr += cp[i + 0]) & 0xff);
                cp[i + 1] = (uint8_t)((cg += cp[i + 1]) & 0xff);
                cp[i + 2] = (uint8_t)((cb += cp[i + 2]) & 0xff);
            }
        }
        else if (stride == 4)
        {
            uint32_t cr = cp[0];
            uint32_t cg = cp[1];
            uint32_t cb = cp[2];
            uint32_t ca = cp[3];
            tmsize_t i = stride;
            for (; i < cc; i += stride)
            {
                cp[i + 0] = (uint8_t)((cr += cp[i + 0]) & 0xff);
                cp[i + 1] = (uint8_t)((cg += cp[i + 1]) & 0xff);
                cp[i + 2] = (uint8_t)((cb += cp[i + 2]) & 0xff);
                cp[i + 3] = (uint8_t)((ca += cp[i + 3]) & 0xff);
            }
        }
        else
        {
            cc -= stride;
            do
            {
                REPEAT4(stride,
                        cp[stride] = (uint8_t)((cp[stride] + *cp) & 0xff);
                        cp++)
                cc -= stride;
            } while (cc > 0);
        }
    }
    return 1;
}

void TIFFPrintDirectory(TIFF *tif, FILE *fd, long flags)
{
    TIFFDirectory *td = &tif->tif_dir;
    char *sep;
    long l, n;

    fprintf(fd, "TIFF Directory at offset 0x%" PRIx64 " (%" PRIu64 ")\n",
            tif->tif_diroff, tif->tif_diroff);
    if (TIFFFieldSet(tif, FIELD_SUBFILETYPE))
    {
        fprintf(fd, "  Subfile Type:");
        sep = " ";
        if (td->td_subfiletype & FILETYPE_REDUCEDIMAGE)
        {
            fprintf(fd, "%sreduced-resolution image", sep);
            sep = "/";
        }
        if (td->td_subfiletype & FILETYPE_PAGE)
        {
            fprintf(fd, "%smulti-page document", sep);
            sep = "/";
        }
        if (td->td_subfiletype & FILETYPE_MASK)
            fprintf(fd, "%stransparency mask", sep);
        fprintf(fd, " (%" PRIu32 " = 0x%" PRIx32 ")\n", td->td_subfiletype,
                td->td_subfiletype);
    }
    if (TIFFFieldSet(tif, FIELD_IMAGEDIMENSIONS))
    {
        fprintf(fd, "  Image Width: %" PRIu32 " Image Length: %" PRIu32,
                td->td_imagewidth, td->td_imagelength);
        if (TIFFFieldSet(tif, FIELD_IMAGEDEPTH))
            fprintf(fd, " Image Depth: %" PRIu32, td->td_imagedepth);
        fprintf(fd, "\n");
    }
    if (TIFFFieldSet(tif, FIELD_TILEDIMENSIONS))
    {
        fprintf(fd, "  Tile Width: %" PRIu32 " Tile Length: %" PRIu32,
                td->td_tilewidth, td->td_tilelength);
        if (TIFFFieldSet(tif, FIELD_TILEDEPTH))
            fprintf(fd, " Tile Depth: %" PRIu32, td->td_tiledepth);
        fprintf(fd, "\n");
    }
    if (TIFFFieldSet(tif, FIELD_RESOLUTION))
    {
        fprintf(fd, "  Resolution: %g, %g", td->td_xresolution,
                td->td_yresolution);
        if (TIFFFieldSet(tif, FIELD_RESOLUTIONUNIT))
        {
            switch (td->td_resolutionunit)
            {
                case RESUNIT_NONE:
                    fprintf(fd, " (unitless)");
                    break;
                case RESUNIT_INCH:
                    fprintf(fd, " pixels/inch");
                    break;
                case RESUNIT_CENTIMETER:
                    fprintf(fd, " pixels/cm");
                    break;
                default:
                    fprintf(fd, " (unit %" PRIu16 " = 0x%" PRIx16 ")",
                            td->td_resolutionunit, td->td_resolutionunit);
                    break;
            }
        }
        fprintf(fd, "\n");
    }
    if (TIFFFieldSet(tif, FIELD_POSITION))
        fprintf(fd, "  Position: %g, %g\n", td->td_xposition, td->td_yposition);
    if (TIFFFieldSet(tif, FIELD_BITSPERSAMPLE))
        fprintf(fd, "  Bits/Sample: %" PRIu16 "\n", td->td_bitspersample);
    if (TIFFFieldSet(tif, FIELD_SAMPLEFORMAT))
    {
        fprintf(fd, "  Sample Format: ");
        switch (td->td_sampleformat)
        {
            case SAMPLEFORMAT_VOID:
                fprintf(fd, "void\n");
                break;
            case SAMPLEFORMAT_INT:
                fprintf(fd, "signed integer\n");
                break;
            case SAMPLEFORMAT_UINT:
                fprintf(fd, "unsigned integer\n");
                break;
            case SAMPLEFORMAT_IEEEFP:
                fprintf(fd, "IEEE floating point\n");
                break;
            case SAMPLEFORMAT_COMPLEXINT:
                fprintf(fd, "complex signed integer\n");
                break;
            case SAMPLEFORMAT_COMPLEXIEEEFP:
                fprintf(fd, "complex IEEE floating point\n");
                break;
            default:
                fprintf(fd, "%" PRIu16 " (0x%" PRIx16 ")\n",
                        td->td_sampleformat, td->td_sampleformat);
                break;
        }
    }
    if (TIFFFieldSet(tif, FIELD_COMPRESSION))
    {
        const TIFFCodec *c = TIFFFindCODEC(td->td_compression);
        fprintf(fd, "  Compression Scheme: ");
        if (c)
            fprintf(fd, "%s\n", c->name);
        else
            fprintf(fd, "%" PRIu16 " (0x%" PRIx16 ")\n", td->td_compression,
                    td->td_compression);
    }
    if (TIFFFieldSet(tif, FIELD_PHOTOMETRIC))
    {
        fprintf(fd, "  Photometric Interpretation: ");
        if (td->td_photometric < NPHOTONAMES)
            fprintf(fd, "%s\n", photoNames[td->td_photometric]);
        else
        {
            switch (td->td_photometric)
            {
                case PHOTOMETRIC_LOGL:
                    fprintf(fd, "CIE Log2(L)\n");
                    break;
                case PHOTOMETRIC_LOGLUV:
                    fprintf(fd, "CIE Log2(L) (u',v')\n");
                    break;
                default:
                    fprintf(fd, "%" PRIu16 " (0x%" PRIx16 ")\n",
                            td->td_photometric, td->td_photometric);
                    break;
            }
        }
    }
    if (TIFFFieldSet(tif, FIELD_EXTRASAMPLES) && td->td_extrasamples)
    {
        uint16_t i;
        fprintf(fd, "  Extra Samples: %" PRIu16 "<", td->td_extrasamples);
        sep = "";
        for (i = 0; i < td->td_extrasamples; i++)
        {
            switch (td->td_sampleinfo[i])
            {
                case EXTRASAMPLE_UNSPECIFIED:
                    fprintf(fd, "%sunspecified", sep);
                    break;
                case EXTRASAMPLE_ASSOCALPHA:
                    fprintf(fd, "%sassoc-alpha", sep);
                    break;
                case EXTRASAMPLE_UNASSALPHA:
                    fprintf(fd, "%sunassoc-alpha", sep);
                    break;
                default:
                    fprintf(fd, "%s%" PRIu16 " (0x%" PRIx16 ")", sep,
                            td->td_sampleinfo[i], td->td_sampleinfo[i]);
                    break;
            }
            sep = ", ";
        }
        fprintf(fd, ">\n");
    }
    if (TIFFFieldSet(tif, FIELD_INKNAMES))
    {
        char *cp;
        uint16_t i;
        fprintf(fd, "  Ink Names: ");
        i = td->td_samplesperpixel;
        sep = "";
        for (cp = td->td_inknames;
             i > 0 && cp < td->td_inknames + td->td_inknameslen;
             cp = strchr(cp, '\0') + 1, i--)
        {
            size_t max_chars = td->td_inknameslen - (cp - td->td_inknames);
            fputs(sep, fd);
            _TIFFprintAsciiBounded(fd, cp, max_chars);
            sep = ", ";
        }
        fputs("\n", fd);
    }
    if (TIFFFieldSet(tif, FIELD_NUMBEROFINKS))
    {
        fprintf(fd, "  NumberOfInks: %d\n", td->td_numberofinks);
    }
    if (TIFFFieldSet(tif, FIELD_THRESHHOLDING))
    {
        fprintf(fd, "  Thresholding: ");
        switch (td->td_threshholding)
        {
            case THRESHHOLD_BILEVEL:
                fprintf(fd, "bilevel art scan\n");
                break;
            case THRESHHOLD_HALFTONE:
                fprintf(fd, "halftone or dithered scan\n");
                break;
            case THRESHHOLD_ERRORDIFFUSE:
                fprintf(fd, "error diffused\n");
                break;
            default:
                fprintf(fd, "%" PRIu16 " (0x%" PRIx16 ")\n",
                        td->td_threshholding, td->td_threshholding);
                break;
        }
    }
    if (TIFFFieldSet(tif, FIELD_FILLORDER))
    {
        fprintf(fd, "  FillOrder: ");
        switch (td->td_fillorder)
        {
            case FILLORDER_MSB2LSB:
                fprintf(fd, "msb-to-lsb\n");
                break;
            case FILLORDER_LSB2MSB:
                fprintf(fd, "lsb-to-msb\n");
                break;
            default:
                fprintf(fd, "%" PRIu16 " (0x%" PRIx16 ")\n", td->td_fillorder,
                        td->td_fillorder);
                break;
        }
    }
    if (TIFFFieldSet(tif, FIELD_YCBCRSUBSAMPLING))
    {
        fprintf(fd, "  YCbCr Subsampling: %" PRIu16 ", %" PRIu16 "\n",
                td->td_ycbcrsubsampling[0], td->td_ycbcrsubsampling[1]);
    }
    if (TIFFFieldSet(tif, FIELD_YCBCRPOSITIONING))
    {
        fprintf(fd, "  YCbCr Positioning: ");
        switch (td->td_ycbcrpositioning)
        {
            case YCBCRPOSITION_CENTERED:
                fprintf(fd, "centered\n");
                break;
            case YCBCRPOSITION_COSITED:
                fprintf(fd, "cosited\n");
                break;
            default:
                fprintf(fd, "%" PRIu16 " (0x%" PRIx16 ")\n",
                        td->td_ycbcrpositioning, td->td_ycbcrpositioning);
                break;
        }
    }
    if (TIFFFieldSet(tif, FIELD_HALFTONEHINTS))
        fprintf(fd, "  Halftone Hints: light %" PRIu16 " dark %" PRIu16 "\n",
                td->td_halftonehints[0], td->td_halftonehints[1]);
    if (TIFFFieldSet(tif, FIELD_ORIENTATION))
    {
        fprintf(fd, "  Orientation: ");
        if (td->td_orientation < NORIENTNAMES)
            fprintf(fd, "%s\n", orientNames[td->td_orientation]);
        else
            fprintf(fd, "%" PRIu16 " (0x%" PRIx16 ")\n", td->td_orientation,
                    td->td_orientation);
    }
    if (TIFFFieldSet(tif, FIELD_SAMPLESPERPIXEL))
        fprintf(fd, "  Samples/Pixel: %" PRIx16 "\n", td->td_samplesperpixel);
    if (TIFFFieldSet(tif, FIELD_ROWSPERSTRIP))
    {
        fprintf(fd, "  Rows/Strip: ");
        if (td->td_rowsperstrip == (uint32_t)-1)
            fprintf(fd, "(infinite)\n");
        else
            fprintf(fd, "%" PRIu32 "\n", td->td_rowsperstrip);
    }
    if (TIFFFieldSet(tif, FIELD_MINSAMPLEVALUE))
        fprintf(fd, "  Min Sample Value: %" PRIu16 "\n", td->td_minsamplevalue);
    if (TIFFFieldSet(tif, FIELD_MAXSAMPLEVALUE))
        fprintf(fd, "  Max Sample Value: %" PRIu16 "\n", td->td_maxsamplevalue);
    if (TIFFFieldSet(tif, FIELD_SMINSAMPLEVALUE))
    {
        int i;
        int count =
            (tif->tif_flags & TIFF_PERSAMPLE) ? td->td_samplesperpixel : 1;
        fprintf(fd, "  SMin Sample Value:");
        for (i = 0; i < count; ++i)
            fprintf(fd, " %g", td->td_sminsamplevalue[i]);
        fprintf(fd, "\n");
    }
    if (TIFFFieldSet(tif, FIELD_SMAXSAMPLEVALUE))
    {
        int i;
        int count =
            (tif->tif_flags & TIFF_PERSAMPLE) ? td->td_samplesperpixel : 1;
        fprintf(fd, "  SMax Sample Value:");
        for (i = 0; i < count; ++i)
            fprintf(fd, " %g", td->td_smaxsamplevalue[i]);
        fprintf(fd, "\n");
    }
    if (TIFFFieldSet(tif, FIELD_PLANARCONFIG))
    {
        fprintf(fd, "  Planar Configuration: ");
        switch (td->td_planarconfig)
        {
            case PLANARCONFIG_CONTIG:
                fprintf(fd, "single image plane\n");
                break;
            case PLANARCONFIG_SEPARATE:
                fprintf(fd, "separate image planes\n");
                break;
            default:
                fprintf(fd, "%" PRIu16 " (0x%" PRIx16 ")\n",
                        td->td_planarconfig, td->td_planarconfig);
                break;
        }
    }
    if (TIFFFieldSet(tif, FIELD_PAGENUMBER))
        fprintf(fd, "  Page Number: %" PRIu16 "-%" PRIu16 "\n",
                td->td_pagenumber[0], td->td_pagenumber[1]);
    if (TIFFFieldSet(tif, FIELD_COLORMAP))
    {
        fprintf(fd, "  Color Map: ");
        if (flags & TIFFPRINT_COLORMAP)
        {
            fprintf(fd, "\n");
            n = 1L << td->td_bitspersample;
            for (l = 0; l < n; l++)
                fprintf(fd, "   %5ld: %5" PRIu16 " %5" PRIu16 " %5" PRIu16 "\n",
                        l, td->td_colormap[0][l], td->td_colormap[1][l],
                        td->td_colormap[2][l]);
        }
        else
            fprintf(fd, "(present)\n");
    }
    if (TIFFFieldSet(tif, FIELD_REFBLACKWHITE))
    {
        int i;
        fprintf(fd, "  Reference Black/White:\n");
        for (i = 0; i < 3; i++)
            fprintf(fd, "    %2d: %5g %5g\n", i,
                    td->td_refblackwhite[2 * i + 0],
                    td->td_refblackwhite[2 * i + 1]);
    }
    if (TIFFFieldSet(tif, FIELD_TRANSFERFUNCTION))
    {
        fprintf(fd, "  Transfer Function: ");
        if (flags & TIFFPRINT_CURVES)
        {
            fprintf(fd, "\n");
            n = 1L << td->td_bitspersample;
            for (l = 0; l < n; l++)
            {
                uint16_t i;
                fprintf(fd, "    %2ld: %5" PRIu16, l,
                        td->td_transferfunction[0][l]);
                for (i = 1;
                     i < td->td_samplesperpixel - td->td_extrasamples && i < 3;
                     i++)
                    fprintf(fd, " %5" PRIu16, td->td_transferfunction[i][l]);
                fputc('\n', fd);
            }
        }
        else
            fprintf(fd, "(present)\n");
    }
    if (TIFFFieldSet(tif, FIELD_SUBIFD) && (td->td_subifd))
    {
        uint16_t i;
        fprintf(fd, "  SubIFD Offsets:");
        for (i = 0; i < td->td_nsubifd; i++)
            fprintf(fd, " %5" PRIu64, td->td_subifd[i]);
        fputc('\n', fd);
    }

    /*
    ** Custom tag support.
    */
    {
        int i;
        short count;

        count = (short)TIFFGetTagListCount(tif);
        for (i = 0; i < count; i++)
        {
            uint32_t tag = TIFFGetTagListEntry(tif, i);
            const TIFFField *fip;
            uint32_t value_count;
            int mem_alloc = 0;
            void *raw_data = NULL;
            uint16_t dotrange[2]; /* must be kept in that scope and not moved in
                                     the below TIFFTAG_DOTRANGE specific case */

            fip = TIFFFieldWithTag(tif, tag);
            if (fip == NULL)
                continue;

            if (fip->field_passcount)
            {
                if (fip->field_readcount == TIFF_VARIABLE2)
                {
                    if (TIFFGetField(tif, tag, &value_count, &raw_data) != 1)
                        continue;
                }
                else if (fip->field_readcount == TIFF_VARIABLE)
                {
                    uint16_t small_value_count;
                    if (TIFFGetField(tif, tag, &small_value_count, &raw_data) !=
                        1)
                        continue;
                    value_count = small_value_count;
                }
                else
                {
                    assert(fip->field_readcount == TIFF_VARIABLE ||
                           fip->field_readcount == TIFF_VARIABLE2);
                    continue;
                }
            }
            else
            {
                if (fip->field_readcount == TIFF_VARIABLE ||
                    fip->field_readcount == TIFF_VARIABLE2)
                    value_count = 1;
                else if (fip->field_readcount == TIFF_SPP)
                    value_count = td->td_samplesperpixel;
                else
                    value_count = fip->field_readcount;
                if (fip->field_tag == TIFFTAG_DOTRANGE &&
                    strcmp(fip->field_name, "DotRange") == 0)
                {
                    /* TODO: This is an evil exception and should not have been
                       handled this way ... likely best if we move it into
                       the directory structure with an explicit field in
                       libtiff 4.1 and assign it a FIELD_ value */
                    raw_data = dotrange;
                    TIFFGetField(tif, tag, dotrange + 0, dotrange + 1);
                }
                else if (fip->field_type == TIFF_ASCII ||
                         fip->field_readcount == TIFF_VARIABLE ||
                         fip->field_readcount == TIFF_VARIABLE2 ||
                         fip->field_readcount == TIFF_SPP || value_count > 1)
                {
                    if (TIFFGetField(tif, tag, &raw_data) != 1)
                        continue;
                }
                else
                {
                    /*--: Rational2Double: For Rationals evaluate
                     * "set_get_field_type" to determine internal storage size.
                     */
                    int tv_size = TIFFFieldSetGetSize(fip);
                    raw_data = _TIFFmallocExt(tif, tv_size * value_count);
                    mem_alloc = 1;
                    if (TIFFGetField(tif, tag, raw_data) != 1)
                    {
                        _TIFFfreeExt(tif, raw_data);
                        continue;
                    }
                }
            }

            /*
             * Catch the tags which needs to be specially handled
             * and pretty print them. If tag not handled in
             * _TIFFPrettyPrintField() fall down and print it as
             * any other tag.
             */
            if (raw_data != NULL &&
                !_TIFFPrettyPrintField(tif, fip, fd, tag, value_count,
                                       raw_data))
                _TIFFPrintField(fd, fip, value_count, raw_data);

            if (mem_alloc)
                _TIFFfreeExt(tif, raw_data);
        }
    }

    if (tif->tif_tagmethods.printdir)
        (*tif->tif_tagmethods.printdir)(tif, fd, flags);

    if ((flags & TIFFPRINT_STRIPS) && TIFFFieldSet(tif, FIELD_STRIPOFFSETS))
    {
        uint32_t s;

        fprintf(fd, "  %" PRIu32 " %s:\n", td->td_nstrips,
                isTiled(tif) ? "Tiles" : "Strips");
        for (s = 0; s < td->td_nstrips; s++)
            fprintf(fd, "    %3" PRIu32 ": [%8" PRIu64 ", %8" PRIu64 "]\n", s,
                    TIFFGetStrileOffset(tif, s),
                    TIFFGetStrileByteCount(tif, s));
    }
}

tmsize_t TIFFReadEncodedStrip(TIFF *tif, uint32_t strip, void *buf,
                              tmsize_t size)
{
    static const char module[] = "TIFFReadEncodedStrip";
    TIFFDirectory *td = &tif->tif_dir;
    tmsize_t stripsize;
    uint16_t plane;

    stripsize = TIFFReadEncodedStripGetStripSize(tif, strip, &plane);
    if (stripsize == ((tmsize_t)(-1)))
        return ((tmsize_t)(-1));

    /* shortcut to avoid an extra memcpy() */
    if (td->td_compression == COMPRESSION_NONE && size != (tmsize_t)(-1) &&
        size >= stripsize && !isMapped(tif) &&
        ((tif->tif_flags & TIFF_NOREADRAW) == 0))
    {
        if (TIFFReadRawStrip1(tif, strip, buf, stripsize, module) != stripsize)
            return ((tmsize_t)(-1));

        if (!isFillOrder(tif, td->td_fillorder) &&
            (tif->tif_flags & TIFF_NOBITREV) == 0)
            TIFFReverseBits(buf, stripsize);

        (*tif->tif_postdecode)(tif, buf, stripsize);
        return (stripsize);
    }

    if ((size != (tmsize_t)(-1)) && (size < stripsize))
        stripsize = size;
    if (!TIFFFillStrip(tif, strip))
    {
        /* The output buf may be NULL, in particular if TIFFTAG_FAXFILLFUNC
           is being used. Thus, memset must be conditional on buf not NULL. */
        if (buf)
            memset(buf, 0, (size_t)stripsize);
        return ((tmsize_t)(-1));
    }
    if ((*tif->tif_decodestrip)(tif, buf, stripsize, plane) <= 0)
        return ((tmsize_t)(-1));
    (*tif->tif_postdecode)(tif, buf, stripsize);
    return (stripsize);
}

tmsize_t TIFFReadEncodedTile(TIFF *tif, uint32_t tile, void *buf, tmsize_t size)
{
    static const char module[] = "TIFFReadEncodedTile";
    TIFFDirectory *td = &tif->tif_dir;
    tmsize_t tilesize = tif->tif_tilesize;

    if (!TIFFCheckRead(tif, 1))
        return ((tmsize_t)(-1));
    if (tile >= td->td_nstrips)
    {
        TIFFErrorExtR(tif, module,
                      "%" PRIu32 ": Tile out of range, max %" PRIu32, tile,
                      td->td_nstrips);
        return ((tmsize_t)(-1));
    }

    /* shortcut to avoid an extra memcpy() */
    if (td->td_compression == COMPRESSION_NONE && size != (tmsize_t)(-1) &&
        size >= tilesize && !isMapped(tif) &&
        ((tif->tif_flags & TIFF_NOREADRAW) == 0))
    {
        if (TIFFReadRawTile1(tif, tile, buf, tilesize, module) != tilesize)
            return ((tmsize_t)(-1));

        if (!isFillOrder(tif, td->td_fillorder) &&
            (tif->tif_flags & TIFF_NOBITREV) == 0)
            TIFFReverseBits(buf, tilesize);

        (*tif->tif_postdecode)(tif, buf, tilesize);
        return (tilesize);
    }

    if (size == (tmsize_t)(-1))
        size = tilesize;
    else if (size > tilesize)
        size = tilesize;
    if (!TIFFFillTile(tif, tile))
    {
        /* See TIFFReadEncodedStrip comment regarding TIFFTAG_FAXFILLFUNC. */
        if (buf)
            memset(buf, 0, (size_t)size);
        return ((tmsize_t)(-1));
    }
    else if ((*tif->tif_decodetile)(tif, (uint8_t *)buf, size,
                                    (uint16_t)(tile / td->td_stripsperimage)))
    {
        (*tif->tif_postdecode)(tif, (uint8_t *)buf, size);
        return (size);
    }
    else
        return ((tmsize_t)(-1));
}

/* Use the provided input buffer (inbuf, insize) and decompress it into
 * (outbuf, outsize).
 * This function replaces the use of
 * TIFFReadEncodedStrip()/TIFFReadEncodedTile() when the user can provide the
 * buffer for the input data, for example when he wants to avoid libtiff to read
 * the strile offset/count values from the [Strip|Tile][Offsets/ByteCounts]
 * array. inbuf content must be writable (if bit reversal is needed) Returns 1
 * in case of success, 0 otherwise.
 */
int TIFFReadFromUserBuffer(TIFF *tif, uint32_t strile, void *inbuf,
                           tmsize_t insize, void *outbuf, tmsize_t outsize)
{
    static const char module[] = "TIFFReadFromUserBuffer";
    TIFFDirectory *td = &tif->tif_dir;
    int ret = 1;
    uint32_t old_tif_flags = tif->tif_flags;
    tmsize_t old_rawdatasize = tif->tif_rawdatasize;
    void *old_rawdata = tif->tif_rawdata;

    if (tif->tif_mode == O_WRONLY)
    {
        TIFFErrorExtR(tif, tif->tif_name, "File not open for reading");
        return 0;
    }
    if (tif->tif_flags & TIFF_NOREADRAW)
    {
        TIFFErrorExtR(tif, module,
                      "Compression scheme does not support access to raw "
                      "uncompressed data");
        return 0;
    }

    tif->tif_flags &= ~TIFF_MYBUFFER;
    tif->tif_flags |= TIFF_BUFFERMMAP;
    tif->tif_rawdatasize = insize;
    tif->tif_rawdata = inbuf;
    tif->tif_rawdataoff = 0;
    tif->tif_rawdataloaded = insize;

    if (!isFillOrder(tif, td->td_fillorder) &&
        (tif->tif_flags & TIFF_NOBITREV) == 0)
    {
        TIFFReverseBits(inbuf, insize);
    }

    if (TIFFIsTiled(tif))
    {
        if (!TIFFStartTile(tif, strile))
        {
            ret = 0;
            /* See related TIFFReadEncodedStrip comment. */
            if (outbuf)
                memset(outbuf, 0, (size_t)outsize);
        }
        else if (!(*tif->tif_decodetile)(
                     tif, (uint8_t *)outbuf, outsize,
                     (uint16_t)(strile / td->td_stripsperimage)))
        {
            ret = 0;
        }
    }
    else
    {
        uint32_t rowsperstrip = td->td_rowsperstrip;
        uint32_t stripsperplane;
        if (rowsperstrip > td->td_imagelength)
            rowsperstrip = td->td_imagelength;
        if (rowsperstrip == 0)
        {
            TIFFErrorExtR(tif, module, "rowsperstrip is zero");
            ret = 0;
        }
        else
        {
            stripsperplane =
                TIFFhowmany_32_maxuint_compat(td->td_imagelength, rowsperstrip);
            if (!TIFFStartStrip(tif, strile))
            {
                ret = 0;
                /* See related TIFFReadEncodedStrip comment. */
                if (outbuf)
                    memset(outbuf, 0, (size_t)outsize);
            }
            else if (!(*tif->tif_decodestrip)(
                         tif, (uint8_t *)outbuf, outsize,
                         (uint16_t)(strile / stripsperplane)))
            {
                ret = 0;
            }
        }
    }
    if (ret)
    {
        (*tif->tif_postdecode)(tif, (uint8_t *)outbuf, outsize);
    }

    if (!isFillOrder(tif, td->td_fillorder) &&
        (tif->tif_flags & TIFF_NOBITREV) == 0)
    {
        TIFFReverseBits(inbuf, insize);
    }

    tif->tif_flags = (old_tif_flags & (TIFF_MYBUFFER | TIFF_BUFFERMMAP)) |
                     (tif->tif_flags & ~(TIFF_MYBUFFER | TIFF_BUFFERMMAP));
    tif->tif_rawdatasize = old_rawdatasize;
    tif->tif_rawdata = old_rawdata;
    tif->tif_rawdataoff = 0;
    tif->tif_rawdataloaded = 0;

    return ret;
}

int TIFFReadScanline(TIFF *tif, void *buf, uint32_t row, uint16_t sample)
{
    int e;

    if (!TIFFCheckRead(tif, 0))
        return (-1);
    if ((e = TIFFSeek(tif, row, sample)) != 0)
    {
        /*
         * Decompress desired row into user buffer.
         */
        e = (*tif->tif_decoderow)(tif, (uint8_t *)buf, tif->tif_scanlinesize,
                                  sample);

        /* we are now poised at the beginning of the next row */
        tif->tif_row = row + 1;

        if (e)
            (*tif->tif_postdecode)(tif, (uint8_t *)buf, tif->tif_scanlinesize);
    }
    else
    {
        /* See TIFFReadEncodedStrip comment regarding TIFFTAG_FAXFILLFUNC. */
        if (buf)
            memset(buf, 0, (size_t)tif->tif_scanlinesize);
    }
    return (e > 0 ? 1 : -1);
}

static int TIFFSeek(TIFF *tif, uint32_t row, uint16_t sample)
{
    register TIFFDirectory *td = &tif->tif_dir;
    uint32_t strip;
    int whole_strip;
    tmsize_t read_ahead = 0;

    /*
    ** Establish what strip we are working from.
    */
    if (row >= td->td_imagelength)
    { /* out of range */
        TIFFErrorExtR(tif, tif->tif_name,
                      "%" PRIu32 ": Row out of range, max %" PRIu32 "", row,
                      td->td_imagelength);
        return (0);
    }
    if (td->td_planarconfig == PLANARCONFIG_SEPARATE)
    {
        if (sample >= td->td_samplesperpixel)
        {
            TIFFErrorExtR(tif, tif->tif_name,
                          "%" PRIu16 ": Sample out of range, max %" PRIu16 "",
                          sample, td->td_samplesperpixel);
            return (0);
        }
        strip = (uint32_t)sample * td->td_stripsperimage +
                row / td->td_rowsperstrip;
    }
    else
        strip = row / td->td_rowsperstrip;

        /*
         * Do we want to treat this strip as one whole chunk or
         * read it a few lines at a time?
         */
#if defined(CHUNKY_STRIP_READ_SUPPORT)
    whole_strip = TIFFGetStrileByteCount(tif, strip) < 10 || isMapped(tif);
    if (td->td_compression == COMPRESSION_LERC ||
        td->td_compression == COMPRESSION_JBIG)
    {
        /* Ideally plugins should have a way to declare they don't support
         * chunk strip */
        whole_strip = 1;
    }

    if (!whole_strip)
    {
        /* 16 is for YCbCr mode where we may need to read 16 */
        /* lines at a time to get a decompressed line, and 5000 */
        /* is some constant value, for example for JPEG tables */

        /* coverity[dead_error_line:SUPPRESS] */
        if (tif->tif_scanlinesize < TIFF_TMSIZE_T_MAX / 16 &&
            tif->tif_scanlinesize * 16 < TIFF_TMSIZE_T_MAX - 5000)
        {
            read_ahead = tif->tif_scanlinesize * 16 + 5000;
        }
        else
        {
            read_ahead = tif->tif_scanlinesize;
        }
    }
#else
    whole_strip = 1;
#endif

    /*
     * If we haven't loaded this strip, do so now, possibly
     * only reading the first part.
     */
    if (strip != tif->tif_curstrip)
    { /* different strip, refill */

        if (whole_strip)
        {
            if (!TIFFFillStrip(tif, strip))
                return (0);
        }
#if defined(CHUNKY_STRIP_READ_SUPPORT)
        else
        {
            if (!TIFFFillStripPartial(tif, strip, read_ahead, 1))
                return 0;
        }
#endif
    }

#if defined(CHUNKY_STRIP_READ_SUPPORT)
    /*
    ** If we already have some data loaded, do we need to read some more?
    */
    else if (!whole_strip)
    {
        /* coverity[dead_error_line:SUPPRESS] */
        if (((tif->tif_rawdata + tif->tif_rawdataloaded) - tif->tif_rawcp) <
                read_ahead &&
            (uint64_t)tif->tif_rawdataoff + tif->tif_rawdataloaded <
                TIFFGetStrileByteCount(tif, strip))
        {
            if (!TIFFFillStripPartial(tif, strip, read_ahead, 0))
                return 0;
        }
    }
#endif

    if (row < tif->tif_row)
    {
        /*
         * Moving backwards within the same strip: backup
         * to the start and then decode forward (below).
         *
         * NB: If you're planning on lots of random access within a
         * strip, it's better to just read and decode the entire
         * strip, and then access the decoded data in a random fashion.
         */

        if (tif->tif_rawdataoff != 0)
        {
            if (!TIFFFillStripPartial(tif, strip, read_ahead, 1))
                return 0;
        }
        else
        {
            if (!TIFFStartStrip(tif, strip))
                return (0);
        }
    }

    if (row != tif->tif_row)
    {
        /*
         * Seek forward to the desired row.
         */

        /* TODO: Will this really work with partial buffers? */

        if (!(*tif->tif_seek)(tif, row - tif->tif_row))
            return (0);
        tif->tif_row = row;
    }

    return (1);
}

 * Compute which strip a (row,sample) value is in.
 */
uint32_t TIFFComputeStrip(TIFF *tif, uint32_t row, uint16_t sample)
{
    static const char module[] = "TIFFComputeStrip";
    TIFFDirectory *td = &tif->tif_dir;
    uint32_t strip;

    if (td->td_rowsperstrip == 0)
    {
        TIFFErrorExtR(tif, module,
                      "Cannot compute strip: RowsPerStrip is zero");
        return 0;
    }
    strip = row / td->td_rowsperstrip;
    if (td->td_planarconfig == PLANARCONFIG_SEPARATE)
    {
        if (sample >= td->td_samplesperpixel)
        {
            TIFFErrorExtR(tif, module, "%lu: Sample out of range, max %lu",
                          (unsigned long)sample,
                          (unsigned long)td->td_samplesperpixel);
            return (0);
        }
        strip += (uint32_t)sample * td->td_stripsperimage;
    }
    return (strip);
}

static tmsize_t _tiffReadProc(thandle_t fd, void *buf, tmsize_t size)
{
    fd_as_handle_union_t fdh;
    const size_t bytes_total = (size_t)size;
    size_t bytes_read;
    tmsize_t count = -1;
    if ((tmsize_t)bytes_total != size)
    {
        errno = EINVAL;
        return (tmsize_t)-1;
    }
    fdh.h = fd;
    for (bytes_read = 0; bytes_read < bytes_total; bytes_read += count)
    {
        char *buf_offset = (char *)buf + bytes_read;
        size_t io_size = bytes_total - bytes_read;
        if (io_size > TIFF_IO_MAX)
            io_size = TIFF_IO_MAX;
        /* Below is an obvious false positive of Coverity Scan */
        /* coverity[overflow_sink] */
        count = read(fdh.fd, buf_offset, (TIFFIOSize_t)io_size);
        if (count <= 0)
            break;
    }
    if (count < 0)
        return (tmsize_t)-1;
    /* Silence Coverity Scan warning about unsigned to signed underflow. */
    /* coverity[return_overflow:SUPPRESS] */
    return (tmsize_t)bytes_read;
}

static tmsize_t _tiffWriteProc(thandle_t fd, void *buf, tmsize_t size)
{
    fd_as_handle_union_t fdh;
    const size_t bytes_total = (size_t)size;
    size_t bytes_written;
    tmsize_t count = -1;
    if ((tmsize_t)bytes_total != size)
    {
        errno = EINVAL;
        return (tmsize_t)-1;
    }
    fdh.h = fd;
    for (bytes_written = 0; bytes_written < bytes_total; bytes_written += count)
    {
        const char *buf_offset = (char *)buf + bytes_written;
        size_t io_size = bytes_total - bytes_written;
        if (io_size > TIFF_IO_MAX)
            io_size = TIFF_IO_MAX;
        /* Below is an obvious false positive of Coverity Scan */
        /* coverity[overflow_sink] */
        count = write(fdh.fd, buf_offset, (TIFFIOSize_t)io_size);
        if (count <= 0)
            break;
    }
    if (count < 0)
        return (tmsize_t)-1;
    /* Silence Coverity Scan warning about unsigned to signed underflow. */
    /* coverity[return_overflow:SUPPRESS] */
    return (tmsize_t)bytes_written;
    /* return ((tmsize_t) write(fdh.fd, buf, bytes_total)); */
}

#define isUnspecified(tif, f)                                                  \
    (TIFFFieldSet(tif, f) && (tif)->tif_dir.td_imagelength == 0)

int TIFFSetupStrips(TIFF *tif)
{
    TIFFDirectory *td = &tif->tif_dir;

    if (isTiled(tif))
        td->td_stripsperimage = isUnspecified(tif, FIELD_TILEDIMENSIONS)
                                    ? td->td_samplesperpixel
                                    : TIFFNumberOfTiles(tif);
    else
        td->td_stripsperimage = isUnspecified(tif, FIELD_ROWSPERSTRIP)
                                    ? td->td_samplesperpixel
                                    : TIFFNumberOfStrips(tif);
    td->td_nstrips = td->td_stripsperimage;
    /* TIFFWriteDirectoryTagData has a limitation to 0x80000000U bytes */
    if (td->td_nstrips >=
        0x80000000U / ((tif->tif_flags & TIFF_BIGTIFF) ? 0x8U : 0x4U))
    {
        TIFFErrorExtR(tif, "TIFFSetupStrips",
                      "Too large Strip/Tile Offsets/ByteCounts arrays");
        return 0;
    }
    if (td->td_planarconfig == PLANARCONFIG_SEPARATE)
        td->td_stripsperimage /= td->td_samplesperpixel;

    if (td->td_stripoffset_p != NULL)
        _TIFFfreeExt(tif, td->td_stripoffset_p);
    td->td_stripoffset_p = (uint64_t *)_TIFFCheckMalloc(
        tif, td->td_nstrips, sizeof(uint64_t), "for \"StripOffsets\" array");
    if (td->td_stripbytecount_p != NULL)
        _TIFFfreeExt(tif, td->td_stripbytecount_p);
    td->td_stripbytecount_p = (uint64_t *)_TIFFCheckMalloc(
        tif, td->td_nstrips, sizeof(uint64_t), "for \"StripByteCounts\" array");
    if (td->td_stripoffset_p == NULL || td->td_stripbytecount_p == NULL)
        return (0);
    /*
     * Place data at the end-of-file
     * (by setting offsets to zero).
     */
    _TIFFmemset(td->td_stripoffset_p, 0, td->td_nstrips * sizeof(uint64_t));
    _TIFFmemset(td->td_stripbytecount_p, 0, td->td_nstrips * sizeof(uint64_t));
    TIFFSetFieldBit(tif, FIELD_STRIPOFFSETS);
    TIFFSetFieldBit(tif, FIELD_STRIPBYTECOUNTS);
    return (1);
}

int TIFFInitZIP(TIFF *tif, int scheme)
{
    static const char module[] = "TIFFInitZIP";
    ZIPState *sp;

    assert((scheme == COMPRESSION_DEFLATE) ||
           (scheme == COMPRESSION_ADOBE_DEFLATE));
#ifdef NDEBUG
    (void)scheme;
#endif

    /*
     * Merge codec-specific tag information.
     */
    if (!_TIFFMergeFields(tif, zipFields, TIFFArrayCount(zipFields)))
    {
        TIFFErrorExtR(tif, module,
                      "Merging Deflate codec-specific tags failed");
        return 0;
    }

    /*
     * Allocate state block so tag methods have storage to record values.
     */
    tif->tif_data = (uint8_t *)_TIFFcallocExt(tif, sizeof(ZIPState), 1);
    if (tif->tif_data == NULL)
        goto bad;
    sp = GetZIPState(tif);
    sp->stream.zalloc = TIFF_zalloc;
    sp->stream.zfree = TIFF_zfree;
    sp->stream.opaque = tif;
    sp->stream.data_type = Z_BINARY;

    /*
     * Override parent get/set field methods.
     */
    sp->vgetparent = tif->tif_tagmethods.vgetfield;
    tif->tif_tagmethods.vgetfield = ZIPVGetField; /* hook for codec tags */
    sp->vsetparent = tif->tif_tagmethods.vsetfield;
    tif->tif_tagmethods.vsetfield = ZIPVSetField; /* hook for codec tags */

    /* Default values for codec-specific fields */
    sp->zipquality = Z_DEFAULT_COMPRESSION; /* default comp. level */
    sp->state = 0;
#if LIBDEFLATE_SUPPORT
    sp->subcodec = DEFLATE_SUBCODEC_LIBDEFLATE;
#else
    sp->subcodec = DEFLATE_SUBCODEC_ZLIB;
#endif

    /*
     * Install codec methods.
     */
    tif->tif_fixuptags = ZIPFixupTags;
    tif->tif_setupdecode = ZIPSetupDecode;
    tif->tif_predecode = ZIPPreDecode;
    tif->tif_decoderow = ZIPDecode;
    tif->tif_decodestrip = ZIPDecode;
    tif->tif_decodetile = ZIPDecode;
    tif->tif_setupencode = ZIPSetupEncode;
    tif->tif_preencode = ZIPPreEncode;
    tif->tif_postencode = ZIPPostEncode;
    tif->tif_encoderow = ZIPEncode;
    tif->tif_encodestrip = ZIPEncode;
    tif->tif_encodetile = ZIPEncode;
    tif->tif_cleanup = ZIPCleanup;
    /*
     * Setup predictor setup.
     */
    (void)TIFFPredictorInit(tif);
    return (1);
bad:
    TIFFErrorExtR(tif, module, "No space for ZIP state block");
    return (0);
}

static void *TIFF_zalloc(void *opaque, unsigned int items, unsigned int size)
{
    static const char module[] = "TIFF_zalloc";
    TIFF *tif = opaque;

    if (items > ~(size_t)0 / size)
    {
        TIFFErrorExtR(tif, module, "Overflow");
        return NULL;
    }

    return _TIFFmallocExt(tif, items * size);
}

static void TIFF_zfree(void *opaque, void *ptr)
{
    _TIFFfreeExt((TIFF *)opaque, ptr);
}

static int ZIPDecode(TIFF *tif, uint8_t *op, tmsize_t occ, uint16_t s)
{
    static const char module[] = "ZIPDecode";
    ZIPState *sp = ZIPDecoderState(tif);

    (void)s;
    assert(sp != NULL);
    assert(sp->state == ZSTATE_INIT_DECODE);

    if (sp->read_error)
    {
        memset(op, 0, (size_t)occ);
        TIFFErrorExtR(tif, module,
                      "ZIPDecode: Scanline %" PRIu32 " cannot be read due to "
                      "previous error",
                      tif->tif_row);
        return 0;
    }

#if LIBDEFLATE_SUPPORT
    if (sp->libdeflate_state == 1)
        return 0;

    /* If we have libdeflate support and we are asked to read a whole */
    /* strip/tile, then go for using it */
    do
    {
        TIFFDirectory *td = &tif->tif_dir;

        if (sp->libdeflate_state == 0)
            break;
        if (sp->subcodec == DEFLATE_SUBCODEC_ZLIB)
            break;

        /* Check if we are in the situation where we can use libdeflate */
        if (isTiled(tif))
        {
            if (TIFFTileSize64(tif) != (uint64_t)occ)
                break;
        }
        else
        {
            uint32_t strip_height = td->td_imagelength - tif->tif_row;
            if (strip_height > td->td_rowsperstrip)
                strip_height = td->td_rowsperstrip;
            if (TIFFVStripSize64(tif, strip_height) != (uint64_t)occ)
                break;
        }

        /* Check for overflow */
        if ((size_t)tif->tif_rawcc != (uint64_t)tif->tif_rawcc)
            break;
        if ((size_t)occ != (uint64_t)occ)
            break;

        /* Go for decompression using libdeflate */
        {
            enum libdeflate_result res;
            if (sp->libdeflate_dec == NULL)
            {
                sp->libdeflate_dec = libdeflate_alloc_decompressor();
                if (sp->libdeflate_dec == NULL)
                {
                    break;
                }
            }

            sp->libdeflate_state = 1;

            res = libdeflate_zlib_decompress(sp->libdeflate_dec, tif->tif_rawcp,
                                             (size_t)tif->tif_rawcc, op,
                                             (size_t)occ, NULL);

            tif->tif_rawcp += tif->tif_rawcc;
            tif->tif_rawcc = 0;

            /* We accept LIBDEFLATE_INSUFFICIENT_SPACE has a return */
            /* There are odd files in the wild where the last strip, when */
            /* it is smaller in height than td_rowsperstrip, actually contains
             */
            /* data for td_rowsperstrip lines. Just ignore that silently. */
            if (res != LIBDEFLATE_SUCCESS &&
                res != LIBDEFLATE_INSUFFICIENT_SPACE)
            {
                memset(op, 0, (size_t)occ);
                TIFFErrorExtR(tif, module, "Decoding error at scanline %lu",
                              (unsigned long)tif->tif_row);
                sp->read_error = 1;
                return 0;
            }

            return 1;
        }
    } while (0);
    sp->libdeflate_state = 0;
#endif /* LIBDEFLATE_SUPPORT */

    sp->stream.next_in = tif->tif_rawcp;

    sp->stream.next_out = op;
    assert(sizeof(sp->stream.avail_out) == 4); /* if this assert gets raised,
         we need to simplify this code to reflect a ZLib that is likely updated
         to deal with 8byte memory sizes, though this code will respond
         appropriately even before we simplify it */
    do
    {
        int state;
        uInt avail_in_before = TIFF_CLAMP_UINT64_TO_INT32_MAX(tif->tif_rawcc);
        uInt avail_out_before = TIFF_CLAMP_UINT64_TO_INT32_MAX(occ);
        sp->stream.avail_in = avail_in_before;
        sp->stream.avail_out = avail_out_before;
        state = inflate(&sp->stream, Z_PARTIAL_FLUSH);
        tif->tif_rawcc -= (avail_in_before - sp->stream.avail_in);
        occ -= (avail_out_before - sp->stream.avail_out);
        if (state == Z_STREAM_END)
            break;
        if (state == Z_DATA_ERROR)
        {
            memset(sp->stream.next_out, 0, (size_t)occ);
            TIFFErrorExtR(tif, module, "Decoding error at scanline %lu, %s",
                          (unsigned long)tif->tif_row, SAFE_MSG(sp));
            sp->read_error = 1;
            return (0);
        }
        if (state != Z_OK)
        {
            memset(sp->stream.next_out, 0, (size_t)occ);
            TIFFErrorExtR(tif, module, "ZLib error: %s", SAFE_MSG(sp));
            sp->read_error = 1;
            return (0);
        }
    } while (occ > 0);
    if (occ != 0)
    {
        TIFFErrorExtR(tif, module,
                      "Not enough data at scanline %lu (short %" PRIu64
                      " bytes)",
                      (unsigned long)tif->tif_row, (uint64_t)occ);
        memset(sp->stream.next_out, 0, (size_t)occ);
        sp->read_error = 1;
        return (0);
    }

    tif->tif_rawcp = sp->stream.next_in;

    return (1);
}

static int ZIPEncode(TIFF *tif, uint8_t *bp, tmsize_t cc, uint16_t s)
{
    static const char module[] = "ZIPEncode";
    ZIPState *sp = ZIPEncoderState(tif);

    assert(sp != NULL);
    assert(sp->state == ZSTATE_INIT_ENCODE);

    (void)s;

#if LIBDEFLATE_SUPPORT
    if (sp->libdeflate_state == 1)
        return 0;

    /* If we have libdeflate support and we are asked to write a whole */
    /* strip/tile, then go for using it */
    do
    {
        TIFFDirectory *td = &tif->tif_dir;

        if (sp->libdeflate_state == 0)
            break;
        if (sp->subcodec == DEFLATE_SUBCODEC_ZLIB)
            break;

        /* Libdeflate does not support the 0-compression level */
        if (sp->zipquality == Z_NO_COMPRESSION)
            break;

        /* Check if we are in the situation where we can use libdeflate */
        if (isTiled(tif))
        {
            if (TIFFTileSize64(tif) != (uint64_t)cc)
                break;
        }
        else
        {
            uint32_t strip_height = td->td_imagelength - tif->tif_row;
            if (strip_height > td->td_rowsperstrip)
                strip_height = td->td_rowsperstrip;
            if (TIFFVStripSize64(tif, strip_height) != (uint64_t)cc)
                break;
        }

        /* Check for overflow */
        if ((size_t)tif->tif_rawdatasize != (uint64_t)tif->tif_rawdatasize)
            break;
        if ((size_t)cc != (uint64_t)cc)
            break;

        /* Go for compression using libdeflate */
        {
            size_t nCompressedBytes;
            if (sp->libdeflate_enc == NULL)
            {
                /* To get results as good as zlib, we asked for an extra */
                /* level of compression */
                sp->libdeflate_enc = libdeflate_alloc_compressor(
                    sp->zipquality == Z_DEFAULT_COMPRESSION ? 7
                    : sp->zipquality >= 6 && sp->zipquality <= 9
                        ? sp->zipquality + 1
                        : sp->zipquality);
                if (sp->libdeflate_enc == NULL)
                {
                    TIFFErrorExtR(tif, module, "Cannot allocate compressor");
                    break;
                }
            }

            /* Make sure the output buffer is large enough for the worse case.
             */
            /* In TIFFWriteBufferSetup(), when libtiff allocates the buffer */
            /* we've taken a 10% margin over the uncompressed size, which should
             */
            /* be large enough even for the the worse case scenario. */
            if (libdeflate_zlib_compress_bound(sp->libdeflate_enc, (size_t)cc) >
                (size_t)tif->tif_rawdatasize)
            {
                break;
            }

            sp->libdeflate_state = 1;
            nCompressedBytes = libdeflate_zlib_compress(
                sp->libdeflate_enc, bp, (size_t)cc, tif->tif_rawdata,
                (size_t)tif->tif_rawdatasize);

            if (nCompressedBytes == 0)
            {
                TIFFErrorExtR(tif, module, "Encoder error at scanline %lu",
                              (unsigned long)tif->tif_row);
                return 0;
            }

            tif->tif_rawcc = nCompressedBytes;

            if (!TIFFFlushData1(tif))
                return 0;

            return 1;
        }
    } while (0);
    sp->libdeflate_state = 0;
#endif /* LIBDEFLATE_SUPPORT */

    sp->stream.next_in = bp;
    assert(sizeof(sp->stream.avail_in) == 4); /* if this assert gets raised,
         we need to simplify this code to reflect a ZLib that is likely updated
         to deal with 8byte memory sizes, though this code will respond
         appropriately even before we simplify it */
    do
    {
        uInt avail_in_before = TIFF_CLAMP_UINT64_TO_INT32_MAX(cc);
        sp->stream.avail_in = avail_in_before;
        if (deflate(&sp->stream, Z_NO_FLUSH) != Z_OK)
        {
            TIFFErrorExtR(tif, module, "Encoder error: %s", SAFE_MSG(sp));
            return (0);
        }
        if (sp->stream.avail_out == 0)
        {
            tif->tif_rawcc = tif->tif_rawdatasize;
            if (!TIFFFlushData1(tif))
                return 0;
            sp->stream.next_out = tif->tif_rawdata;
            sp->stream.avail_out =
                TIFF_CLAMP_UINT64_TO_INT32_MAX(tif->tif_rawdatasize);
        }
        cc -= (avail_in_before - sp->stream.avail_in);
    } while (cc > 0);
    return (1);
}

static int ZIPPreDecode(TIFF *tif, uint16_t s)
{
    ZIPState *sp = ZIPDecoderState(tif);

    (void)s;
    assert(sp != NULL);

    if ((sp->state & ZSTATE_INIT_DECODE) == 0)
        tif->tif_setupdecode(tif);

#if LIBDEFLATE_SUPPORT
    sp->libdeflate_state = -1;
#endif
    sp->stream.next_in = tif->tif_rawdata;
    assert(sizeof(sp->stream.avail_in) == 4); /* if this assert gets raised,
         we need to simplify this code to reflect a ZLib that is likely updated
         to deal with 8byte memory sizes, though this code will respond
         appropriately even before we simplify it */
    sp->stream.avail_in = TIFF_CLAMP_UINT64_TO_INT32_MAX(tif->tif_rawcc);
    if (inflateReset(&sp->stream) == Z_OK)
    {
        sp->read_error = 0;
        return 1;
    }
    return 0;
}

int test(int classictif, int height, int tiled)
{
    const char *filename = "defer_strile_loading.tif";
    TIFF *tif;
    int i;
    uint64_t ret = 0;
    FILE *f;

    (void)ret;

    tif = TIFFOpen(filename,
                   classictif ? "wDO"
                              : "w8DO"); /* O should be ignored in write mode */
    if (!tif)
    {
        fprintf(stderr, "cannot create %s\n", filename);
        return 1;
    }
    ret = TIFFSetField(tif, TIFFTAG_COMPRESSION, COMPRESSION_NONE);
    assert(ret);
    ret = TIFFSetField(tif, TIFFTAG_IMAGEWIDTH, 1);
    assert(ret);
    ret = TIFFSetField(tif, TIFFTAG_IMAGELENGTH, height);
    assert(ret);
    ret = TIFFSetField(tif, TIFFTAG_BITSPERSAMPLE, 8);
    assert(ret);
    ret = TIFFSetField(tif, TIFFTAG_SAMPLESPERPIXEL, 1);
    assert(ret);
    ret = TIFFSetField(tif, TIFFTAG_PLANARCONFIG, PLANARCONFIG_CONTIG);
    assert(ret);
    if (tiled)
    {
        int j;
        ret = TIFFSetField(tif, TIFFTAG_TILEWIDTH, 16);
        assert(ret);
        ret = TIFFSetField(tif, TIFFTAG_TILELENGTH, 16);
        assert(ret);
        for (j = 0; j < (height + 15) / 16; j++)
        {
            unsigned char tilebuffer[256];
            memset(tilebuffer, (unsigned char)j, 256);
            ret = TIFFWriteEncodedTile(tif, j, tilebuffer, 256);
            assert(ret == 256);
        }
    }
    else
    {
        ret = TIFFSetField(tif, TIFFTAG_ROWSPERSTRIP, 1);
        assert(ret);
        for (i = 0; i < height; i++)
        {
            unsigned char c = (unsigned char)i;
            ret = TIFFWriteEncodedStrip(tif, i, &c, 1);
            assert(ret == 1);

            if (i == 1 && height > 100000)
                i = height - 2;
        }
    }
    TIFFClose(tif);

    f = fopen(filename, "rb");
    if (!f)
        return 1;

    for (i = 0; i < 2; i++)
    {
        tif = TIFFOpen(filename, i == 0 ? "rD" : "rO");
        if (!tif)
        {
            fprintf(stderr, "cannot open %s\n", filename);
            fclose(f);
            return 1;
        }
        if (tiled)
        {
            int j;
            for (j = 0; j < (height + 15) / 16; j++)
            {
                int retry;
                unsigned char expected_c = (unsigned char)j;

                for (retry = 0; retry < 2; retry++)
                {
                    unsigned char tilebuffer[256];
                    memset(tilebuffer, 0, 256);
                    ret = TIFFReadEncodedTile(tif, j, tilebuffer, 256);
                    assert(ret == 256);
                    if (tilebuffer[0] != expected_c ||
                        tilebuffer[255] != expected_c)
                    {
                        fprintf(stderr, "unexpected value at tile %d: %d %d\n",
                                j, tilebuffer[0], tilebuffer[255]);
                        TIFFClose(tif);
                        fclose(f);
                        return 1;
                    }
                }

                {
                    int err = 0;
                    uint64_t offset, size;
                    unsigned char inputbuffer[256];
                    unsigned char tilebuffer[256];

                    offset = TIFFGetStrileOffsetWithErr(tif, j, &err);
                    assert(offset != 0);
                    assert(err == 0);

                    size = TIFFGetStrileByteCountWithErr(tif, j, &err);
                    (void)size;
                    assert(size == 256);
                    assert(err == 0);

                    if (offset > INT32_MAX)
                    {
                        fprintf(stderr,
                                "Offset %" PRId64 " exceeds fseek limit.\n",
                                offset);
                        TIFFClose(tif);
                        fclose(f);
                        return 1;
                    }
                    fseek(f, (long)offset, SEEK_SET);
                    {
                        size_t nread = fread(inputbuffer, 256, 1, f);
                        (void)nread;
                    }

                    memset(tilebuffer, 0, 256);
                    ret = TIFFReadFromUserBuffer(tif, j, inputbuffer, 256,
                                                 tilebuffer, 256);
                    assert(ret == 1);
                    if (tilebuffer[0] != expected_c ||
                        tilebuffer[255] != expected_c)
                    {
                        fprintf(stderr, "unexpected value at tile %d: %d %d\n",
                                j, tilebuffer[0], tilebuffer[255]);
                        TIFFClose(tif);
                        fclose(f);
                        return 1;
                    }
                }
            }
        }
        else
        {
            int j;
            for (j = 0; j < height; j++)
            {
                int retry;
                unsigned char expected_c = (unsigned char)j;
                for (retry = 0; retry < 2; retry++)
                {
                    unsigned char c = 0;
                    ret = TIFFReadEncodedStrip(tif, j, &c, 1);
                    assert(ret == 1);
                    if (c != expected_c)
                    {
                        fprintf(stderr, "unexpected value at line %d: %d\n", j,
                                c);
                        TIFFClose(tif);
                        fclose(f);
                        return 1;
                    }
                }

                {
                    int err = 0;
                    uint64_t offset, size;
                    unsigned char inputbuffer[1];
                    unsigned char tilebuffer[1];

                    offset = TIFFGetStrileOffsetWithErr(tif, j, &err);
                    assert(offset != 0);
                    assert(err == 0);

                    size = TIFFGetStrileByteCountWithErr(tif, j, &err);
                    (void)size;
                    assert(size == 1);
                    assert(err == 0);

                    if (offset > INT32_MAX)
                    {
                        fprintf(stderr,
                                "Offset %" PRId64 " exceeds fseek limit.\n",
                                offset);
                        TIFFClose(tif);
                        fclose(f);
                        return 1;
                    }
                    fseek(f, (long)offset, SEEK_SET);
                    {
                        size_t nread = fread(inputbuffer, 1, 1, f);
                        (void)nread;
                    }
                    memset(tilebuffer, 0, 1);
                    ret = TIFFReadFromUserBuffer(tif, j, inputbuffer, 1,
                                                 tilebuffer, 1);
                    assert(ret == 1);
                    if (tilebuffer[0] != expected_c)
                    {
                        fprintf(stderr, "unexpected value at line %d: %d\n", j,
                                tilebuffer[0]);
                        TIFFClose(tif);
                        fclose(f);
                        return 1;
                    }
                }

                if (j == 1 && height > 100000)
                    j = height - 2;
            }

            if (height > 100000)
            {
                /* Missing strip */
                int err = 0;
                ret = TIFFGetStrileOffsetWithErr(tif, 2, &err);
                assert(ret == 0);
                assert(err == 0);

                ret = TIFFGetStrileByteCountWithErr(tif, 2, &err);
                assert(ret == 0);
                assert(err == 0);
            }
        }

        {
            int err = 0;
            ret = TIFFGetStrileOffsetWithErr(tif, 0xFFFFFFFFU, &err);
            assert(ret == 0);
            assert(err == 1);

            ret = TIFFGetStrileByteCountWithErr(tif, 0xFFFFFFFFU, &err);
            assert(ret == 0);
            assert(err == 1);
        }

        {
            toff_t *offsets = NULL;
            toff_t *bytecounts = NULL;
            ret = TIFFGetField(
                tif, tiled ? TIFFTAG_TILEOFFSETS : TIFFTAG_STRIPOFFSETS,
                &offsets);
            assert(ret);
            assert(offsets);
            ret = TIFFGetField(
                tif, tiled ? TIFFTAG_TILEBYTECOUNTS : TIFFTAG_STRIPBYTECOUNTS,
                &bytecounts);
            assert(ret);
            assert(bytecounts);
            if (tiled)
            {
                assert(bytecounts[0] == 256);
            }
            else
            {
                assert(bytecounts[0] == 1);
                if (height > 1 && height <= 100000)
                {
                    assert(offsets[1] == offsets[0] + 1);
                    assert(offsets[height - 1] == offsets[0] + height - 1);
                }
                assert(bytecounts[height - 1] == 1);
            }
        }

        TIFFClose(tif);
    }
    fclose(f);

    unlink(filename);
    return 0;
}

int test(const char *mode, int tiled, int height)
{
    const char *filename = "defer_strile_writing.tif";
    TIFF *tif;
    int i;
    tmsize_t ret = 0;
    (void)ret;

    tif = TIFFOpen(filename, mode);
    if (!tif)
    {
        fprintf(stderr, "cannot create %s\n", filename);
        return 1;
    }
    ret = TIFFSetField(tif, TIFFTAG_COMPRESSION, COMPRESSION_NONE);
    assert(ret);
    ret = TIFFSetField(tif, TIFFTAG_IMAGEWIDTH, 1);
    assert(ret);
    ret = TIFFSetField(tif, TIFFTAG_IMAGELENGTH, height);
    assert(ret);
    ret = TIFFSetField(tif, TIFFTAG_BITSPERSAMPLE, 8);
    assert(ret);
    ret = TIFFSetField(tif, TIFFTAG_SAMPLESPERPIXEL, 1);
    assert(ret);
    ret = TIFFSetField(tif, TIFFTAG_PLANARCONFIG, PLANARCONFIG_CONTIG);
    assert(ret);

    if (tiled)
    {
        ret = TIFFSetField(tif, TIFFTAG_TILEWIDTH, 16);
        assert(ret);
        ret = TIFFSetField(tif, TIFFTAG_TILELENGTH, 16);
        assert(ret);
    }
    else
    {
        ret = TIFFSetField(tif, TIFFTAG_ROWSPERSTRIP, 1);
        assert(ret);
    }

    ret = TIFFDeferStrileArrayWriting(tif);
    assert(ret);

    ret = TIFFWriteCheck(tif, tiled, "test");
    assert(ret);

    ret = TIFFWriteDirectory(tif);
    assert(ret);

    /* Create other directory */
    TIFFFreeDirectory(tif);
    TIFFCreateDirectory(tif);

    ret = TIFFSetField(tif, TIFFTAG_SUBFILETYPE, FILETYPE_PAGE);
    assert(ret);
    ret = TIFFSetField(tif, TIFFTAG_COMPRESSION, COMPRESSION_NONE);
    assert(ret);
    ret = TIFFSetField(tif, TIFFTAG_IMAGEWIDTH, 1);
    assert(ret);
    ret = TIFFSetField(tif, TIFFTAG_IMAGELENGTH, 1);
    assert(ret);
    ret = TIFFSetField(tif, TIFFTAG_BITSPERSAMPLE, 8);
    assert(ret);
    ret = TIFFSetField(tif, TIFFTAG_SAMPLESPERPIXEL, 1);
    assert(ret);
    ret = TIFFSetField(tif, TIFFTAG_PLANARCONFIG, PLANARCONFIG_CONTIG);
    assert(ret);
    ret = TIFFSetField(tif, TIFFTAG_ROWSPERSTRIP, 1);
    assert(ret);

    ret = TIFFDeferStrileArrayWriting(tif);
    assert(ret);

    ret = TIFFWriteCheck(tif, 0, "test");
    assert(ret);

    ret = TIFFWriteDirectory(tif);
    assert(ret);

    /* Force writing of strile arrays */
    ret = TIFFSetDirectory(tif, 0);
    assert(ret);

    ret = TIFFForceStrileArrayWriting(tif);
    assert(ret);

    ret = TIFFSetDirectory(tif, 1);
    assert(ret);

    ret = TIFFForceStrileArrayWriting(tif);
    assert(ret);

    /* Now write data on first directory */
    ret = TIFFSetDirectory(tif, 0);
    assert(ret);

    if (tiled)
    {
        int j;
        for (j = 0; j < (height + 15) / 16; j++)
        {
            unsigned char tilebuffer[256];
            memset(tilebuffer, (unsigned char)j, 256);
            ret = TIFFWriteEncodedTile(tif, j, tilebuffer, 256);
            assert(ret == 256);
        }
    }
    else
    {
        for (i = 0; i < height; i++)
        {
            unsigned char c = (unsigned char)i;
            ret = TIFFWriteEncodedStrip(tif, i, &c, 1);
            assert(ret == 1);

            if (i == 1 && height > 100000)
                i = height - 2;
        }
    }

    TIFFClose(tif);

    tif = TIFFOpen(filename, "r");
    if (!tif)
    {
        fprintf(stderr, "cannot open %s\n", filename);
        return 1;
    }
    if (tiled)
    {
        int j;
        for (j = 0; j < (height + 15) / 16; j++)
        {
            int retry;
            for (retry = 0; retry < 2; retry++)
            {
                unsigned char tilebuffer[256];
                unsigned char expected_c = (unsigned char)j;
                memset(tilebuffer, 0, 256);
                ret = TIFFReadEncodedTile(tif, j, tilebuffer, 256);
                assert(ret == 256);
                if (tilebuffer[0] != expected_c ||
                    tilebuffer[255] != expected_c)
                {
                    fprintf(stderr, "unexpected value at tile %d: %d %d\n", j,
                            tilebuffer[0], tilebuffer[255]);
                    TIFFClose(tif);
                    return 1;
                }
            }
        }
    }
    else
    {
        int j;
        for (j = 0; j < height; j++)
        {
            int retry;
            for (retry = 0; retry < 2; retry++)
            {
                unsigned char c = 0;
                unsigned char expected_c = (unsigned char)j;
                ret = TIFFReadEncodedStrip(tif, j, &c, 1);
                assert(ret == 1);
                if (c != expected_c)
                {
                    fprintf(stderr, "unexpected value at line %d: %d\n", j, c);
                    TIFFClose(tif);
                    return 1;
                }
            }
        }
    }

    TIFFClose(tif);

    unlink(filename);
    return 0;
}

void checkOpenLogFile(int blnReOpen)
{
    /* First open logfile, if it does not exist, otherwise leave it as is except
     * blnReOpen is set. */
    if (blnReOpen && fpLog != NULL)
    {
        fclose(fpLog);
        fpLog = NULL;
    }

    if (fpLog == NULL && logFilename != NULL)
    {
        fpLog = fopen(logFilename, "a");
        if (fpLog == NULL)
        {
            fprintf(stderr, "\nError: Could not open logfile %s.\n",
                    logFilename);
        }
    }

    /* Switch stdXOut to logFile, if ...*/
    if (blnStdOutToLogFile)
    {
        if (fpLog != NULL)
        {
            stdXOut = fpLog;
        }
    }
    if (stdXOut == NULL)
    {
        fprintf(stderr, "\nError: stdXOut is NULL - exiting.\n");
        exit(10);
    }
    return;
}

#define A1 (((uint32_t)0xffL) << 24)
#define PACK(r, g, b)                                                          \
    ((uint32_t)(r) | ((uint32_t)(g) << 8) | ((uint32_t)(b) << 16) | A1)

#define RASTER_MEMSETVAL 0xba

/* Check some contents of the raster buffer. Ensure they are correctly filled.
 */
int checkRasterContents(char *txt, TIFFRGBAImage *img, uint32_t *raster,
                        uint32_t rw, uint32_t rh, uint16_t orientation)
{
    /* For this test, the image pixel samples are set for R= row, G= column, B=
     * 0xfe and the last raster component is 0xff. The raster is preset with
     * 0xbe. In general, according to documentation:
     *  - If the raster height is greater than that of the image, then the image
     * data are placed in the lower part of the raster.
     *  - If the raster width is greater than that of the image, then the image
     * data are placed in the left part of the raster.
     */
    typedef union
    {
        uint8_t u8[4];
        uint32_t u32;
    } RasterPixel;
    typedef struct
    {
        uint32_t x;
        uint32_t y;
    } Coordinate;

    (void)txt;

    /* Exit for special test case */
    if (rh == 0 || rw == 0)
        return 0;

    /* When image is cropped, or raster is larger than image, determine crop
     * lengths for image within raster. */
    uint32_t rwmin = TIFFmin(rw, img->width - img->col_offset);
    uint32_t rhmin = TIFFmin(rh, img->height - img->row_offset);
    /* When there is a col_offset or row_offset, the image pixels of the corners
     * are differently. */
    uint32_t xcol_start = img->col_offset;
    uint32_t xrow_start = img->row_offset;

    /* Pixel values of image corner pixels according to image dimensions written
     * in write_image_data(). Pixel values are set to (rowIdx, colIdx, 0xfe).
     * The first pixel stored in the file is P0 with I0=(0,0,0xfe);
     * the last pixel of the first data row is P1 with I1=(0,imgWidth-1,0xfe);
     * the first pixel of the last row is P2 with I2=(imgLength-1,0,0xfe) and
     * the last pixel of the last row is P3 with
     * I3=(imgLength-1,imgWidth-1,0xfe). P/I are arranged in Z-order: P0---P1
     *    P2---P3
     * I01 is value of row-0 and col-1 or in image coordinates x=1, y=0.
     */
    RasterPixel I[8];
    /* Without offsets: */
    // I[0].u32 = PACK(0, 0, 0xfe);
    // I[1].u32 = PACK(0, rwmin - 1, 0xfe);
    // I[2].u32 = PACK(rhmin - 1, 0, 0xfe);
    // I[3].u32 = PACK(rhmin - 1, rwmin - 1, 0xfe);
    /* With offsets: */
    I[0].u32 = PACK(xrow_start, xcol_start, 0xfe);
    I[1].u32 = PACK(xrow_start, xcol_start + rwmin - 1, 0xfe);
    I[2].u32 = PACK(xrow_start + rhmin - 1, xcol_start, 0xfe);
    I[3].u32 = PACK(xrow_start + rhmin - 1, xcol_start + rwmin - 1, 0xfe);
    /* The value of the next pixels in the row (or behind) to the pixels P0 th
     * P3 is: P0, P4 --- P1, P5 P2, P6 --- P3, P7
     */
    I[4].u32 = PACK(I[0].u8[0], I[0].u8[1] + 1, 0xfe);
    I[5].u32 = PACK(RASTER_MEMSETVAL, RASTER_MEMSETVAL, RASTER_MEMSETVAL);
    I[6].u32 = PACK(I[2].u8[2], I[2].u8[1] + 1, 0xfe);
    I[7].u32 = PACK(RASTER_MEMSETVAL, RASTER_MEMSETVAL, RASTER_MEMSETVAL);

    /* Depending on orientation (and requested orientation) the input data are
     * fliped horizontally and / or vertically. Without rotation, this leads to
     * four possible orientations (locations of the first pixel from the image
     * file). See tif_getimage.c setorientation(). If the raster matrix is
     * larger than the image, the image data is stored in the lower-left part of
     * the raster matrix.
     *
     * "firstPixelAt" gives the orientation of the data from file, stored in the
     * raster matrix; i.e. the location of the first pixel from the file.
     */

    int firstPixelAt =
        ORIENTATION_TOPLEFT; /* if data from file is not flipped */
    switch (orientation)
    {
        case ORIENTATION_TOPLEFT:
        case ORIENTATION_LEFTTOP:
            if (img->req_orientation == ORIENTATION_TOPRIGHT ||
                img->req_orientation == ORIENTATION_RIGHTTOP)
                firstPixelAt = ORIENTATION_TOPRIGHT; // FLIP_HORIZONTALLY
            else if (img->req_orientation == ORIENTATION_BOTRIGHT ||
                     img->req_orientation == ORIENTATION_RIGHTBOT)
                firstPixelAt = ORIENTATION_BOTRIGHT; // FLIP_HORIZONTALLY |
                                                     // FLIP_VERTICALLY;
            else if (img->req_orientation == ORIENTATION_BOTLEFT ||
                     img->req_orientation == ORIENTATION_LEFTBOT)
                firstPixelAt = ORIENTATION_BOTLEFT; // FLIP_VERTICALLY;
            break;
        case ORIENTATION_TOPRIGHT:
        case ORIENTATION_RIGHTTOP:
            if (img->req_orientation == ORIENTATION_TOPLEFT ||
                img->req_orientation == ORIENTATION_LEFTTOP)
                firstPixelAt = ORIENTATION_TOPRIGHT; // FLIP_HORIZONTALLY;
            else if (img->req_orientation == ORIENTATION_BOTRIGHT ||
                     img->req_orientation == ORIENTATION_RIGHTBOT)
                firstPixelAt = ORIENTATION_BOTLEFT; // FLIP_VERTICALLY;
            else if (img->req_orientation == ORIENTATION_BOTLEFT ||
                     img->req_orientation == ORIENTATION_LEFTBOT)
                firstPixelAt = ORIENTATION_BOTRIGHT; // FLIP_HORIZONTALLY |
                                                     // FLIP_VERTICALLY;
            break;
        case ORIENTATION_BOTRIGHT:
        case ORIENTATION_RIGHTBOT:
            if (img->req_orientation == ORIENTATION_TOPLEFT ||
                img->req_orientation == ORIENTATION_LEFTTOP)
                firstPixelAt = ORIENTATION_BOTRIGHT; // FLIP_HORIZONTALLY |
                                                     // FLIP_VERTICALLY;
            else if (img->req_orientation == ORIENTATION_TOPRIGHT ||
                     img->req_orientation == ORIENTATION_RIGHTTOP)
                firstPixelAt = ORIENTATION_BOTLEFT; // FLIP_VERTICALLY;
            else if (img->req_orientation == ORIENTATION_BOTLEFT ||
                     img->req_orientation == ORIENTATION_LEFTBOT)
                firstPixelAt = ORIENTATION_TOPRIGHT; // FLIP_HORIZONTALLY;
            break;
        case ORIENTATION_BOTLEFT:
        case ORIENTATION_LEFTBOT:
            if (img->req_orientation == ORIENTATION_TOPLEFT ||
                img->req_orientation == ORIENTATION_LEFTTOP)
                firstPixelAt = ORIENTATION_BOTLEFT; // FLIP_VERTICALLY;
            else if (img->req_orientation == ORIENTATION_TOPRIGHT ||
                     img->req_orientation == ORIENTATION_RIGHTTOP)
                firstPixelAt = ORIENTATION_BOTRIGHT; // FLIP_HORIZONTALLY |
                                                     // FLIP_VERTICALLY;
            else if (img->req_orientation == ORIENTATION_BOTRIGHT ||
                     img->req_orientation == ORIENTATION_RIGHTBOT)
                firstPixelAt = ORIENTATION_TOPRIGHT; // FLIP_HORIZONTALLY;
            break;
        default: /* NOTREACHED */
            break;
    }

    /* Determine position in raster-matrix (0..rw-1 / 0..rh-1)
     * If the raster matrix is larger than the image, the image data is stored
     * in the lower-left part of the raster matrix.
     * P0 to P3 are image corner in Z-order sequence within raster matrix:
     *    P0---P1
     *    P2---P3
     */
    Coordinate P[8];
    switch (firstPixelAt)
    {
        case ORIENTATION_TOPLEFT:
            P[0].x = 0;
            P[0].y = TIFFmax(0, (tmsize_t)rh - rhmin);
            P[1].x = rwmin - 1;
            P[1].y = TIFFmax(0, (tmsize_t)rh - rhmin);
            P[2].x = 0;
            P[2].y = rh - 1;
            P[3].x = rwmin - 1;
            P[3].y = rh - 1;
            break;
        case ORIENTATION_TOPRIGHT:
            P[0].x = rwmin - 1;
            P[0].y = TIFFmax(0, (tmsize_t)rh - rhmin);
            P[1].x = 0;
            P[1].y = TIFFmax(0, (tmsize_t)rh - rhmin);
            P[2].x = rwmin - 1;
            P[2].y = rh - 1;
            P[3].x = 0;
            P[3].y = rh - 1;
            break;
        case ORIENTATION_BOTRIGHT:
            P[0].x = rwmin - 1;
            P[0].y = rh - 1;
            P[1].x = 0;
            P[1].y = rh - 1;
            P[2].x = rwmin - 1;
            P[2].y = TIFFmax(0, (tmsize_t)rh - rhmin);
            P[3].x = 0;
            P[3].y = TIFFmax(0, (tmsize_t)rh - rhmin);
            break;
        case ORIENTATION_BOTLEFT:
            P[0].x = 0;
            P[0].y = rh - 1;
            P[1].x = rwmin - 1;
            P[1].y = rh - 1;
            P[2].x = 0;
            P[2].y = TIFFmax(0, (tmsize_t)rh - rhmin);
            P[3].x = rwmin - 1;
            P[3].y = TIFFmax(0, (tmsize_t)rh - rhmin);
            break;
        default: /* NOTREACHED */
            fprintf(stdXOut, "Error in SWITCH statement at line %d", __LINE__);
            goto failure;
            break;
    }

    /* Determine offset of P[i] into the raster of uint32_t: */
    uint32_t roff[8];
#define NUMP 4
    for (int i = 0; i < NUMP; i++)
    {
        roff[i] = P[i].y * rw + P[i].x;
    }

    /* Check value of corner pixels at expected location in raster. */
    RasterPixel a;
    for (int i = 0; i < NUMP; i++)
    {
        a.u32 = raster[roff[i]];
        if (a.u32 != I[i].u32)
        {
            fprintf(stdXOut,
                    "\nPixel value of P%d = (%d, %d, %d)/(%02x, %02x, %02x) in "
                    "raster at offset %d does not match expected value "
                    "(%d, "
                    "%d, %d)/(%02x, %02x, %02x)",
                    i, a.u8[0], a.u8[1], a.u8[2], a.u8[0], a.u8[1], a.u8[2],
                    roff[i], I[i].u8[0], I[i].u8[1], I[i].u8[2], I[i].u8[0],
                    I[i].u8[1], I[i].u8[2]);
            goto failure;
        }
    }
    return 0;

failure:
    return 1;
} /*-- checkRasterContents() --*/

int main()
{
    int retval = 0;
    int retvalLast = 0;
    int ntest = 0;
    char filename[128] = {0};

    if (logFilename != NULL)
    {
        unlink(logFilename);
        if (blnMultipleLogFiles)
        {
            for (unsigned int i = 0;
                 i < (sizeof(arrLogFilenames) / sizeof(arrLogFilenames[0]));
                 i++)
            {
                unlink(arrLogFilenames[i]);
            }
        }
    }

    /* Set default output to stderr. */
    stdXOut = stderr;

    /* If fprintf shall be redirected from stderr to logFile. */
    checkOpenLogFile(FALSE);

    /* Individual single testcase. */
    if (blnSpecialTest)
    {
        retval +=
            test_ReadRGBAImage("test_RGBAImage_xxx.tif", 0, 1, 8, 4, FALSE, 1);
        return 0;
    }

    fprintf(stdXOut, "==== Testing RGBAImage... ====\n");
    if (stdXOut != stderr)
        fprintf(stderr, "==== Testing RGBAImage... ====\n");

    unsigned int openMode = 0;
    for (int tiled = 0; tiled <= 1; tiled++)
    {
        fprintf(stdXOut,
                "\n---------------------------------------------"
                "\n==== Testing %s with openMode = %s ===="
                "\n---------------------------------------------\n",
                (tiled ? "TILED" : "STRIP"), modeStrings[openMode]);
        for (planarconfig = PLANARCONFIG_CONTIG;
             planarconfig <= PLANARCONFIG_SEPARATE; planarconfig++)
        {
            if (blnMultipleLogFiles)
            {
                unsigned int n = tiled * 2 + (planarconfig - 1);
                assert(n <
                       (sizeof(arrLogFilenames) / sizeof(arrLogFilenames[0])));
                logFilename = arrLogFilenames[n];
                checkOpenLogFile(TRUE);
            }
            for (unsigned int orientation = 1; orientation < 9; orientation++)
            {
                for (unsigned int req_orientation = 1; req_orientation < 9;
                     req_orientation++)
                {
                    sprintf(filename, "test_RGBAImage_%02d_%s_%s_%s_%s-%s.tif",
                            ntest, modeStrings[openMode], (tiled ? "TL" : "ST"),
                            (planarconfig == 1 ? "CONTIG" : "SEPARATE"),
                            orientationStrings[orientation],
                            orientationStrings[req_orientation]);
                    /* clang-format off */
                retval += test_ReadRGBAImage(filename, openMode, orientation,8, 4, tiled, req_orientation);  ntest++;
                if (retval != retvalLast) { fprintf(stdXOut, "    >>>> Test %d FAILED  (openMode %s; tiled=%d). <<<<\n\n", ntest, modeStrings[openMode], tiled); retvalLast = retval; }
                retval += test_ReadRGBAImage(filename, openMode, orientation,16, 16, tiled, req_orientation);  ntest++;
                if (retval != retvalLast) { fprintf(stdXOut, "    >>>> Test %d FAILED  (openMode %s; tiled=%d). <<<<\n\n", ntest, modeStrings[openMode], tiled); retvalLast = retval; }
                retval += test_ReadRGBAImage(filename, openMode, orientation,31, 18, tiled, req_orientation);  ntest++;
                if (retval != retvalLast) { fprintf(stdXOut, "    >>>> Test %d FAILED  (openMode %s; tiled=%d). <<<<\n\n", ntest, modeStrings[openMode], tiled); retvalLast = retval; }
                retval += test_ReadRGBAImage(filename, openMode, orientation,32, 32, tiled, req_orientation);  ntest++;
                if (retval != retvalLast) { fprintf(stdXOut, "    >>>> Test %d FAILED  (openMode %s; tiled=%d). <<<<\n\n", ntest, modeStrings[openMode], tiled); retvalLast = retval; }
                    /* clang-format on */
                }
            }
        }
    }

    if (!retval)
    {
        fprintf(stdXOut, "\n==== Testing RGBAImage finished OK. ====\n");
        if (stdXOut != stderr)
            fprintf(stderr, "\n==== Testing RGBAImage finished OK. ====\n");
    }
    else
    {
        fprintf(stdXOut,
                "\n==== Testing RGBAImage finished with ERROR. ====\n");
        if (stdXOut != stderr)
            fprintf(stderr,
                    "\n==== Testing RGBAImage finished with ERROR. ====\n");
    }

    return retval;
} /*-- main() -- */

void printRaster(char *txt, TIFFRGBAImage *img, uint32_t *raster, uint32_t rw,
                 uint32_t rh, uint16_t orientation, bool tiled)
{
    uint32_t h, w;
    FILE *fp = NULL;
    union
    {
        uint8_t u8[4];
        uint32_t u32;
    } u;
    char straux[2048];

    /* If fpLog is already open, don't open and close that file. */
    if (fpLog != NULL)
        fp = fpLog;
    else if (logFilename != NULL)
        fp = fopen(logFilename, "a");

    if (img->col_offset != 0 || img->row_offset != 0)
    {
        sprintf(straux,
                "\n--- (%3d /%3d) Orientation = %d (%s) %s, %s readWidth = %d, "
                "readLength = %d, col_off = %d, row_off = %d, "
                "req_orientation=%d (%s) using %s---\n",
                img->width, img->height, orientation,
                orientationStrings[orientation],
                (planarconfig == 1 ? "CONTIG" : "SEPARATE"),
                (tiled ? "TILED" : "STRIP"), rw, rh, img->col_offset,
                img->row_offset, img->req_orientation,
                orientationStrings[img->req_orientation], txt);
    }
    else
    {
        sprintf(straux,
                "\n--- (%3d /%3d) Orientation = %d (%s) %s, %s readWidth = %d, "
                "readLength = %d, req_orientation=%d (%s) using "
                "%s---\n",
                img->width, img->height, orientation,
                orientationStrings[orientation],
                (planarconfig == 1 ? "CONTIG" : "SEPARATE"),
                (tiled ? "TILED" : "STRIP"), rw, rh, img->req_orientation,
                orientationStrings[img->req_orientation], txt);
    }
    if (fp != NULL)
        fprintf(fp, "%s", straux);
    if (blnPrintRasterToScreen)
        fprintf(stdout, "%s", straux);
    for (h = 0; h < rh; h++)
    {
        for (w = 0; w < rw; w++)
        {
            u.u32 = raster[h * rw + w];
            sprintf(straux, "%02x %02x %02x %02x ", u.u8[0], u.u8[1], u.u8[2],
                    u.u8[3]);
            if (fp != NULL)
                fprintf(fp, "%s", straux);
            if (blnPrintRasterToScreen)
                fprintf(stdout, "%s", straux);
        }
        sprintf(straux, "\n");
        if (fp != NULL)
            fprintf(fp, "%s", straux);
        if (blnPrintRasterToScreen)
            fprintf(stdout, "%s", straux);
    }
    sprintf(straux, "--------------\n");
    if (fp != NULL)
    {
        fprintf(fp, "%s", straux);
        if (fpLog == NULL)
            fclose(fp);
    }
    if (blnPrintRasterToScreen)
        fprintf(stdout, "%s", straux);
    return;
} /*-- printRaster() --*/

/* Calls TIFFRGBAImageGet() and TIFFReadRGBAImage() with given raster sizes and
 * reads the data from file into that raster. The raster content of both
 * functions is printed and checked.
 */
int testRGBAImageReadFunctions(TIFF *tif, uint32_t imgWidth, uint32_t imgLength,
                               uint32_t rWidth, uint32_t rHeight,
                               uint16_t orientation, uint16_t req_orientation,
                               int cLine)
{
    int ret;
    uint32_t *raster1 = NULL;
    uint32_t *raster2 = NULL;
    char emsg[1024] = "";
    TIFFRGBAImage img;
    int ok;

    /* Just for debugging output in printRaster() */
    bool tiledlocal = TIFFIsTiled(tif);

    tmsize_t rasterSize = sizeof(uint32_t) * rWidth * rHeight;
    if (rasterSize == 0)
    {
        rasterSize = sizeof(uint32_t) * imgWidth * imgLength;
    }
    raster1 = (uint32_t *)_TIFFmalloc(rasterSize);
    raster2 = (uint32_t *)_TIFFmalloc(rasterSize);
    if (raster1 == NULL || raster2 == NULL)
    {
        fprintf(stdXOut,
                "Can't allocate 'raster'-buffer. Testline %d called from %d\n",
                __LINE__, cLine);
        goto failure;
    }
    memset(raster1, RASTER_MEMSETVAL, rasterSize);
    memset(raster2, RASTER_MEMSETVAL, rasterSize);

    if (TIFFRGBAImageBegin(&img, tif, 0, emsg))
    {
        img.req_orientation = req_orientation;
        ok = TIFFRGBAImageGet(&img, raster1, rWidth, rHeight);
        printRaster("TIFFRGBAImageGet()", &img, raster1, rWidth, rHeight,
                    orientation, tiledlocal);
        TIFFRGBAImageEnd(&img);
        if (ok != 1)
        {
            fprintf(stdXOut,
                    "TIFFRGBAImageGet() returned failure. Testline %d called "
                    "from %d\n",
                    __LINE__, cLine);
            goto failure;
        }
        if ((ret = checkRasterContents("TIFFRGBAImageGet()", &img, raster1,
                                       rWidth, rHeight, orientation)))
            goto failure;
    }

    _TIFFfree(raster1);
    _TIFFfree(raster2);
    return 0;

failure:
    if (raster1)
        _TIFFfree(raster1);
    if (raster2)
        _TIFFfree(raster2);
    return 1;
} /*-- testRGBAImageReadFunctions() --*/

/* Calls TIFFRGBAImageGet() with col_offset and row_offset and with a given
 * raster and reads the data from file into that raster. The raster content is
 * printed and checked.
 */
int testRGBAImageReadWithOffsets(TIFF *tif, uint32_t imgWidth,
                                 uint32_t imgLength, int w_offset, int l_offset,
                                 uint32_t rWidth, uint32_t rHeight,
                                 uint16_t orientation, uint16_t req_orientation,
                                 int cLine)
{
    int ret;
    uint32_t *raster1 = NULL;
    char emsg[1024] = "";
    TIFFRGBAImage img;
    int ok;

    /* Just for debugging output in printRaster() */
    bool tiledlocal = TIFFIsTiled(tif);

    tmsize_t rasterSize = sizeof(uint32_t) * rWidth * rHeight;
    if (rasterSize == 0)
    {
        rasterSize = sizeof(uint32_t) * imgWidth * imgLength;
    }
    raster1 = (uint32_t *)_TIFFmalloc(rasterSize);
    if (raster1 == NULL)
    {
        fprintf(stdXOut,
                "Can't allocate 'raster'-buffer. Testline %d called from %d\n",
                __LINE__, cLine);
        goto failure;
    }
    memset(raster1, RASTER_MEMSETVAL, rasterSize);

    if (TIFFRGBAImageBegin(&img, tif, 0, emsg))
    {
        img.req_orientation = req_orientation;
        img.col_offset = w_offset;
        img.row_offset = l_offset;
        ok = TIFFRGBAImageGet(&img, raster1, rWidth, rHeight);
        printRaster("TIFFRGBAImageGet()", &img, raster1, rWidth, rHeight,
                    orientation, tiledlocal);
        TIFFRGBAImageEnd(&img);
        if (ok != 1)
        {
            if (!blnQuiet)
                fprintf(stdXOut,
                        "TIFFRGBAImageGet() returned failure in test with "
                        "offsets. Testline %d called from %d\n",
                        __LINE__, cLine);
            goto failure;
        }
        if ((ret = checkRasterContents("TIFFRGBAImageGet()", &img, raster1,
                                       rWidth, rHeight, orientation)))
            goto failure;
    }
    _TIFFfree(raster1);
    return 0;

failure:
    if (raster1)
        _TIFFfree(raster1);
    return 1;
} /*-- testRGBAImageReadWithOffsets() --*/

int test_ReadRGBAImage(const char *filename, unsigned int openMode,
                       uint16_t orientation, uint32_t width, uint32_t length,
                       bool tiled, unsigned int req_orientation)
{

    int ret;
    TIFFErrorHandler errHandler = NULL;

    assert(openMode < (sizeof(modeStrings) / sizeof(modeStrings[0])));
    assert(orientation <
           (sizeof(orientationStrings) / sizeof(orientationStrings[0])));
    blnQuiet = FALSE;

#ifdef DEBUG_TESTING
    fprintf(stdXOut,
            "\n==== test_ReadRGBAImage() - sequence --- Orientation = %d (%s) "
            "%s, %s ====\n",
            orientation, orientationStrings[orientation],
            (planarconfig == 1 ? "CONTIG" : "SEPARATE"),
            (tiled ? "TILED" : "STRIP"));
#else
    fprintf(stdXOut, ".");
#endif
    /*-- Create a file and write numIFDs IFDs directly to it --*/
    TIFF *tif = TIFFOpen(filename, modeStrings[openMode]);
    if (!tif)
    {
        fprintf(stdXOut, "\nCan't create %s. Testline %d\n", filename,
                __LINE__);
        return 1;
    }

    /* Writing baseline images (IFDs) to file. */
    if (write_data_to_current_directory(tif, width, length, tiled, orientation,
                                        true, NULL, 0))
    {
        fprintf(stdXOut,
                "\nCan't write data to current directory in %s. Testline %d\n",
                filename, __LINE__);
        goto failure;
    }
    /* Write IFD tags to file (and setup new empty IFD). */
    TIFFWriteDirectory_M(tif, filename, __LINE__);
    TIFFClose(tif);
    TIFFOpen_M(tif, filename, "r", __LINE__);

    if (blnSpecialTest)
        goto testcase;

    /*=== Test basic function TIFFRGBAImageGet() ===*/
    /* Full image */
    if ((ret = testRGBAImageReadFunctions(tif, width, length, width, length,
                                          orientation, req_orientation,
                                          __LINE__)))
        GOTOFAILURE

    /* More lines - result will be different for NewCode - */
    if ((ret = testRGBAImageReadFunctions(tif, width, length, width, length + 2,
                                          orientation, req_orientation,
                                          __LINE__)))
        GOTOFAILURE

    /* Less lines */
    if ((ret = testRGBAImageReadFunctions(tif, width, length, width, length - 1,
                                          orientation, req_orientation,
                                          __LINE__)))
        GOTOFAILURE

    /* Less columns */
    if ((ret = testRGBAImageReadFunctions(tif, width, length, width - 3, length,
                                          orientation, req_orientation,
                                          __LINE__)))
        GOTOFAILURE

    /* Less lines and less columns */
    if ((ret = testRGBAImageReadFunctions(tif, width, length, width - 5,
                                          length - 1, orientation,
                                          req_orientation, __LINE__)))
        GOTOFAILURE

    /* More columns. */
    if ((ret = testRGBAImageReadFunctions(tif, width, length, width + 2, length,
                                          orientation, req_orientation,
                                          __LINE__)))
        GOTOFAILURE

    /* More rows and columns. */
    if ((ret = testRGBAImageReadFunctions(tif, width, length, width + 2,
                                          length + 2, orientation,
                                          req_orientation, __LINE__)))
        GOTOFAILURE

    /*-- Test an invalid raster size --*/
    if ((ret = testRGBAImageReadFunctions(tif, width, length, width, 0,
                                          orientation, req_orientation,
                                          __LINE__)))
        GOTOFAILURE
    if ((ret = testRGBAImageReadFunctions(tif, width, length, 0, length,
                                          orientation, req_orientation,
                                          __LINE__)))
        GOTOFAILURE
    if ((ret = testRGBAImageReadFunctions(tif, width, length, 0, 0, orientation,
                                          req_orientation, __LINE__)))
        GOTOFAILURE

    /*=== Testing reading with OFFSETs in the image file; raster can then also
     * be smaller ===*/
    /*-- row_offset --*/
testcase:
    if ((ret = testRGBAImageReadWithOffsets(tif, width, length, 0, length - 1,
                                            width, length, orientation,
                                            req_orientation, __LINE__)))
        GOTOFAILURE
    if ((ret = testRGBAImageReadWithOffsets(tif, width, length, 0, length - 4,
                                            width, 4, orientation,
                                            req_orientation, __LINE__)))
        GOTOFAILURE
    if ((ret = testRGBAImageReadWithOffsets(tif, width, length, 0, length - 4,
                                            width, 2, orientation,
                                            req_orientation, __LINE__)))
        GOTOFAILURE

    /*-- col_offset --*/
    if ((ret = testRGBAImageReadWithOffsets(tif, width, length, width - 2, 0,
                                            width, length, orientation,
                                            req_orientation, __LINE__)))
        GOTOFAILURE
    if ((ret = testRGBAImageReadWithOffsets(tif, width, length, width - 2, 0, 2,
                                            length, orientation,
                                            req_orientation, __LINE__)))
        GOTOFAILURE
    if ((ret = testRGBAImageReadWithOffsets(tif, width, length, width - 3, 0, 2,
                                            length, orientation,
                                            req_orientation, __LINE__)))
        GOTOFAILURE

    /*-- row_offset and col_offset --*/
    if ((ret = testRGBAImageReadWithOffsets(
             tif, width, length, width - 4, length - 2, width, length,
             orientation, req_orientation, __LINE__)))
        GOTOFAILURE

    /* Here are some tests which are expected to fail. Suppress warning messages
     * for them. */
    blnQuiet = TRUE;
    errHandler = TIFFSetErrorHandler(NULL);

    /*-- row_offset --*/
    if (!(ret = testRGBAImageReadWithOffsets(tif, width, length, 0, length,
                                             width, length, orientation,
                                             req_orientation, __LINE__)))
        GOTOFAILURE
    if (!(ret = testRGBAImageReadWithOffsets(tif, width, length, 0, length + 5,
                                             width, length, orientation,
                                             req_orientation, __LINE__)))
        GOTOFAILURE
    if (!(ret = testRGBAImageReadWithOffsets(tif, width, length, 0, -10, width,
                                             length, orientation,
                                             req_orientation, __LINE__)))
        GOTOFAILURE

    /*-- col_offset --*/
    if (!(ret = testRGBAImageReadWithOffsets(tif, width, length, width, 0,
                                             width, length, orientation,
                                             req_orientation, __LINE__)))
        GOTOFAILURE
    if (!(ret = testRGBAImageReadWithOffsets(tif, width, length, width + 5, 0,
                                             width, length, orientation,
                                             req_orientation, __LINE__)))
        GOTOFAILURE
    if (!(ret = testRGBAImageReadWithOffsets(tif, width, length, -15, 0, width,
                                             length, orientation,
                                             req_orientation, __LINE__)))
        GOTOFAILURE

    /*-- row_offset and col_offset --*/
    if (!(ret = testRGBAImageReadWithOffsets(tif, width, length, -20, -30,
                                             width, length, orientation,
                                             req_orientation, __LINE__)))
        GOTOFAILURE

    /*-- Leaving function --*/
    if (errHandler != NULL)
        TIFFSetErrorHandler(errHandler);
    TIFFClose(tif);
#ifndef DEBUG_TESTING
    unlink(filename);
#endif
    return 0;

failure:
    if (errHandler != NULL)
        TIFFSetErrorHandler(errHandler);
    if (tif)
        TIFFClose(tif);
    return 1;
} /*-- test_ReadRGBAImage() --*/

 * an image with given number of lines as strips (scanlines) or tiles to
 * file.
 */
int write_data_to_current_directory(TIFF *tif, uint32_t width, uint32_t length,
                                    bool tiled, uint16_t orientation,
                                    bool write_data,
                                    unsigned char *plastlinedata,
                                    unsigned int lastlinebytesmax)
{
    if (!tif)
    {
        fprintf(stdXOut, "Invalid TIFF handle. Line %d\n", __LINE__);
        return 1;
    }
    const char *filename = TIFFFileName(tif);
    TIFFSetField_M(tif, TIFFTAG_IMAGEWIDTH, width, filename, __LINE__);
    TIFFSetField_M(tif, TIFFTAG_IMAGELENGTH, length, filename, __LINE__);
    TIFFSetField_M(tif, TIFFTAG_BITSPERSAMPLE, BPS, filename, __LINE__);
    TIFFSetField_M(tif, TIFFTAG_SAMPLESPERPIXEL, SPP, filename, __LINE__);

    if (tiled)
    {
        /* Tilesizes must be multiple of 16. */
        TIFFSetField_M(tif, TIFFTAG_TILEWIDTH, 16, filename, __LINE__);
        TIFFSetField_M(tif, TIFFTAG_TILELENGTH, 16, filename, __LINE__);
    }
    else
    {
        TIFFSetField_M(tif, TIFFTAG_ROWSPERSTRIP, rows_per_strip, filename,
                       __LINE__);
    }

    TIFFSetField_M(tif, TIFFTAG_PLANARCONFIG, planarconfig, filename, __LINE__);
    TIFFSetField_M(tif, TIFFTAG_PHOTOMETRIC, photometric, filename, __LINE__);
    /* Write Orientation tag. */
    TIFFSetField_M(tif, TIFFTAG_ORIENTATION, orientation, filename, __LINE__);

    /* Write dummy pixel data. */
    if (write_data)
    {
        if (write_image_data(tif, width, length, tiled, 99, plastlinedata,
                             lastlinebytesmax))
        {
            fprintf(stdXOut, "Can't write image data. Testline %d\n", __LINE__);
            return 1;
        }
    }
    return 0;

failure:
    return 1;
} /*-- write_data_to_current_directory() --*/

int write_image_data(TIFF *tif, uint32_t width, uint32_t length, bool tiled,
                     unsigned int pixval, unsigned char *plastlinedata,
                     unsigned int lastlinebytesmax)
{
    size_t bufLen;
    unsigned char *pbufLine = NULL;
    unsigned int bpsmod = (1 << BPS);
    uint32_t tlwidth;
    uint32_t tllength;
    tmsize_t tlsize;

    uint16_t planarconfig, samples_per_pixel;
    uint32_t rows_per_strip = 0;

    (void)pixval;

    const char *filename = TIFFFileName(tif);

    TIFFGetField_M(tif, TIFFTAG_PLANARCONFIG, &planarconfig, filename,
                   __LINE__);
    TIFFGetField_M(tif, TIFFTAG_SAMPLESPERPIXEL, &samples_per_pixel, filename,
                   __LINE__);

    if (tiled)
    {
        TIFFGetField_M(tif, TIFFTAG_TILEWIDTH, &tlwidth, filename, __LINE__);
        TIFFGetField_M(tif, TIFFTAG_TILELENGTH, &tllength, filename, __LINE__);
        /* For tiled mode get size of a tile in bytes */
        tlsize = TIFFTileSize(tif);
        bufLen = (size_t)tlsize;
    }
    else
    {
        TIFFGetField_M(tif, TIFFTAG_ROWSPERSTRIP, &rows_per_strip, filename,
                       __LINE__);
        /* For strip mode get size of a row in bytes */
        bufLen = (((size_t)width * SPP * BPS) + 7) / 8;
    }

    pbufLine = _TIFFmalloc(bufLen);
    if (pbufLine == NULL)
        return 1;

    /* Write dummy pixel data. */
    if (tiled)
    {
        /* With SEPARATE, the complete image of each color is written one after
         * the other. */
        uint32_t numtiles = TIFFNumberOfTiles(tif);
        uint32_t this_spp =
            (planarconfig < PLANARCONFIG_SEPARATE ? 0 : (SPP - 1));
        uint32_t last_width = width % tlwidth;
        uint32_t tiles_per_row = width / tlwidth + (last_width > 0 ? 1 : 0);
        uint32_t last_length = length % tllength;
        uint32_t tiles_per_col = length / tllength + (last_length > 0 ? 1 : 0);
        /* Correct values for following processing at special case. */
        if (last_width == 0)
            last_width = tlwidth;
        if (last_length == 0)
            last_length = tllength;

        uint32_t i, j, k, s, row, this_tlwidth, this_tllength;
        uint32_t coltile, rowtile;
        for (s = 0; s <= this_spp; s++)
        {
            for (coltile = 0; coltile < tiles_per_col; coltile++)
            {
                if (coltile < (tiles_per_col - 1))
                    this_tllength = tllength;
                else
                    this_tllength = last_length;
                for (rowtile = 0; rowtile < tiles_per_row; rowtile++)
                {
                    if (rowtile < (tiles_per_row - 1))
                        this_tlwidth = tlwidth;
                    else
                        this_tlwidth = last_width;
                    j = 0;
                    for (row = 0; row < this_tllength; row++)
                    {
                        /* Fill tile buffer. */
                        for (k = 0; (k < this_tlwidth); k++)
                        {
                            if (planarconfig < PLANARCONFIG_SEPARATE || s == 0)
                                pbufLine[j++] =
                                    (unsigned char)((row + coltile * tllength) %
                                                    bpsmod); /* row */
                            if (planarconfig < PLANARCONFIG_SEPARATE || s == 1)
                                pbufLine[j++] =
                                    (unsigned char)((k + rowtile * tlwidth) %
                                                    bpsmod); /* column */
                            if (planarconfig < PLANARCONFIG_SEPARATE || s == 2)
                                pbufLine[j++] = (unsigned char)((254) % bpsmod);
                        }
                        /* Fill rest of row in last tile with zeros. */
                        for (; (k < tlwidth); k++)
                        {
                            if (planarconfig < PLANARCONFIG_SEPARATE || s == 0)
                                pbufLine[j++] = 0; /* row */
                            if (planarconfig < PLANARCONFIG_SEPARATE || s == 1)
                                pbufLine[j++] = 0; /* column */
                            if (planarconfig < PLANARCONFIG_SEPARATE || s == 2)
                                pbufLine[j++] =
                                    (unsigned char)((0xcc) % bpsmod);
                        }
                    } /* row */
                    /* Calculate tile-number for TIFFWriteEncodedTile(). */
                    i = s * tiles_per_row * tiles_per_col +
                        coltile * tiles_per_row + rowtile;
                    if (TIFFWriteEncodedTile(tif, i, pbufLine, 0) == -1)
                    {
                        fprintf(stdXOut,
                                "Can't write image data tile. Testline %d\n",
                                __LINE__);
                        return 1;
                    }
                    if ((plastlinedata != NULL) && (i == (numtiles - 1)))
                    {
                        memcpy(plastlinedata, pbufLine,
                               TIFFmin(bufLen, (size_t)lastlinebytesmax));
                    }
                } /* rowtile */
            }     /* coltile */
        }         /* s sample in pixel */
    }
    else
    {
        /*== STRIP ==*/
        uint32_t i;
        /* Fill image buffer. */
        uint32_t k, j;
        uint16_t s;
        if (planarconfig == PLANARCONFIG_CONTIG)
        {
            for (i = 0; i < length; i++)
            {
                for (k = 0, j = 0; k < width && j <= (bufLen - SPP);
                     k++, j += SPP)
                {
                    pbufLine[j] = (unsigned char)((i) % bpsmod); /* row */
                    pbufLine[j + 1] =
                        (unsigned char)((k) % bpsmod); /* column */
                    pbufLine[j + 2] = (unsigned char)((254) % bpsmod);
                }
                TIFFWriteScanline_M(tif, pbufLine, i, 0, filename, __LINE__);
            }
        }
        else
        {
            /* SEPARATE - RRRR GGGGG BBBBB, each all lines per strip */
            for (i = 0; i < length; i += rows_per_strip)
            {
                for (s = 0; s < samples_per_pixel; s++)
                {
                    for (j = 0; j < rows_per_strip; j++)
                    {
                        for (k = 0; k < width; k++)
                        {
                            if (s == 0)
                                pbufLine[k] =
                                    (unsigned char)((i + j) % bpsmod); /* row */
                            else if (s == 1)
                                pbufLine[k] =
                                    (unsigned char)((k) % bpsmod); /* column */
                            else if (s == 2)
                                pbufLine[k] = (unsigned char)((254) % bpsmod);
                        }
                        TIFFWriteScanline_M(tif, pbufLine, (i + j), s, filename,
                                            __LINE__);
                    }
                }
            }
        }
        if ((plastlinedata != NULL) && (i == (length - 1)))
        {
            memcpy(plastlinedata, pbufLine,
                   TIFFmin(bufLen, (size_t)lastlinebytesmax));
        }
    } /* -- strip --*/
    _TIFFfree(pbufLine);
    return 0;
failure:
    return 1;
} /*-- write_image_data() --*/

int main()
{
    tmsize_t ret;
    TIFF *tif = TIFFOpen("test_append_to_strip.tif", "w");
    if (tif == NULL)
    {
        fprintf(stderr, "Cannot create test_append_to_strip.tif");
        return 1;
    }
    ret = TIFFSetField(tif, TIFFTAG_COMPRESSION, COMPRESSION_NONE);
    assert(ret);
    ret = TIFFSetField(tif, TIFFTAG_IMAGEWIDTH, 1);
    assert(ret);
    ret = TIFFSetField(tif, TIFFTAG_IMAGELENGTH, 9);
    assert(ret);
    ret = TIFFSetField(tif, TIFFTAG_ROWSPERSTRIP, 5);
    assert(ret);
    ret = TIFFSetField(tif, TIFFTAG_BITSPERSAMPLE, 8);
    assert(ret);
    ret = TIFFSetField(tif, TIFFTAG_SAMPLESPERPIXEL, 1);
    assert(ret);
    int row;
    for (row = 0; row < 9; ++row)
    {
        char c = (char)row;
        int strip = (row < 5) ? 0 : 1;
        ret = TIFFWriteRawStrip(tif, strip, &c, 1);
        assert(ret == 1);
    }
    (void)ret;
    TIFFClose(tif);
    tif = TIFFOpen("test_append_to_strip.tif", "r");
    if (tif == NULL)
    {
        fprintf(stderr, "Cannot create test_append_to_strip.tif");
        return 1;
    }
    toff_t *panByteCounts = NULL;
    TIFFGetField(tif, TIFFTAG_STRIPBYTECOUNTS, &panByteCounts);
    assert(panByteCounts);
    int exitCode = 0;
    if (panByteCounts[0] != 5)
    {
        exitCode = 1;
        fprintf(stderr, "panByteCounts[0] = %d. Expected 5.\n",
                (int)panByteCounts[0]);
    }
    if (panByteCounts[1] != 4)
    {
        exitCode = 1;
        fprintf(stderr, "panByteCounts[1] = %d. Expected 4.\n",
                (int)panByteCounts[1]);
    }
    for (row = 0; row < 9; ++row)
    {
        char c;
        TIFFReadScanline(tif, &c, row, 0);
        if (c != row)
        {
            fprintf(
                stderr,
                "TIFFReadScanline() for scanline %d returned %d. %d expected\n",
                row, c, row);
            exitCode = 1;
        }
    }
    TIFFClose(tif);
    unlink("test_append_to_strip.tif");
    return exitCode;
}

int test_curdircount_setting(unsigned int openMode)
{
#define N_DIRECTORIES_2 2
    char filename[128] = {0};
    tdir_t expected_curdir = (tdir_t)(-1);

    if (openMode >= (sizeof(openModeStrings) / sizeof(openModeStrings[0])))
    {
        fprintf(stderr, "Index %d for openMode parameter out of range.\n",
                openMode);
        return 1;
    }

    /* Get individual filenames and delete existent ones. */
    sprintf(filename, "test_dircount_%s.tif", openModeStrings[openMode]);
    unlink(filename);

    /* Create a file and write N_DIRECTORIES_2 directories to it. */
    TIFF *tif = TIFFOpen(filename, openModeStrings[openMode]);
    if (!tif)
    {
        fprintf(stderr, "Can't create %s\n", filename);
        return 1;
    }

    /*-- Standard case for writing sequential IFDs. --*/
    for (int i = 0; i < N_DIRECTORIES_2; i++)
    {
        if (write_data_to_current_directory(tif, i, false))
        {
            fprintf(stderr,
                    "Can't write data to current directory in %s at %d\n",
                    filename, __LINE__);
            goto failure;
        }
        TIFFWriteDirectory_M(tif, filename, __LINE__);
        expected_curdir++;
        CHECKCURDIRNUM_M(tif, expected_curdir, __LINE__);
    }
    TIFFClose(tif);

    /* Simulate case for trap in TIFFLinkDirectory() where tif_lastdiroff is set
     * but tif_curdircount is not.
     * https://gitlab.com/libtiff/libtiff/-/merge_requests/634#note_1990250515
     */
    tif = TIFFOpen(filename, "r+");
    CHECKCURDIRNUM_M(tif, 0, __LINE__);
    TIFFRewriteDirectory(tif);
    CHECKCURDIRNUM_M(tif, 0, __LINE__);
    TIFFCreateDirectory(tif);
    TIFFWriteDirectory(tif);
    CHECKCURDIRNUM_M(tif, 2, __LINE__);
    tdir_t numdir = TIFFNumberOfDirectories(tif);
    TIFFClose(tif);

    /* Testcase iswrittentofile=0 for SetSubDirectory(0). */
    tif = TIFFOpen(filename, "r+");
    TIFFSetSubDirectory(tif, 0);
    /* After TIFFSetSubDirectory(tif, 0) the read IFD is re-written as a
     * new IFD and tif_curdir and tif_curdircount shall be updated.
     * The latter was not the case before resetting iswrittentofile=0 at
     * SetSubDirectory(0). Even an IFD-Loop was then wrongly assumed at the next
     * TIFFNumberOfDirectories() call. */
    TIFFWriteDirectory(tif);
    CHECKCURDIRNUM_M(tif, numdir, __LINE__);

    /* Unlink all directories. */
    numdir = TIFFNumberOfDirectories(tif);
    for (int i = numdir; 0 < i; i--)
    {
        TIFFUnlinkDirectory(tif, i);
        CHECKCURDIRNUM_M(tif, (tdir_t)(-1), __LINE__);
    }

    TIFFClose(tif);
    unlink(filename);
    return 0;

failure:
    TIFFClose(tif);
    return 1;
} /*-- test_curdircount_setting() --*/

/* Test correct incrementing of tif_curdir TIFFCurrentDirectory()
 *
 * Up to 4.6.0 there are cases where tif_curdir is set inconsistently or
 * incorrectly, depending on the previous history. This function shows some of
 * these cases and tests them after the improvements.
 */
int test_current_dirnum_incrementing(int testcase, unsigned int openMode)
{
#define N_DIRECTORIES_2 2
    char filename[128] = {0};
    tdir_t lastdir;
    tdir_t expected_curdir = (tdir_t)(-1);

    if (openMode >= (sizeof(openModeStrings) / sizeof(openModeStrings[0])))
    {
        fprintf(stderr, "Index %d for openMode parameter out of range.\n",
                openMode);
        return 1;
    }

    /* Get individual filenames and delete existent ones. */
    sprintf(filename, "test_current_dirnum_incrementing_%s.tif",
            openModeStrings[openMode]);
    unlink(filename);

    /* Create a file and write N_DIRECTORIES_2 directories to it. */
    TIFF *tif = TIFFOpen(filename, openModeStrings[openMode]);
    if (!tif)
    {
        fprintf(stderr, "Can't create %s\n", filename);
        return 1;
    }

    /*-- Standard case for writing sequential IFDs. --*/
    for (int i = 0; i < N_DIRECTORIES_2; i++)
    {
        if (write_data_to_current_directory(tif, i, false))
        {
            fprintf(stderr,
                    "Can't write data to current directory in %s at %d\n",
                    filename, __LINE__);
            goto failure;
        }
        TIFFWriteDirectory_M(tif, filename, __LINE__);
        expected_curdir++;
        CHECKCURDIRNUM_M(tif, expected_curdir, __LINE__);
    }

    /*-- Standard case for sequential reading up to the end. --*/
    expected_curdir = 0;
    TIFFSetDirectory_M(tif, expected_curdir, filename, __LINE__);
    while (TIFFReadDirectory(tif))
    {
        expected_curdir++;
        CHECKCURDIRNUM_M(tif, expected_curdir, __LINE__);
    }
    /* Last read for next_offset 0 shall not increment tif_curdir. */
    CHECKCURDIRNUM_M(tif, expected_curdir, __LINE__);

    /* Now, go back to IFD 0 and overwrite it in the first loop and rewrite it
     * in the second loop (due to "i" having two digits then).
     * tif_curdir should stay to that IFD-number.  */
    expected_curdir = 0;
    for (unsigned int i = 9; i < 11; i++)
    {
        TIFFSetDirectory_M(tif, expected_curdir, filename, __LINE__);
        if (write_data_to_current_directory(tif, i, false))
        {
            fprintf(stderr,
                    "Can't write data to current directory in %s at %d\n",
                    filename, __LINE__);
            goto failure;
        }
        TIFFWriteDirectory_M(tif, filename, __LINE__);
        /* Fails in 4.6.0 */
        CHECKCURDIRNUM_M(tif, expected_curdir, __LINE__);
    }

    /* Now, go back to IFD 1 and overwrite it in the first loop and rewrite it
     * in the second loop (due to "i" having two digits then).
     * tif_curdir should stay to that IFD-number.  */
    expected_curdir = 1;
    for (unsigned int i = 8; i < 13; i += 4)
    {
        TIFFSetDirectory_M(tif, expected_curdir, filename, __LINE__);
        if (write_data_to_current_directory(tif, i, false))
        {
            fprintf(stderr,
                    "Can't write data to current directory in %s at %d\n",
                    filename, __LINE__);
            goto failure;
        }
        TIFFWriteDirectory_M(tif, filename, __LINE__);
        /* Fails in 4.6.0 */
        CHECKCURDIRNUM_M(tif, expected_curdir, __LINE__);
    }

    /* Set IFD 0 and append new IFDs.  */
    if (testcase == 0)
    {
        expected_curdir = TIFFNumberOfDirectories(tif);
    }
    else if (testcase == 1)
    {
        TIFFClose(tif);
        tif = TIFFOpen(filename, openModeStrings[openMode]);
        expected_curdir = 0;
    }
    else if (testcase == 2)
    {
        expected_curdir = TIFFNumberOfDirectories(tif);
        TIFFClose(tif);
        /* Replace 'w' for write by 'a' for append. */
        char strAux[8] = {0};
        strncpy(strAux, openModeStrings[openMode], sizeof(strAux) - 1);
        strAux[0] = 'a';
        tif = TIFFOpen(filename, strAux);
    }
    for (unsigned int setdir = 0; setdir < 3; setdir += 2)
    {
        for (unsigned int i = 0; i < 2; i++)
        {
            if (testcase == 0)
            {
                TIFFSetDirectory_M(tif, setdir, filename, __LINE__);
                TIFFCreateDirectory(tif);
            }
            if (write_data_to_current_directory(tif, expected_curdir, false))
            {
                fprintf(
                    stderr,
                    "Can't write data to current directory in %s at line %d\n",
                    filename, __LINE__);
                goto failure;
            }
            TIFFWriteDirectory_M(tif, filename, __LINE__);
            /* Fails in 4.6.0, except for testcase TIFFOpen("w") */
            CHECKCURDIRNUM_M(tif, expected_curdir, __LINE__);
            expected_curdir++;
        }
    }

    /*-- Several CheckpointDirectory() testing --*/
    /* Set state such as if the last directory would have been just written.
     * - read last IFD from file and then
     * - create and activate a newly initialized IFD, not written yet. */
    if (testcase == 0)
    {
        lastdir = TIFFNumberOfDirectories(tif) - 1;
        expected_curdir = lastdir + 1;
        TIFFSetDirectory(tif, lastdir);
        TIFFCreateDirectory(tif);
    }
    else if (testcase == 1)
    {
        TIFFClose(tif);
        tif = TIFFOpen(filename, openModeStrings[openMode]);
        expected_curdir = 0;
    }
    /* Fill the new IFD and checkpoint several times before writing. */
    if (write_data_to_current_directory(tif, expected_curdir, false))
    {
        fprintf(stderr, "Can't write data to current directory in %s at %d\n",
                filename, __LINE__);
        goto failure;
    }
    for (unsigned int i = 0; i < 2; i++)
    {
        TIFFCheckpointDirectory_M(tif, expected_curdir, filename, __LINE__);
        /* Fails in 4.6.0 only in second loop */
        CHECKCURDIRNUM_M(tif, expected_curdir, __LINE__);
        if (i == 1)
        {
            /* In last loop force IFD to be rewritten. */
            TIFFSetField(tif, TIFFTAG_PAGENAME, "6.th IFD rewritten");
        }
        TIFFCheckpointDirectory_M(tif, expected_curdir, filename, __LINE__);
        /* Fails in 4.6.0 */
        CHECKCURDIRNUM_M(tif, expected_curdir, __LINE__);
        TIFFWriteDirectory_M(tif, filename, __LINE__);
        /* Fails in 4.6.0 */
        CHECKCURDIRNUM_M(tif, expected_curdir, __LINE__);
        /* Prepare checkpointing of same IFD in next loop after reading it from
         * file. */
        TIFFSetDirectory_M(tif, expected_curdir, filename, __LINE__);
    }

    /*-- RewriteDirectory() testing --*/
    /* RewriteDirectory() forces to write the IFD to another location
     * and set-up a new, empty IFD. */
    /* Set state such as if the last directory would have been just written.
     * - read last IFD from file and then
     * - create and activate a newly initialized IFD, not written yet. */
    if (testcase == 0 || testcase == 2)
    {
        lastdir = TIFFNumberOfDirectories(tif) - 1;
    }
    else
    {
        lastdir = expected_curdir;
    }
    TIFFSetDirectory(tif, lastdir);
    TIFFCreateDirectory(tif);
    expected_curdir = lastdir + 1;
    /* Write a new IFD using TIFFRewriteDirectory, read it and rewrite it again.
     * First with curdir set to the last IFD and then set to the first one. */
    for (unsigned int i = 0; i < 2; i++)
    {
        if (write_data_to_current_directory(tif, expected_curdir, false))
        {
            fprintf(stderr,
                    "Can't write data to current directory in %s at %d\n",
                    filename, __LINE__);
            goto failure;
        }
        if (!TIFFRewriteDirectory(tif))
        {
            fprintf(stderr, "Can't rewrite directory to %s at line %d\n",
                    filename, __LINE__);
            goto failure;
        }
        /* Fails in 4.6.0 only in second loop */
        CHECKCURDIRNUM_M(tif, expected_curdir, __LINE__);
        /* Read IFD and write it to another location. */
        TIFFSetDirectory_M(tif, expected_curdir, filename, __LINE__);
        if (!TIFFRewriteDirectory(tif))
        {
            fprintf(stderr, "Can't rewrite directory to %s at line %d\n",
                    filename, __LINE__);
            goto failure;
        }
        /* Fails in 4.6.0 */
        CHECKCURDIRNUM_M(tif, expected_curdir, __LINE__);
        expected_curdir++;
        /* Second loop starts with IFD 0 read from file. */
        TIFFSetDirectory_M(tif, 0, filename, __LINE__);
        TIFFCreateDirectory(tif);
    }

    /*-- CustomDirectory testing --*/
    /* Set state such as if the last directory would have been just written.
     * - Read last IFD from file and then
     * - create and activate a newly initialized IFD, not written yet and
     *   attach an EXIF IFD to it with forcing a re-write of the IFD by
     *   adding the EXIF-IFD tag.
     * - Do that two times:
     *     - first  set last  IFD and append a new one,
     *     - second set first IFD and append a new one. */
    if (testcase == 0 || testcase == 1)
    {
        lastdir = TIFFNumberOfDirectories(tif) - 1;
    }
    else
    {
        lastdir = expected_curdir - 1;
    }
    TIFFSetDirectory(tif, lastdir);
    TIFFCreateDirectory(tif);
    expected_curdir = lastdir + 1;
    uint64_t offsetEXIFBase[2];
    for (unsigned int i = 0; i < 2; i++)
    {
        if (write_data_to_current_directory(tif, expected_curdir, false))
        {
            fprintf(stderr,
                    "Can't write data to current directory in %s at %d\n",
                    filename, __LINE__);
            goto failure;
        }
        TIFFWriteDirectory_M(tif, filename, __LINE__);
        /* Fails in 4.6.0 only in second loop */
        CHECKCURDIRNUM_M(tif, expected_curdir, __LINE__);
        if (write_EXIF_data_to_current_directory(tif, i, &offsetEXIFBase[i]))
        {
            fprintf(stderr,
                    "Can't write EXIF data to current directory in %s. "
                    "Testline %d\n",
                    filename, __LINE__);
            goto failure;
        }
        /* CustomDirectory invalidates directory number. */
        CHECKCURDIRNUM_M(tif, (tdir_t)(-1), __LINE__);
        /* Go back to current main-IFD and update EXIF-IFD offset. */
        TIFFSetDirectory_M(tif, expected_curdir, filename, __LINE__);
        if (!TIFFSetField(tif, TIFFTAG_EXIFIFD, offsetEXIFBase[i]))
        {
            fprintf(stderr, "Can't set TIFFTAG_EXIFIFD tag. Testline %d\n",
                    __LINE__);
            goto failure;
        }
        TIFFWriteDirectory_M(tif, filename, __LINE__);
        /* Fails in 4.6.0 */
        CHECKCURDIRNUM_M(tif, expected_curdir, __LINE__);
        expected_curdir++;

        /* Second loop starts with IFD 0 read from file. */
        TIFFSetDirectory_M(tif, 0, filename, __LINE__);
        TIFFCreateDirectory(tif);
    }

    /*-- Read EXIF Custom-Directory --*/
    for (unsigned int i = 0; i < 2; i++)
    {
        if (!TIFFReadEXIFDirectory(tif, offsetEXIFBase[i]))
        {
            fprintf(stderr,
                    "TIFFReadEXIFDirectory(%" PRIu64 ") failed for %s "
                    "at %d\n",
                    offsetEXIFBase[i], filename, __LINE__);
            goto failure;
        }
        CHECKCURDIRNUM_M(tif, 0, __LINE__);
    }

    /*-- Test for fail of ReadDirectory() and fail of SetDirectory() --*/
    /*-- Writing IFD0, IFD1 as valid IFD and IFD2 as corrupted. --*/
    uint64_t offsetBase[4];
    TIFFClose(tif);
    tif = TIFFOpen(filename, openModeStrings[openMode]);
    expected_curdir = 0;
    fprintf(stderr, "----- Expect some error messages about 'scanline size is "
                    "zero' -----\n");
    for (int i = 0; i < 3; i++)
    {
        if (write_data_to_current_directory(tif, i, (i == 2 ? true : false)))
        {
            fprintf(stderr,
                    "Can't write data to current directory in %s at %d\n",
                    filename, __LINE__);
            goto failure;
        }
        TIFFWriteDirectory_M(tif, filename, __LINE__);
        /* Expect offsetBase{0,0,0} here, because TIFFWriteDirectory() returns
         * a new and empty IFD after writing. */
        offsetBase[i] = TIFFCurrentDirOffset(tif);
        CHECKCURDIRNUM_M(tif, expected_curdir, __LINE__);
        expected_curdir++;
    }
    TIFFSetDirectory_M(tif, 0, filename, __LINE__);
    offsetBase[0] = TIFFCurrentDirOffset(tif);
    CHECKCURDIRNUM_M(tif, 0, __LINE__);
    TIFFSetDirectory_M(tif, 1, filename, __LINE__);
    offsetBase[1] = TIFFCurrentDirOffset(tif);
    CHECKCURDIRNUM_M(tif, 1, __LINE__);
    /* TIFFReadDirectory() shall fail but curdir shall be incremented,
     * because parts of corrupt IFD2 are read in. */
    if (TIFFReadDirectory(tif))
    {
        fprintf(stderr,
                "TIFFReadDirectory() for IFD2 was expected to fail but "
                "succeeded for %s "
                "at %d\n",
                filename, __LINE__);
        goto failure;
    }
    offsetBase[2] = TIFFCurrentDirOffset(tif);
    CHECKCURDIRNUM_M(tif, 2, __LINE__);
    TIFFSetDirectory_M(tif, 0, filename, __LINE__);
    CHECKCURDIRNUM_M(tif, 0, __LINE__);
    /* TIFFSetDirectory() shall fail on IFD2 but curdir shall be incremented,
     * because parts of corrupt IFD2 are read in. */
    if (TIFFSetDirectory(tif, 2))
    {
        fprintf(stderr,
                "TIFFSetDirectory(2) was expected to fail but succeeded for %s "
                "at %d\n",
                filename, __LINE__);
        goto failure;
    }
    CHECKCURDIRNUM_M(tif, 2, __LINE__);
    /* Also TIFFSetSubDirectory() shall fail for IFD2 and curdir shall be
     * set correctly to 2. Therefore, set it back to IFD0 first. */
    TIFFSetDirectory_M(tif, 0, filename, __LINE__);
    CHECKCURDIRNUM_M(tif, 0, __LINE__);
    if (TIFFSetSubDirectory(tif, offsetBase[2]))
    {
        fprintf(stderr,
                "TIFFSetSubDirectory(%" PRIu64
                ") was expected to fail but succeeded for %s "
                "at %d\n",
                offsetBase[2], filename, __LINE__);
        goto failure;
    }
    /* Fails in 4.6.0 */
    CHECKCURDIRNUM_M(tif, 2, __LINE__);

    /* However, TIFFSetSubDirectory() on a non valid IFD "offset" shall fail,
     * and tif_curdir shall be set to "unknown" (-1). */
    fprintf(stderr, "----- Expect error messages about 'Sanity check AND "
                    "Failed to read directory' -----\n");
    if (TIFFSetSubDirectory(tif, 10))
    {
        fprintf(stderr,
                "TIFFSetSubDirectory(%" PRIu64
                ") was expected to fail but succeeded for %s "
                "at %d\n",
                offsetBase[1], filename, __LINE__);
        goto failure;
    }
    /* Fails in 4.6.0 */
    CHECKCURDIRNUM_M(tif, (tdir_t)(-1), __LINE__);
    /* Set IFD0 for next test */
    TIFFSetSubDirectory(tif, offsetBase[0]);
    CHECKCURDIRNUM_M(tif, 0, __LINE__);

    /* TIFFSetSubDirectory(0) shall invalidate the active IFD read from file by
     * setting tif_nextdiroff and tif_diroff=0 */
    TIFFSetSubDirectory(tif, 0);
    CHECKCURDIRNUM_M(tif, (tdir_t)(-1), __LINE__);

    /*-- Patch offset of IFD2 to not existing IFD3 without entries.
     *   Thus TIFFFetchDirectory() will fail. --*/
#define TIFFReadFile_M(tif, buf, size)                                         \
    ((*TIFFGetReadProc(tif))(TIFFClientdata(tif), (buf), (size)));
#define TIFFWriteFile_M(tif, buf, size)                                        \
    ((*TIFFGetWriteProc(tif))(TIFFClientdata(tif), (buf), (size)));
#define TIFFSeekFile_M(tif, off, whence)                                       \
    ((*TIFFGetSeekProc(tif))(TIFFClientdata(tif), (off), (whence)));

    /* ---------------------------------------------------------------------
     * Test IFD index incrementing in case the functions return with certain
     * errors. To provoke that errors, the file is patched by writing bytes
     * directly into the file. Therefore, code below does only handle
     * Classic-TIFF and little-endian files.
     * The code works also on big endian machines, which have to swap some
     * directly read/written values.
     * --------------------------------------------------------------------- */
    if (!(TIFFIsBigEndian(tif) || TIFFIsBigTIFF(tif)))
    {
        /* Patch nextIFDOffset of IFD2, which is 0, with offset to itself.
         * This generates an IFD3 without any elements at the end of file.
         * Reading IFD3 should provoke reading error. */
        uint64_t ss = TIFFSeekFile_M(tif, offsetBase[2], 0);
        uint16_t cnt = 0;
        uint64_t rr = TIFFReadFile_M(tif, &cnt, 2);
        if (TIFFIsByteSwapped(tif))
            TIFFSwabShort(&cnt);
        ss = TIFFSeekFile_M(tif, offsetBase[2] + cnt * 12 + 2, 0);
        uint32_t wt = (uint32_t)ss;
        if (TIFFIsByteSwapped(tif))
            TIFFSwabLong(&wt);
        rr = TIFFWriteFile_M(tif, &wt, 4);
        (void)rr;

        /* Now there are offsets to four IFDs in the file, where the last one is
         * not existing and has a non-valid dircount and entries behind EOF.
         * (dircount is 458 (as offset) */
        fprintf(stderr, "----- Expect error messages about 'Error fetching "
                        "directory link.' -----\n");
        /* TIFFNumberOfDirectories() returns 3 and omits the invalid fourth IFD.
         */
        lastdir = TIFFNumberOfDirectories(tif);
        TIFFSetDirectory(tif, 0);
        CHECKCURDIRNUM_M(tif, 0, __LINE__);

        /* TIFFSetDirectory(3) fails with error messages:
         *   TIFFFetchDirectory: test_current_dirnum_incrementing_wl.tif:
         *   Can not read TIFF directory.
         *   TIFFReadDirectory: Failed to read directory at offset 458. */
        fprintf(stderr, "----- Expect error messages about 'Cannot read TIFF "
                        "directory.' -----\n");
        if (TIFFSetDirectory(tif, 3))
        {
            fprintf(stderr,
                    "TIFFSetDirectory(3) for IFD3 was expected to fail but "
                    "succeeded for %s "
                    "at %d\n",
                    filename, __LINE__);
            goto failure;
        }

        /* Fails in 4.6.0 */
        /* Reading invalid IFD 3 leads to an error and was not read in.
         * Therefore, curdir shall be 65535 (non-existing directory) */
        CHECKCURDIRNUM_M(tif, (tdir_t)(-1), __LINE__);
        offsetBase[3] = TIFFCurrentDirOffset(tif);

        /* Point IFD3 to a location within the file, where it has now for
         * little-endian TIFF files a non-valid dircount=0, which leads also to
         * an error and the IFD is not read in. */
        ss = TIFFSeekFile_M(tif, offsetBase[2] + cnt * 12 + 2, 0);
        wt = (uint32_t)(offsetBase[1] + 8);
        // wt = (uint32_t)(ss + 400);
        if (TIFFIsByteSwapped(tif))
            TIFFSwabLong(&wt);
        rr = TIFFWriteFile_M(tif, &wt, 4);

        fprintf(stderr, "----- Expect error messages about 'Error fetching "
                        "directory link.' -----\n");
        /* TIFFNumberOfDirectories() returns now 4, because for an IFD linked
         * list dircount=0 is not treated as an error and there is an offset
         * (=1) to a next IFD. Then, at the fifth IFD a link error occurs. */
        lastdir = TIFFNumberOfDirectories(tif);
        TIFFSetDirectory(tif, 0);
        CHECKCURDIRNUM_M(tif, 0, __LINE__);

        /* TIFFSetDirectory(3) fails with error messages:
         *    test_current_dirnum_incrementing_wl.tif: Failed to allocate
         *    memory for to read TIFF directory (0 elements of 12 bytes each).
         *    TIFFReadDirectory: Failed to read directory at offset 178.
         * The IFD 3 is not read in and curdir is set to 65535 (non-existing
         * directory).
         */
        fprintf(stderr,
                "----- Expect error messages about 'Failed to allocate "
                "memory for to read TIFF directory.' AND 'Failed to read "
                "directory ..' -----\n");
        if (TIFFSetDirectory(tif, 3))
        {
            fprintf(stderr,
                    "TIFFSetDirectory(3) for IFD3 was expected to fail but "
                    "succeeded for %s "
                    "at %d\n",
                    filename, __LINE__);
            goto failure;
        }

        /* Fails in 4.6.0 */
        CHECKCURDIRNUM_M(tif, (tdir_t)(-1), __LINE__);
    }

    TIFFClose(tif);
    unlink(filename);
    return 0;

failure:
    if (tif)
    {
        TIFFClose(tif);
    }
    return 1;
} /*-- test_current_dirnum_incrementing() --*/

int test_lastdir_offset(unsigned int openMode)
{
    char filename_optimized[128] = {0};
    char filename_non_optimized[128] = {0};
    int i, count_optimized, count_non_optimized;
    uint64_t offsets_base[N_DIRECTORIES];
    uint64_t offsets_comparison[N_DIRECTORIES];
    TIFF *tif;

    if (openMode >= (sizeof(openModeStrings) / sizeof(openModeStrings[0])))
    {
        fprintf(stderr, "Index %d for openMode parameter out of range.\n",
                openMode);
        return 1;
    }

    /* Get individual filenames and delete existent ones. */
    sprintf(filename_optimized, "test_directory_optimized_%s.tif",
            openModeStrings[openMode]);
    sprintf(filename_non_optimized, "test_directory_non_optimized_%s.tif",
            openModeStrings[openMode]);
    unlink(filename_optimized);
    unlink(filename_non_optimized);

    /* First file: open it and add multiple directories. This uses the
     * lastdir optimization. */
    tif = TIFFOpen(filename_optimized, openModeStrings[openMode]);
    if (!tif)
    {
        fprintf(stderr, "Can't create %s\n", filename_optimized);
        return 1;
    }
    for (i = 0; i < N_DIRECTORIES; i++)
    {
        if (write_data_to_current_directory(tif, i, false))
        {
            fprintf(stderr, "Can't write data to current directory in %s\n",
                    filename_optimized);
            goto failure;
        }
        if (!TIFFWriteDirectory(tif))
        {
            fprintf(stderr, "Can't write directory to %s\n",
                    filename_optimized);
            goto failure;
        }
    }
    TIFFClose(tif);
    tif = NULL;

    /* Second file: close it after adding each directory. This avoids the
     * lastdir optimization. */
    for (i = 0; i < N_DIRECTORIES; i++)
    {
        if (write_directory_to_closed_file(filename_non_optimized, openMode, i))
        {
            fprintf(stderr, "Can't write directory to %s\n",
                    filename_non_optimized);
            goto failure;
        }
    }

    /* Check that both files have the expected number of directories */
    if (count_directories(filename_optimized, &count_optimized))
    {
        fprintf(stderr, "Error counting directories in file %s.\n",
                filename_optimized);
        goto failure;
    }
    if (count_optimized != N_DIRECTORIES)
    {
        fprintf(stderr,
                "Unexpected number of directories in %s. Expected %i, "
                "found %i.\n",
                filename_optimized, N_DIRECTORIES, count_optimized);
        goto failure;
    }
    if (count_directories(filename_non_optimized, &count_non_optimized))
    {
        fprintf(stderr, "Error counting directories in file %s.\n",
                filename_non_optimized);
        goto failure;
    }
    if (count_non_optimized != N_DIRECTORIES)
    {
        fprintf(stderr,
                "Unexpected number of directories in %s. Expected %i, "
                "found %i.\n",
                filename_non_optimized, N_DIRECTORIES, count_non_optimized);
        goto failure;
    }

    /* Check that both files have the same directory offsets */
    /* In parallel of comparing offsets between optimized base file and
     * non-optimized file, test also three methods of walking through the
     * IFD chain within get_dir_offsets(). This tests the optimization of
     * faster SetDirectory(). */
    if (get_dir_offsets(filename_optimized, offsets_base,
                        DirWalkMode_ReadDirectory))
    {
        fprintf(stderr, "Error reading directory offsets from %s.\n",
                filename_optimized);
        goto failure;
    }
    for (int file_i = 0; file_i < 2; ++file_i)
    {
        const char *filename =
            (file_i == 0) ? filename_optimized : filename_non_optimized;

        for (enum DirWalkMode mode = DirWalkMode_ReadDirectory;
             mode <= DirWalkMode_SetDirectory_Reverse; ++mode)
        {
            if (get_dir_offsets(filename, offsets_comparison, mode))
            {
                fprintf(stderr,
                        "Error reading directory offsets from %s in mode %d.\n",
                        filename, mode);
                goto failure;
            }
            for (i = 0; i < N_DIRECTORIES; i++)
            {
                if (offsets_base[i] != offsets_comparison[i])
                {
                    fprintf(stderr,
                            "Unexpected directory offset for directory %i, "
                            "expected "
                            "offset %" PRIu64 " but got %" PRIu64 ".\n",
                            i, offsets_base[i], offsets_comparison[i]);
                    goto failure;
                }
            }
        }
    }
    /* hint: files are always closed by count_directories() and
     * get_dir_offsets() */
    unlink(filename_optimized);
    unlink(filename_non_optimized);
    return 0;

failure:
    if (tif)
    {
        TIFFClose(tif);
    }
    return 1;
} /*-- test_lastdir_offset() --*/

 * This could happen because TIFFRewriteDirectory() relies on the traversal of
 * the directory linked list in order to move the rewritten directory to the
 * end of the file. This means the `lastdir_offset` optimization should be
 * skipped, otherwise the linked list will be broken at the point where it
 * connected to the rewritten directory, resulting in the loss of the
 * directories that come after it.
 * Rewriting the first directory requires an additional test, because it is
 * treated differently from the directories that have a predecessor in the list.
 */
int test_rewrite_lastdir_offset(unsigned int openMode)
{
    char filename[128] = {0};
    int i, count;
    TIFF *tif;

    if (openMode >= (sizeof(openModeStrings) / sizeof(openModeStrings[0])))
    {
        fprintf(stderr, "Index %d for openMode parameter out of range.\n",
                openMode);
        return 1;
    }

    /* Get individual filenames and delete existent ones. */
    sprintf(filename, "test_directory_rewrite_%s.tif",
            openModeStrings[openMode]);
    unlink(filename);

    /* Create a file and write N_DIRECTORIES (10) directories to it. */
    tif = TIFFOpen(filename, openModeStrings[openMode]);
    if (!tif)
    {
        fprintf(stderr, "Can't create %s\n", filename);
        return 1;
    }
    for (i = 0; i < N_DIRECTORIES; i++)
    {
        if (write_data_to_current_directory(tif, i, false))
        {
            fprintf(stderr, "Can't write data to current directory in %s\n",
                    filename);
            goto failure;
        }
        if (!TIFFWriteDirectory(tif))
        {
            fprintf(stderr, "Can't write directory to %s\n", filename);
            goto failure;
        }
    }

    /* Without closing the file, go to the fifth directory
     * and check, if dirn is requested directory. */
    TIFFSetDirectory(tif, 4);
    if (!is_requested_directory(tif, 4, filename))
    {
        TIFFClose(tif);
        return 4;
    }

    /* Rewrite the fifth directory by calling TIFFRewriteDirectory
     * and check, if the offset of IFD loaded by TIFFSetDirectory() is
     * different. Then, the IFD loop directory list is correctly maintained for
     * speed up of TIFFSetDirectory() with directly getting the offset that
     * list.
     */
    uint64_t off1 = TIFFCurrentDirOffset(tif);
    if (write_data_to_current_directory(tif, 4, false))
    {
        fprintf(stderr, "Can't write data to fifth directory in %s\n",
                filename);
        goto failure;
    }
    if (!TIFFRewriteDirectory(tif))
    {
        fprintf(stderr, "Can't rewrite fifth directory to %s\n", filename);
        goto failure;
    }
    i = 4;
    if (!TIFFSetDirectory(tif, i))
    {
        fprintf(stderr, "Can't set %d.th directory from %s\n", i, filename);
        goto failure;
    }
    uint64_t off2 = TIFFCurrentDirOffset(tif);
    if (!is_requested_directory(tif, i, filename))
    {
        goto failure;
    }
    if (off1 == off2)
    {
        fprintf(stderr,
                "Rewritten directory %d was not correctly accessed by "
                "TIFFSetDirectory() in file %s\n",
                i, filename);
        goto failure;
    }

    /* Now, perform the test for the first directory */
    TIFFSetDirectory(tif, 0);
    if (!is_requested_directory(tif, 0, filename))
    {
        TIFFClose(tif);
        return 5;
    }
    off1 = TIFFCurrentDirOffset(tif);
    if (write_data_to_current_directory(tif, 0, false))
    {
        fprintf(stderr, "Can't write data to first directory in %s\n",
                filename);
        goto failure;
    }
    if (!TIFFRewriteDirectory(tif))
    {
        fprintf(stderr, "Can't rewrite first directory to %s\n", filename);
        goto failure;
    }
    i = 0;
    if (!TIFFSetDirectory(tif, i))
    {
        fprintf(stderr, "Can't set %d.th directory from %s\n", i, filename);
        goto failure;
    }
    off2 = TIFFCurrentDirOffset(tif);
    if (!is_requested_directory(tif, i, filename))
    {
        goto failure;
    }
    if (off1 == off2)
    {
        fprintf(stderr,
                "Rewritten directory %d was not correctly accessed by "
                "TIFFSetDirectory() in file %s\n",
                i, filename);
        goto failure;
    }

    TIFFClose(tif);
    tif = NULL;

    /* Check that the file has the expected number of directories*/
    if (count_directories(filename, &count))
    {
        fprintf(stderr, "Error counting directories in file %s.\n", filename);
        goto failure;
    }
    if (count != N_DIRECTORIES)
    {
        fprintf(stderr,
                "Unexpected number of directories in %s. Expected %i, "
                "found %i.\n",
                filename, N_DIRECTORIES, count);
        goto failure;
    }
    /* hint: file was closed by count_directories() */
    unlink(filename);
    return 0;

failure:
    if (tif)
    {
        TIFFClose(tif);
    }
    return 1;
} /*-- test_rewrite_lastdir_offset() --*/

static void extender(TIFF *tif)
{
    if (p_tiff_field_info != NULL)
    {
        TIFFMergeFieldInfo(tif, p_tiff_field_info, N_tiff_field_info);
        if (parent)
        {
            (*parent)(tif);
        }
    }
    else
    {
        TIFFErrorExtR(tif, "field_info_extender",
                      "Pointer to tiff_field_info array is NULL.");
    }
}

/*-- readTestTiff_ignore_some_tags() --*/

int main(void)
{
    /*-- Signed tags test --*/
    parent = TIFFSetTagExtender(&extender);
    if (writeTestTiff("temp.tif", 0) != OK_RETURN)
        return (-1);
    if (readTestTiff("temp.tif", 0) != OK_RETURN)
        return (-1);

    if (writeTestTiff("tempBig.tif", 1) != OK_RETURN)
        return (-1);
    if (readTestTiff("tempBig.tif", 1) != OK_RETURN)
        return (-1);
    unlink("tempBig.tif");
    fprintf(stdout, "---------- Signed tag test finished OK -----------\n");

    /*-- Adapt tiff_field_info array for ignoring unknown tags to LibTIFF, which
     * have been written to file. --*/
    if (readTestTiff_ignore_some_tags("temp.tif") != OK_RETURN)
        return (-1);
    unlink("temp.tif");
    fprintf(stdout,
            "---------- Ignoring unknown tag test finished OK -----------\n");

    return 0;
}

/*-- readTestTiff() --*/

static int readTestTiff_ignore_some_tags(const char *szFileName)
{
    int ret;
    int8_t s8l;
    int16_t s16l;
    int32_t s32l;
    int retcode = FAULT_RETURN;

    /* There is a use case, where LibTIFF shall be prevented from reading
     * unknown tags that are present in the file as anonymous tags. This can be
     * achieved by defining these tags with ".field_bit = FIELD_IGNORE". */

    /* Copy const array to be manipulated and freed just after TIFFMergeFields()
     * within the "extender()" called by TIFFOpen(). */
    TIFFFieldInfo *tiff_field_info2;
    tiff_field_info2 = (TIFFFieldInfo *)malloc(sizeof(tiff_field_info));
    if (tiff_field_info2 == (TIFFFieldInfo *)NULL)
    {
        fprintf(stdout,
                "Can't allocate memoy for tiff_field_info2 structure.\n");
        return (FAULT_RETURN);
    }
    memcpy(tiff_field_info2, tiff_field_info, sizeof(tiff_field_info));
    /* Switch field array for extender callback. */
    p_tiff_field_info = tiff_field_info2;

    /*-- Adapt tiff_field_info array for ignoring unknown tags to LibTIFF, which
     * have been written to file before. --*/
    /* a.) Just set field_bit to FIELD_IGNORE = 0 */
    tiff_field_info2[2].field_bit = FIELD_IGNORE;
    /* b.) Usecase with all field array infos zero but the tag value. */
    ttag_t tag = tiff_field_info2[4].field_tag;
    memset(&tiff_field_info2[4], 0, sizeof(tiff_field_info2[4]));
    tiff_field_info2[4].field_tag = tag;

    fprintf(stdout, "\n-- Reading file with unknown tags to be ignored ...\n");
    TIFF *tif = TIFFOpen(szFileName, "r");

    /* tiff_field_info2 should not be needed anymore, as long as the still
     * active extender() is not called again. Therefore, the extender callback
     * should be disabled by resetting it to the saved one. */
    free(tiff_field_info2);
    tiff_field_info2 = NULL;
    TIFFSetTagExtender(parent);

    if (!tif)
    {
        fprintf(stdout, "Can't open test TIFF file %s.\n", szFileName);
        return (FAULT_RETURN);
    }

    /* Read the first two known tags for testing */
    ret = TIFFGetField(tif, SINT8, &s8l);
    if (ret != 1)
    {
        fprintf(stdout, "Error reading SINT8: ret=%d\n", ret);
        GOTOFAILURE
    }
    else
    {
        if (s8l != s8[idxSingle])
        {
            fprintf(stdout,
                    "Read value of SINT8  %d differs from set value %d\n", s8l,
                    s8[idxSingle]);
            GOTOFAILURE
        }
    }
    ret = TIFFGetField(tif, SINT16, &s16l);
    if (ret != 1)
    {
        fprintf(stdout, "Error reading SINT16: ret=%d\n", ret);
        GOTOFAILURE
    }
    else
    {
        if (s16l != s16[idxSingle])
        {
            fprintf(stdout,
                    "Read value of SINT16  %d differs from set value %d\n",
                    s16l, s16[idxSingle]);
            GOTOFAILURE
        }
    }

    /* The two ignored tags shall not be present. */
    ret = TIFFGetField(tif, tiff_field_info[2].field_tag, &s32l);
    if (ret != 0)
    {
        fprintf(stdout,
                "Error: Tag %d, set to be ignored, has been read from file.\n",
                tiff_field_info[2].field_tag);
        GOTOFAILURE
    }

    ret = TIFFGetField(tif, tiff_field_info[4].field_tag, &s32l);
    if (ret != 0)
    {
        fprintf(stdout,
                "Error: Tag %d, set to be ignored, has been read from file.\n",
                tiff_field_info[4].field_tag);
        GOTOFAILURE
    }

    retcode = OK_RETURN;
failure:

    fprintf(stdout,
            "-- End of test for ignored unknown tags. Closing TIFF file. --\n");
    TIFFClose(tif);
    return (retcode);
}

static int writeTestTiff(const char *szFileName, int isBigTiff)
{
    int ret;
    TIFF *tif;
    int retcode = FAULT_RETURN;

    unlink(szFileName);
    if (isBigTiff)
    {
        fprintf(stdout, "\n-- Writing signed values to BigTIFF...\n");
        tif = TIFFOpen(szFileName, "w8");
    }
    else
    {
        fprintf(stdout, "\n-- Writing signed values to ClassicTIFF...\n");
        tif = TIFFOpen(szFileName, "w");
    }
    if (!tif)
    {
        fprintf(stdout, "Can't create test TIFF file %s.\n", szFileName);
        return (FAULT_RETURN);
    }

    ret = TIFFSetField(tif, SINT8, s8[idxSingle]);
    if (ret != 1)
    {
        fprintf(stdout, "Error writing SINT8: ret=%d\n", ret);
        GOTOFAILURE;
    }
    ret = TIFFSetField(tif, SINT16, s16[idxSingle]);
    if (ret != 1)
    {
        fprintf(stdout, "Error writing SINT16: ret=%d\n", ret);
        GOTOFAILURE;
    }
    ret = TIFFSetField(tif, SINT32, s32[idxSingle]);
    if (ret != 1)
    {
        fprintf(stdout, "Error writing SINT32: ret=%d\n", ret);
        GOTOFAILURE;
    }

    TIFFSetField(tif, C0_SINT8, &s8);
    TIFFSetField(tif, C0_SINT16, &s16);
    TIFFSetField(tif, C0_SINT32, &s32);

    TIFFSetField(tif, C16_SINT8, 6, &s8);
    TIFFSetField(tif, C16_SINT16, 6, &s16);
    TIFFSetField(tif, C16_SINT32, 6, &s32);

    TIFFSetField(tif, C16_SINT8, 6, &s8);
    TIFFSetField(tif, C16_SINT16, 6, &s16);
    TIFFSetField(tif, C16_SINT32, 6, &s32);

    TIFFSetField(tif, C32_SINT8, 6, &s8);
    TIFFSetField(tif, C32_SINT16, 6, &s16);
    TIFFSetField(tif, C32_SINT32, 6, &s32);

    if (isBigTiff)
    {
        ret = TIFFSetField(tif, SINT64, s64[0]);
        if (ret != 1)
        {
            fprintf(stdout, "Error writing SINT64: ret=%d\n", ret);
            GOTOFAILURE;
        }
        ret = TIFFSetField(tif, C0_SINT64, &s64);
        if (ret != 1)
        {
            fprintf(stdout, "Error writing C0_SINT64: ret=%d\n", ret);
            GOTOFAILURE;
        }
        ret = TIFFSetField(tif, C16_SINT64, N(s64), &s64);
        if (ret != 1)
        {
            fprintf(stdout, "Error writing C16_SINT64: ret=%d\n", ret);
            GOTOFAILURE;
        }
        ret = TIFFSetField(tif, C32_SINT64, N(s64), &s64);
        if (ret != 1)
        {
            fprintf(stdout, "Error writing C32_SINT64: ret=%d\n", ret);
            GOTOFAILURE;
        }
        ret = TIFFSetField(tif, C32_SINT64NULL, N(s64), &s64);
        if (ret != 1)
        {
            fprintf(stdout, "Error writing C32_SINT64NULL: ret=%d\n", ret);
            GOTOFAILURE;
        }
    }

    TIFFSetField(tif, TIFFTAG_IMAGEWIDTH, 1);
    TIFFSetField(tif, TIFFTAG_IMAGELENGTH, 1);
    TIFFSetField(tif, TIFFTAG_BITSPERSAMPLE, 8);
    TIFFSetField(tif, TIFFTAG_COMPRESSION, COMPRESSION_NONE);
    TIFFSetField(tif, TIFFTAG_PHOTOMETRIC, PHOTOMETRIC_MINISBLACK);
    TIFFSetField(tif, TIFFTAG_SAMPLESPERPIXEL, 1);
    TIFFSetField(tif, TIFFTAG_ROWSPERSTRIP, 1);
    ret = (int)TIFFWriteEncodedStrip(tif, 0, "\0", 1);
    if (ret != 1)
    {
        fprintf(stdout, "Error TIFFWriteEncodedStrip: ret=%d\n", ret);
        GOTOFAILURE;
    }

    retcode = OK_RETURN;
failure:
    TIFFClose(tif);
    return (retcode);
}

/* ==== check_tag_definitions() =======================================
 * Check for correct definition of tags within tags FieldArray wrt passcount
 * flag and set_get_field_type.
 */
int check_tag_definitions(void)
{
    const TIFFFieldArray *tFieldArray;
    int ret = 0;

    tFieldArray = _TIFFGetFields();
    ret = testPasscountFlag("---- TIFF tags:", tFieldArray,
                            listTagsNotFollowPasscountRules,
                            NUM_ELEMENTS(listTagsNotFollowPasscountRules));

    tFieldArray = _TIFFGetGpsFields();
    ret += testPasscountFlag("---- GPS tags:", tFieldArray, NULL, 0);

    tFieldArray = _TIFFGetExifFields();
    ret += testPasscountFlag("---- EXIF tags:", tFieldArray, NULL, 0);

    return ret;
} /*-- check_tag_definitions() --*/

/* ==== read_all_tags() ===============================================
 * Reads all tags within tFieldArray according to their set_get_field_type
 * definition except tags listed in listTagsNotToWrite.
 * iCnt is an index into predefined arrays for the values written.
 * The read values are compared to the written ones.
 */
int read_all_tags(TIFF *tif, const TIFFFieldArray *tFieldArray,
                  uint32_t *plistTagsNotToWrite, uint32_t nTagsNotToWrite,
                  uint32_t *iCnt)
{

    /* -- Variables for reading within the switch() -- */
    int32_t j;
    float auxFloat = 0.0f;
    double auxDouble = 0.0;
    char auxChar = 0;
    uint32_t auxUint32 = 0;
    uint64_t auxUint64 = 0;
    short auxShort = 0;
    int32_t auxInt32 = 0;
    union
    {
        int32_t Int32;
        short Short1;
        short Short2[2];
        char Char[4];
    } unionInt32;
    void *pVoidArray;
    char *pAscii;
    double dblDiff, dblDiffLimit;

    char auxCharArray[2 * STRSIZE];
    short auxShortArray[2 * N_SIZE];
    int32_t auxInt32Array[2 * N_SIZE];
    float auxFloatArray[2 * N_SIZE];
    double auxDoubleArray[2 * N_SIZE];
#define RATIONAL_EPS                                                           \
    (1.0 / 30000.0) /* reduced difference of rational values, approx 3.3e-5 */

    uint32_t i = *iCnt;
    uint32_t nTags = tFieldArray->count;
    for (uint32_t t = 0; t < nTags; t++, i++)
    {
        uint32_t tTag = tFieldArray->fields[t].field_tag;
        TIFFDataType tType =
            tFieldArray->fields[t].field_type; /* e.g. TIFF_RATIONAL */
        short tWriteCount = tFieldArray->fields[t].field_writecount;
        TIFFSetGetFieldType tSetFieldType =
            tFieldArray->fields[t]
                .set_get_field_type; /* e.g. TIFF_SETGET_C0_FLOAT */
        char *tFieldName = tFieldArray->fields[t].field_name;
        if (tagIsInList(tTag, plistTagsNotToWrite, nTagsNotToWrite))
            continue;

        /*-- dependent on set_get_field_type read value --*/
        switch (tSetFieldType)
        {
            case TIFF_SETGET_ASCII:
                /* Either the stringlength is defined as a fixed length in
                 * .field_writecount or a NULL-terminated string is used. */
                if (!TIFFGetField(tif, tTag, &pAscii))
                {
                    fprintf(stderr, "Can't read %s\n",
                            tFieldArray->fields[t].field_name);
                    GOTOFAILURE
                    break;
                }
                /* Save string from temporary buffer and compare with
                 * written string. */
                strncpy(auxCharArray, pAscii, sizeof(auxCharArray) - 1u);
                auxCharArray[sizeof(auxCharArray) - 1u] = '\0';
                if (tWriteCount > 0)
                    auxInt32 = tWriteCount - 1;
                else
                    auxInt32 = (int32_t)strlen(auxCharArray);
                int retCode2 =
                    strncmp(auxCharArray, auxTextArrayW[i], auxInt32);
                if (retCode2 != 0)
                {
                    fprintf(stderr,
                            "%d:Read value of %s %s differs from set value "
                            "%s\n",
                            i, tFieldName, auxCharArray, auxTextArrayW[i]);
                    GOTOFAILURE
                }
                break;
            case TIFF_SETGET_C16_ASCII:
                if (tTag == TIFFTAG_INKNAMES)
                {
                    if (!TIFFGetField(tif, tTag, &pVoidArray))
                    {
                        fprintf(stderr, "Can't read %s\n",
                                tFieldArray->fields[t].field_name);
                        GOTOFAILURE
                        break;
                    }
                    if (_TIFFmemcmp(inkNamesW, pVoidArray, sizeof(inkNamesW)) !=
                        0)
                    {
                        fprintf(stderr,
                                "InkNames read (%s) are different from "
                                "InkNamesW "
                                "written %s.\n",
                                (char *)pVoidArray, inkNamesW);
                        GOTOFAILURE
                    }
                }
                break;
                /*-- For reading, the parameter size is to be observed !! */
            case TIFF_SETGET_UINT8:
            case TIFF_SETGET_SINT8:
                if (!TIFFGetField(tif, tTag, &auxChar))
                {
                    fprintf(stderr, "Can't read %s\n",
                            tFieldArray->fields[t].field_name);
                    GOTOFAILURE
                    break;
                }
                /* compare read values with written ones */
                auxInt32 = auxChar;
                if (auxInt32 != (char)auxInt32ArrayW[i])
                {
                    fprintf(stderr,
                            "%d:Read value of %s %d differs from set "
                            "value %d\n",
                            i, tFieldName, auxInt32, auxInt32ArrayW[i]);
                }
                break;
            case TIFF_SETGET_UINT16:
            case TIFF_SETGET_SINT16:
                if (!TIFFGetField(tif, tTag, &auxShort))
                {
                    fprintf(stderr, "Can't read %s\n",
                            tFieldArray->fields[t].field_name);
                    GOTOFAILURE
                    break;
                }
                /* compare read values with written ones */
                auxInt32 = auxShort;
                if (auxInt32 != (short)auxInt32ArrayW[i])
                {
                    fprintf(stderr,
                            "%d:Read value of %s %d differs from set "
                            "value %d\n",
                            i, tFieldName, auxInt32, auxInt32ArrayW[i]);
                    GOTOFAILURE
                }
                break;
            case TIFF_SETGET_UINT16_PAIR:
                if (!TIFFGetField(tif, tTag, &auxShortArray[0],
                                  &auxShortArray[1]))
                {
                    fprintf(stderr, "Can't read %s\n",
                            tFieldArray->fields[t].field_name);
                    GOTOFAILURE
                    break;
                }
                if (auxShortArray[0] != 7 ||
                    auxShortArray[1] != auxInt32ArrayW[i])
                {
                    fprintf(stderr,
                            "%d:Read value of %s %d/%d UINT16_PAIR differs "
                            "from set "
                            "values %d/%d\n",
                            i, tFieldName, auxShortArray[0], auxShortArray[1],
                            7, auxInt32ArrayW[i]);
                    GOTOFAILURE
                }
                break;
            case TIFF_SETGET_UINT32:
            case TIFF_SETGET_SINT32:
            case TIFF_SETGET_INT:
                if (!TIFFGetField(tif, tTag, &auxUint32))
                {
                    fprintf(stderr, "Can't read %s\n",
                            tFieldArray->fields[t].field_name);
                    GOTOFAILURE
                    break;
                }
                /* compare read values with written ones */
                auxInt32 = auxUint32;
                if (auxInt32 != auxInt32ArrayW[i])
                {
                    uint32_t auxU;
                    if (tTag == TIFFTAG_TILEDEPTH &&
                        TIFFGetField(tif, TIFFTAG_IMAGEDEPTH, &auxU))
                    {
                        /* At directory re-reading from file,
                           tif->tif_dir.td_tiledepth =
                           tif->tif_dir.td_imagedepth is set. */
                        if (auxUint32 != auxU)
                        {
                            fprintf(stderr,
                                    "%d:Read value of %s %d differs "
                                    "from set "
                                    "value %d\n",
                                    i, tFieldName, auxUint32, auxU);
                            GOTOFAILURE
                        }
                    }
                    else
                    {
                        fprintf(stderr,
                                "%d:Read value of %s %d differs from set "
                                "value %d\n",
                                i, tFieldName, auxInt32, auxInt32ArrayW[i]);
                        GOTOFAILURE
                    }
                }
                break;
            case TIFF_SETGET_IFD8:
                if (!TIFFGetField(tif, tTag, &auxUint64))
                {
                    fprintf(stderr, "Can't read %s\n",
                            tFieldArray->fields[t].field_name);
                    GOTOFAILURE
                    break;
                }
                /* compare read values with written ones, we wrote only
                 * unit32 values! */
                if (auxUint64 != (uint64_t)auxInt32ArrayW[i])
                {
                    fprintf(stderr,
                            "%d:Read value of %s %" PRIu64 " differs from set"
                            "value %d\n",
                            i, tFieldName, auxUint64, auxInt32ArrayW[i]);
                    GOTOFAILURE
                }
                break;

            case TIFF_SETGET_C16_IFD8:
                if (!TIFFGetField(tif, tTag, &unionInt32, &pVoidArray))
                {
                    fprintf(stderr, "Can't read %s\n",
                            tFieldArray->fields[t].field_name);
                    GOTOFAILURE
                    break;
                }
                if (tTag == TIFFTAG_EXTRACAMERAPROFILES)
                {
                    auxUint64 = *(uint64_t *)pVoidArray;
                    if (unionInt32.Short1 != 1 && auxUint64 != 18)
                    {
                        fprintf(stderr,
                                "%d:Read value of %s %" PRIu64
                                " differs from set"
                                "value %d\n",
                                i, tFieldName, auxUint64, 18);
                        GOTOFAILURE
                    }
                }
                else
                {
                    /* ToDo: Such tags are not written yet.
                     */
                    fprintf(stderr, "TIFF_SETGET_C16_IFD8 arrays not supported "
                                    "in this testprogram.\n");
                    GOTOFAILURE
                }
                break;
            case TIFF_SETGET_FLOAT:
                if (!TIFFGetField(tif, tTag, &auxFloat))
                {
                    fprintf(stderr, "Can't read %s\n",
                            tFieldArray->fields[t].field_name);
                    GOTOFAILURE
                    break;
                }
                /* compare read values with written ones */
                if (tType == TIFF_RATIONAL || tType == TIFF_SRATIONAL)
                    dblDiffLimit = RATIONAL_EPS * auxDoubleArrayW[i];
                else
                    dblDiffLimit = 1e-3;
                dblDiff = auxFloat - auxDoubleArrayW[i];
                if (fabs(dblDiff) > fabs(dblDiffLimit))
                {
                    /*--: EXIFTAG_SUBJECTDISTANCE: LibTiff returns value of
                     * "-1.0" if numerator equals 4294967295 (0xFFFFFFFF) to
                     * indicate infinite distance! However, there are two
                     * other EXIF tags where numerator indicates a special
                     * value and six other cases where the denominator
                     * indicates special values, which are not treated
                     * within LibTiff!!
                     */
                    if (!(tTag == EXIFTAG_SUBJECTDISTANCE && auxFloat == -1.0))
                    {
                        fprintf(stderr,
                                "%d:Read value of %s %f differs from set value "
                                "%f\n",
                                i, tFieldName, auxFloat, auxDoubleArrayW[i]);
                        GOTOFAILURE
                    }
                }
                break;
            case TIFF_SETGET_DOUBLE:
                if (!TIFFGetField(tif, tTag, &auxDouble))
                {
                    fprintf(stderr, "Can't read %s\n",
                            tFieldArray->fields[t].field_name);
                    GOTOFAILURE
                    break;
                }
                /* compare read values with written ones */
                if (tType == TIFF_RATIONAL || tType == TIFF_SRATIONAL)
                    dblDiffLimit = RATIONAL_EPS * auxDoubleArrayW[i];
                else
                    dblDiffLimit = 1e-6;
                dblDiff = auxDouble - auxDoubleArrayW[i];
                if (fabs(dblDiff) > fabs(dblDiffLimit))
                {
                    /*--: EXIFTAG_SUBJECTDISTANCE: LibTiff returns value of
                     * "-1.0" if numerator equals 4294967295 (0xFFFFFFFF) to
                     * indicate infinite distance!
                     */
                    if (!(tTag == EXIFTAG_SUBJECTDISTANCE && auxDouble == -1.0))
                    {
                        fprintf(stderr,
                                "%d:Read value of %s %f differs from set value "
                                "%f\n",
                                i, tFieldName, auxDouble, auxDoubleArrayW[i]);
                        GOTOFAILURE
                    }
                }
                break;
            case TIFF_SETGET_C0_FLOAT:
            case TIFF_SETGET_C0_DOUBLE:
            case TIFF_SETGET_C16_FLOAT:
            case TIFF_SETGET_C16_DOUBLE:
            case TIFF_SETGET_C32_FLOAT:
            case TIFF_SETGET_C32_DOUBLE:
            case TIFF_SETGET_C0_UINT8:
            case TIFF_SETGET_C0_SINT8:
            case TIFF_SETGET_C16_UINT8:
            case TIFF_SETGET_C16_SINT8:
            case TIFF_SETGET_C32_UINT8:
            case TIFF_SETGET_C32_SINT8:
            case TIFF_SETGET_C0_UINT16:
            case TIFF_SETGET_C0_SINT16:
            case TIFF_SETGET_C16_UINT16:
            case TIFF_SETGET_C16_SINT16:
            case TIFF_SETGET_C32_UINT16:
            case TIFF_SETGET_C32_SINT16:
            case TIFF_SETGET_C0_UINT32:
            case TIFF_SETGET_C0_SINT32:
            case TIFF_SETGET_C16_UINT32:
            case TIFF_SETGET_C16_SINT32:
            case TIFF_SETGET_C32_UINT32:
            case TIFF_SETGET_C32_SINT32:
            {
                /* _Cxx_ just defines the presence and size of the count
                 * parameter for the array:
                 * - C0=no count parameter (fixed array where,
                 *      positive readcount/writecount gives array count)
                 * - C16=short (uint16_t) count parameter size
                 * - C32=long (uint32_t) count parameter size
                 * Check, if it is a single parameter, a fixed array or a
                 * variable array.
                 */
                if (tWriteCount == 1)
                {
                    fprintf(
                        stderr,
                        "WriteCount for .set_get_field_type %d should be -1, "
                        "-2, -3 or "
                        "greater than 1!  %s\n",
                        tSetFieldType, tFieldArray->fields[t].field_name);
                    GOTOFAILURE
                }
                else
                {
                    /*-- Either fix or variable array --*/
                    if (tWriteCount > 1)
                    {
                        /* fixed array with needed arraysize defined in
                         * .field_writecount */
                        if (!TIFFGetField(tif, tTag, &pVoidArray))
                        {
                            fprintf(stderr, "Can't read %s\n",
                                    tFieldArray->fields[t].field_name);
                            GOTOFAILURE
                            break;
                        }
                        /* set tWriteCount to number of read samples for
                         * next steps
                         */
                        auxInt32 = tWriteCount;
                    }
                    else
                    {
                        /*-- Special treatment of variable array. --
                         * Dependent on _Cxx_, the count parameter is
                         * short or long. Therefore use unionInt32!
                         */
                        if (!TIFFGetField(tif, tTag, &unionInt32, &pVoidArray))
                        {
                            fprintf(stderr, "Can't read %s\n",
                                    tFieldArray->fields[t].field_name);
                            GOTOFAILURE
                            break;
                        }
                        /* set tWriteCount to number of read samples for
                         * next steps
                         */
                        if (tSetFieldType == TIFF_SETGET_C32_UINT8 ||
                            tSetFieldType == TIFF_SETGET_C32_SINT8 ||
                            tSetFieldType == TIFF_SETGET_C32_UINT16 ||
                            tSetFieldType == TIFF_SETGET_C32_SINT16 ||
                            tSetFieldType == TIFF_SETGET_C32_UINT32 ||
                            tSetFieldType == TIFF_SETGET_C32_SINT32 ||
                            tSetFieldType == TIFF_SETGET_C32_FLOAT ||
                            tSetFieldType == TIFF_SETGET_C32_DOUBLE)
                        {
                            auxInt32 = unionInt32.Int32;
                        }
                        else
                        {
                            auxInt32 = unionInt32.Short1;
                        }
                    }
                    /* Save values from temporary array and compare to
                     * written values. */
                    if (tSetFieldType == TIFF_SETGET_C0_FLOAT ||
                        tSetFieldType == TIFF_SETGET_C16_FLOAT ||
                        tSetFieldType == TIFF_SETGET_C32_FLOAT)
                    {
                        memcpy(&auxFloatArray, pVoidArray,
                               (auxInt32 * sizeof(auxFloatArray[0])));
                        /* compare read values with written ones */
                        if (tType == TIFF_RATIONAL || tType == TIFF_SRATIONAL)
                            dblDiffLimit = RATIONAL_EPS * auxDoubleArrayW[i];
                        else
                            dblDiffLimit = 1e-6;
                        for (j = 0; j < auxInt32; j++)
                        {
                            dblDiff = auxFloatArray[j] - auxFloatArrayW[i + j];
                            if (fabs(dblDiff) > fabs(dblDiffLimit))
                            {
                                fprintf(stderr,
                                        "Read value %d of %s #%d %f differs "
                                        "from set value %f\n",
                                        i, tFieldName, j, auxFloatArray[j],
                                        auxFloatArrayW[i + j]);
                                GOTOFAILURE
                            }
                        }
                    }
                    else if (tSetFieldType == TIFF_SETGET_C0_DOUBLE ||
                             tSetFieldType == TIFF_SETGET_C16_DOUBLE ||
                             tSetFieldType == TIFF_SETGET_C32_DOUBLE)
                    {
                        memcpy(&auxDoubleArray, pVoidArray,
                               (auxInt32 * sizeof(auxDoubleArray[0])));
                        /* compare read values with written ones */
                        if (tType == TIFF_RATIONAL || tType == TIFF_SRATIONAL)
                            dblDiffLimit = RATIONAL_EPS * auxDoubleArrayW[i];
                        else
                            dblDiffLimit = 1e-6;
                        for (j = 0; j < auxInt32; j++)
                        {
                            dblDiff =
                                auxDoubleArray[j] - auxDoubleArrayW[i + j];
                            if (fabs(dblDiff) > fabs(dblDiffLimit))
                            {
                                fprintf(stderr,
                                        "Read value %d of %s #%d %f differs "
                                        "from set value %f\n",
                                        i, tFieldName, j, auxDoubleArray[j],
                                        auxDoubleArrayW[i + j]);
                                GOTOFAILURE
                            }
                        }
                    }
                    else if (tSetFieldType == TIFF_SETGET_C0_UINT8 ||
                             tSetFieldType == TIFF_SETGET_C0_SINT8 ||
                             tSetFieldType == TIFF_SETGET_C16_UINT8 ||
                             tSetFieldType == TIFF_SETGET_C16_SINT8 ||
                             tSetFieldType == TIFF_SETGET_C32_UINT8 ||
                             tSetFieldType == TIFF_SETGET_C32_SINT8)
                    {
                        memcpy(&auxCharArray, pVoidArray,
                               (auxInt32 * sizeof(auxCharArray[0])));
                        /* Compare and check values  */
                        char *auxCharCompare;
                        if (tTag == EXIFTAG_EXIFVERSION)
                        {
                            auxCharCompare = exifVersion;
                        }
                        else if (tTag == GPSTAG_VERSIONID)
                        {
                            auxCharCompare = gpsVersion;
                        }
                        else
                        {
                            auxCharCompare = &auxCharArrayW[i];
                        }

                        for (j = 0; j < auxInt32; j++)
                        {
                            if (auxCharArray[j] != auxCharCompare[j])
                            {
                                fprintf(stderr,
                                        "Read value %d of %s #%d %d differs "
                                        "from set value %d\n",
                                        i, tFieldName, j, auxCharArray[j],
                                        auxCharArrayW[i + j]);
                                GOTOFAILURE
                            }
                        }
                    }
                    else if (tSetFieldType == TIFF_SETGET_C0_UINT16 ||
                             tSetFieldType == TIFF_SETGET_C0_SINT16 ||
                             tSetFieldType == TIFF_SETGET_C16_UINT16 ||
                             tSetFieldType == TIFF_SETGET_C16_SINT16 ||
                             tSetFieldType == TIFF_SETGET_C32_UINT16 ||
                             tSetFieldType == TIFF_SETGET_C32_SINT16)
                    {
                        memcpy(&auxShortArray, pVoidArray,
                               (auxInt32 * sizeof(auxShortArray[0])));
                        /* Compare and check values  */
                        for (j = 0; j < auxInt32; j++)
                        {
                            if (auxShortArray[j] != auxShortArrayW[i + j])
                            {
                                fprintf(stderr,
                                        "Read value %d of %s #%d %d "
                                        "differs from "
                                        "set value %d\n",
                                        i, tFieldName, j, auxShortArray[j],
                                        auxShortArrayW[i + j]);
                                GOTOFAILURE
                            }
                        }
                    }
                    else if (tSetFieldType == TIFF_SETGET_C0_UINT32 ||
                             tSetFieldType == TIFF_SETGET_C0_SINT32 ||
                             tSetFieldType == TIFF_SETGET_C16_UINT32 ||
                             tSetFieldType == TIFF_SETGET_C16_SINT32 ||
                             tSetFieldType == TIFF_SETGET_C32_UINT32 ||
                             tSetFieldType == TIFF_SETGET_C32_SINT32)
                    {
                        memcpy(&auxInt32Array, pVoidArray,
                               (auxInt32 * sizeof(auxInt32Array[0])));
                        /* Compare and check values  */
                        for (j = 0; j < auxInt32; j++)
                        {
                            if (auxInt32Array[j] != auxInt32ArrayW[i + j])
                            {
                                fprintf(stderr,
                                        "Read value %d of %s #%d %d "
                                        "differs from "
                                        "set value %d\n",
                                        i, tFieldName, j, auxInt32Array[j],
                                        auxInt32ArrayW[i + j]);
                                GOTOFAILURE
                            }
                        }
                    }
                    else
                    {
                        fprintf(stderr,
                                "SetFieldType %d not defined within array"
                                "reading clause for %s.\n",
                                tSetFieldType, tFieldName);
                        GOTOFAILURE
                    }
                }
            } /* case for all arrays */
            break;
            case TIFF_SETGET_OTHER:
                /* ToDo: Transferfunction and Colormap to be inserted here. */
                break;
            case TIFF_SETGET_UNDEFINED:
                /* Such tags are not written to file. */
                break;
            default:
                fprintf(stderr,
                        "SetFieldType %d not defined within reading switch for "
                        "%s.\n",
                        tSetFieldType, tFieldName);
                GOTOFAILURE
        }; /*-- switch(tSetFieldType) --*/
    }      /*-- for(t to nTags) --*/

    *iCnt = i;
    return 0;
failure:
    fprintf(stderr, "\n");
    *iCnt = i;
    return 1;
} /*---  read_all_tags() ---*/

/* ==== testPasscountFlag() ===========================================
 * Checks the tag FieldArray settings for the passcount flag.
 * Some tags, which are handled directly, do not follow the rules.
 *
 */
int testPasscountFlag(const char *szMsg, const TIFFFieldArray *tFieldArray,
                      uint32_t *plistTagsNotFollowPasscountRules,
                      uint32_t nTagsInList)
{
    uint32_t t;
    int retFails = 0;

    uint32_t nTags = tFieldArray->count;
    /*-- Test ReadCount equals WriteCount. --*/
    int nFails = 0;
    fprintf(stderr, "%-16s Check if writecount equals readcount ... ", szMsg);
    for (t = 0; t < nTags; t++)
    {
        if (tagIsInList(tFieldArray->fields[t].field_tag,
                        plistTagsNotFollowPasscountRules, nTagsInList))
            continue;

        if (tFieldArray->fields[t].field_writecount !=
            tFieldArray->fields[t].field_readcount)
        {
            if (nFails == 0)
                fprintf(stderr, "\n");
            fprintf(stderr,
                    "WriteCount %d for tag \t%-25s not equal ReadCount %d.\n",
                    tFieldArray->fields[t].field_writecount,
                    tFieldArray->fields[t].field_name,
                    tFieldArray->fields[t].field_readcount);
            nFails++;
        }
    } /* for - readcount == writecount */
    if (nFails == 0)
        fprintf(stderr, "--> OK\n");
    retFails += nFails;

    /*-- Test correct setting of passcount flag. --*/
    nFails = 0;
    fprintf(stderr,
            "%-16s Check if passcount flag is set according to "
            "writecount value ... ",
            szMsg);
    for (t = 0; t < nTags; t++)
    {
        if (tagIsInList(tFieldArray->fields[t].field_tag,
                        plistTagsNotFollowPasscountRules, nTagsInList))
            continue;

        if (tFieldArray->fields[t].field_writecount < 0)
        {
            if (tFieldArray->fields[t].field_type != TIFF_ASCII &&
                tFieldArray->fields[t].field_passcount == 0)
            {
                if (tFieldArray->fields[t].field_readcount != TIFF_SPP)
                {
                    if (nFails == 0)
                        fprintf(stderr, "\n");
                    fprintf(stderr,
                            "Passcount flag for variable rd/wrtcount tag "
                            "\t%-25s not "
                            "correctly set. Should be "
                            "TRUE.\n",
                            tFieldArray->fields[t].field_name);
                }
                else
                {
                    if (nFails == 0)
                        fprintf(stderr, "\n");
                    fprintf(
                        stderr,
                        "Passcount flag for TIFF_SPP readcount tag \t%-25s not "
                        "correctly set. Should be "
                        "TRUE.\n",
                        tFieldArray->fields[t].field_name);
                }
                nFails++;
            }
            else if (tFieldArray->fields[t].field_type == TIFF_ASCII &&
                     tFieldArray->fields[t].set_get_field_type ==
                         TIFF_SETGET_ASCII &&
                     tFieldArray->fields[t].field_writecount !=
                         TIFF_VARIABLE2 &&
                     tFieldArray->fields[t].field_passcount != 0)
            {
                if (nFails == 0)
                    fprintf(stderr, "\n");
                fprintf(
                    stderr,
                    "Passcount flag for ASCII tag \t%-25s not correctly set. "
                    "Should be "
                    "FALSE.\n",
                    tFieldArray->fields[t].field_name);
                nFails++;
            }
            else if (tFieldArray->fields[t].field_type == TIFF_ASCII &&
                     tFieldArray->fields[t].field_writecount ==
                         TIFF_VARIABLE2 &&
                     tFieldArray->fields[t].field_passcount == 0)
            {
                if (nFails == 0)
                    fprintf(stderr, "\n");
                fprintf(stderr,
                        "Passcount flag for ASCII 'TIFF_VARIABLE2' tag \t%-25s "
                        "not correctly set. "
                        "Should be TRUE.\n",
                        tFieldArray->fields[t].field_name);
                nFails++;
            }
        }
        else
        {
            /* field_writecount >= 0 */
            if (tFieldArray->fields[t].field_passcount != 0)
            {
                if (nFails == 0)
                    fprintf(stderr, "\n");
                fprintf(stderr,
                        "Passcount flag for tag \t%-25s not correctly set. "
                        "Should be "
                        "FALSE.\n",
                        tFieldArray->fields[t].field_name);
                nFails++;
            }
            if (tFieldArray->fields[t].field_writecount == 0)
            {
                if (nFails == 0)
                    fprintf(stderr, "\n");
                fprintf(stderr,
                        "WriteCount for tag \t%-25s shall be not zero.\n",
                        tFieldArray->fields[t].field_name);
                nFails++;
            }
        }
    } /* for() - passcount flag */
    if (nFails == 0)
        fprintf(stderr, "--> OK\n");
    retFails += nFails;

    /*-- Test correct read-/writecount and TIFF_SETGET type. --*/
    nFails = 0;
    fprintf(stderr, "%-16s Check if writecount fits to set_get_field_type ... ",
            szMsg);
    for (t = 0; t < nTags; t++)
    {
        if (tagIsInList(tFieldArray->fields[t].field_tag,
                        plistTagsNotFollowPasscountRules, nTagsInList))
            continue;

        /* TIFF_SETGET_UNDEFINED tags FIELD_IGNORE tags are not written to file.
         * Thus definition is obsolete. */
        // if (tFieldArray->fields[t].set_get_field_type >=
        // TIFF_SETGET_UNDEFINED &&
        //     tFieldArray->fields[t].field_bit == FIELD_IGNORE)
        //     continue;

        if (tFieldArray->fields[t].field_writecount == TIFF_VARIABLE2 &&
            !(tFieldArray->fields[t].set_get_field_type >=
                  TIFF_SETGET_C32_ASCII &&
              tFieldArray->fields[t].set_get_field_type <=
                  TIFF_SETGET_C32_IFD8))
        {
            if (nFails == 0)
                fprintf(stderr, "\n");
            fprintf(stderr,
                    "WriteCount %d for tag \t%-25s does not fit to "
                    "'set_get_field_type' %d. "
                    "Should be TIFF_VARIABLE2=-3\n",
                    tFieldArray->fields[t].field_writecount,
                    tFieldArray->fields[t].field_name,
                    tFieldArray->fields[t].set_get_field_type);
            nFails++;
        }
        else if (tFieldArray->fields[t].field_writecount == TIFF_VARIABLE &&
                 tFieldArray->fields[t].field_type != TIFF_ASCII &&
                 !(tFieldArray->fields[t].set_get_field_type >=
                       TIFF_SETGET_C16_ASCII &&
                   tFieldArray->fields[t].set_get_field_type <=
                       TIFF_SETGET_C16_IFD8))
        {
            if (tFieldArray->fields[t].field_readcount == TIFF_SPP)
            {
                /* Special case for tags defined with one value per sample,
                 * thus readcount == SamplesPerPixel.
                 */
            }
            else
            {

                if (nFails == 0)
                    fprintf(stderr, "\n");
                fprintf(stderr,
                        "WriteCount %d for tag \t%-25s does not fit to "
                        "'set_get_field_type' %d. "
                        "Should be TIFF_VARIABLE=-1\n",
                        tFieldArray->fields[t].field_writecount,
                        tFieldArray->fields[t].field_name,
                        tFieldArray->fields[t].set_get_field_type);
                nFails++;
            }
        }
        else if (tFieldArray->fields[t].field_writecount > 1 &&
                 !((tFieldArray->fields[t].set_get_field_type >=
                        TIFF_SETGET_C0_ASCII &&
                    tFieldArray->fields[t].set_get_field_type <=
                        TIFF_SETGET_C0_IFD8) ||
                   tFieldArray->fields[t].set_get_field_type ==
                       TIFF_SETGET_ASCII))
        {
            if (!(tFieldArray->fields[t].set_get_field_type ==
                      TIFF_SETGET_UINT16_PAIR &&
                  tFieldArray->fields[t].field_writecount == 2))
            {

                if (nFails == 0)
                    fprintf(stderr, "\n");
                fprintf(stderr,
                        "WriteCount %d for tag \t%-25s does not fit to "
                        "'set_get_field_type' %d. "
                        "Should be >1. \n",
                        tFieldArray->fields[t].field_writecount,
                        tFieldArray->fields[t].field_name,
                        tFieldArray->fields[t].set_get_field_type);
                nFails++;
            }
        }
        else if (tFieldArray->fields[t].field_writecount == 1 &&
                 !(tFieldArray->fields[t].set_get_field_type >=
                       TIFF_SETGET_UNDEFINED &&
                   tFieldArray->fields[t].set_get_field_type <=
                       TIFF_SETGET_INT))
        {
            if (nFails == 0)
                fprintf(stderr, "\n");
            fprintf(stderr,
                    "WriteCount %d for tag \t%-25s does not fit to "
                    "'set_get_field_type' %d. "
                    "Should be 1. \n",
                    tFieldArray->fields[t].field_writecount,
                    tFieldArray->fields[t].field_name,
                    tFieldArray->fields[t].set_get_field_type);
            nFails++;
        }
    } /* for - read-/writecount and TIFF_SETGET type */
    if (nFails == 0)
        fprintf(stderr, "--> OK\n");
    retFails += nFails;

    fprintf(stderr, "\n");
    return retFails;
} /*-- testPassountFlag() --*/

/* ==== write_all_tags() ==============================================
 * Writes all tags within tFieldArray according to their set_get_field_type
 * definition except tags listed in listTagsNotToWrite.
 * iCnt is an index into predefined arrays for the values to write.
 */
int write_all_tags(TIFF *tif, const TIFFFieldArray *tFieldArray,
                   uint32_t *plistTagsNotToWrite, uint32_t nTagsInList,
                   uint32_t *iCnt)
{

    char auxCharArray[2 * STRSIZE];

    uint32_t i = *iCnt;
    uint32_t nTags = tFieldArray->count;
    for (uint32_t t = 0; t < nTags; i++, t++)
    {
        bool deferredSetField = false;
        /* Always reset variableArrayCount to default value here. */
        uint32_t variableArrayCount = VARIABLE_ARRAY_SIZE;

        uint32_t tTag = tFieldArray->fields[t].field_tag;
        if (tagIsInList(tTag, plistTagsNotToWrite, nTagsInList))
            continue;

        TIFFDataType tType =
            tFieldArray->fields[t].field_type; /* e.g. TIFF_RATIONAL */
        (void)tType;
        short tWriteCount = tFieldArray->fields[t].field_writecount;
        TIFFSetGetFieldType tSetFieldType =
            tFieldArray->fields[t]
                .set_get_field_type; /* e.g. TIFF_SETGET_C0_FLOAT */
        char *tFieldName = tFieldArray->fields[t].field_name;
        void *pVoid = NULL;

        /*-- dependent on set_get_field_type write value --*/
        uint32_t auxUint32 = 0;
        switch (tSetFieldType)
        {
            case TIFF_SETGET_ASCII:
                /* Either the stringlength is defined as a fixed length in
                 * .field_writecount or a NULL-terminated string is used.
                 * Shorter strings than in auxTextArraxW need a
                 * NULL-termination. Therefore copy the string. */
                if (tWriteCount > 0)
                    auxUint32 = tWriteCount - 1;
                else
                    auxUint32 = (uint32_t)strlen(auxTextArrayW[i]) - 1;
                auxUint32 = (size_t)auxUint32 >= sizeof(auxCharArray)
                                ? (uint32_t)(sizeof(auxCharArray) - 1)
                                : auxUint32;
                strncpy(auxCharArray, auxTextArrayW[i], auxUint32);
                auxCharArray[auxUint32] = 0;
                if (!TIFFSetField(tif, tTag, auxCharArray))
                {
                    fprintf(stderr, "Can't write %s\n",
                            tFieldArray->fields[t].field_name);
                    goto failure;
                }
                break;
            case TIFF_SETGET_C16_ASCII:
                if (tTag == TIFFTAG_INKNAMES)
                {
                    if (!TIFFSetField(tif, tTag, sizeof(inkNamesW), inkNamesW))
                    {
                        fprintf(stderr, "Can't write %s\n",
                                tFieldArray->fields[t].field_name);
                        goto failure;
                    }
                }
                break;
            case TIFF_SETGET_UINT8:
            case TIFF_SETGET_UINT16:
            case TIFF_SETGET_UINT32:
            case TIFF_SETGET_INT:
            case TIFF_SETGET_UNDEFINED:
                /*-- All those can be written with char, short or long
                 * parameter. Only value range should be in line. */
                if ((tSetFieldType == TIFF_SETGET_UINT8) &&
                    (auxInt32ArrayW[i] > 255))
                    auxInt32ArrayW[i] = 255;
                else if ((tSetFieldType == TIFF_SETGET_UINT16) &&
                         (auxInt32ArrayW[i] > 65535))
                    auxInt32ArrayW[i] = 65535;
                if (tTag == TIFFTAG_FILLORDER)
                    auxInt32ArrayW[i] = 1;
                if (tTag == TIFFTAG_ORIENTATION)
                    auxInt32ArrayW[i] = 7;
                if (tTag == TIFFTAG_RESOLUTIONUNIT)
                    auxInt32ArrayW[i] = 3;
                if (tTag == TIFFTAG_SAMPLEFORMAT)
                    auxInt32ArrayW[i] = SAMPLEFORMAT_UINT;
                if (!TIFFSetField(tif, tTag, auxInt32ArrayW[i]))
                {
                    fprintf(stderr, "Can't write %s\n",
                            tFieldArray->fields[t].field_name);
                    goto failure;
                }
                break;
            case TIFF_SETGET_UINT16_PAIR:
                if (auxInt32ArrayW[i] > 65535)
                    auxInt32ArrayW[i] = 65535;
                if (!TIFFSetField(tif, tTag, 7, auxInt32ArrayW[i]))
                {
                    fprintf(stderr, "Can't write %s\n",
                            tFieldArray->fields[t].field_name);
                    goto failure;
                }
                break;
            case TIFF_SETGET_UINT64:
            case TIFF_SETGET_IFD8:
                /* IFD8 is uint64_t but we write here only values for uint32
                 * size, even for BigTIFF.
                 * -- Attention: --
                 * "Variable promotion" for va_arg parameters are promoted to
                 * "int", which is different in x64 and x86 compilations.
                 * Thus cast to expected uint64_t.
                 */
                if (!TIFFSetField(tif, tTag, (uint64_t)auxInt32ArrayW[i]))
                {
                    fprintf(stderr, "Can't write %s\n",
                            tFieldArray->fields[t].field_name);
                    goto failure;
                }
                break;
            case TIFF_SETGET_SINT8:
            case TIFF_SETGET_SINT16:
            case TIFF_SETGET_SINT32:
                /*-- All those can be written with char, short or long
                 * parameter. Only value range should be in line. */
                if (!TIFFSetField(tif, tTag, -1.0 * auxInt32ArrayW[i]))
                {
                    fprintf(stderr, "Can't write %s\n",
                            tFieldArray->fields[t].field_name);
                    goto failure;
                }
                break;
            case TIFF_SETGET_FLOAT:
            case TIFF_SETGET_DOUBLE:
                if (tWriteCount == 1)
                {
                    /*-- All single values can be written with float or
                     * double parameter. Only value range should be in line.
                     */
                    if (!TIFFSetField(tif, tTag, auxDoubleArrayW[i]))
                    {
                        fprintf(stderr, "Can't write %s\n",
                                tFieldArray->fields[t].field_name);
                        goto failure;
                    }
                }
                else if (tFieldArray->fields[t].field_readcount == TIFF_SPP)
                {
                    /*-- Some tags are written per SamplesPerPixel. For
                     * those, readcount is TIFF_SPP. */
                    if (tTag == TIFFTAG_SMINSAMPLEVALUE ||
                        tTag == TIFFTAG_SMAXSAMPLEVALUE)
                    {
                        auxDoubleArrayW[i] = 250;
                    }
                    if (!TIFFSetField(tif, tTag, auxDoubleArrayW[i]))
                    {
                        fprintf(stderr, "Can't write %s\n",
                                tFieldArray->fields[t].field_name);
                        goto failure;
                    }
                }
                else
                {
                    fprintf(stderr,
                            "WriteCount for .set_get_field_type %d should be "
                            "1!  %s\n",
                            tSetFieldType, tFieldArray->fields[t].field_name);
                }
                break;
                /* _Cxx_ just defines the presence and size of the count
                 * parameter for the array:
                 * - C0=no count parameter (fixed array where,
                 *      positive readcount/writecount gives array count)
                 * - C16=short (uint16_t) count parameter size
                 * - C32=long (uint32_t) count parameter size
                 * Check, if it is a single parameter, a fixed array or a
                 * variable array.
                 */
            case TIFF_SETGET_C0_FLOAT:
            case TIFF_SETGET_C16_FLOAT:
            case TIFF_SETGET_C32_FLOAT:
                /* For arrays, distinguishing between float or double is
                 * essential, even for writing. */
                pVoid = &auxFloatArrayW[i];
                deferredSetField = true;
                break;
            case TIFF_SETGET_C0_DOUBLE:
            case TIFF_SETGET_C16_DOUBLE:
            case TIFF_SETGET_C32_DOUBLE:
                /* For arrays, distinguishing between float or double is
                 * essential, even for writing. */
                pVoid = &auxDoubleArrayW[i];
                deferredSetField = true;
                break;
            case TIFF_SETGET_C0_UINT8:
            case TIFF_SETGET_C0_SINT8:
            case TIFF_SETGET_C16_UINT8:
            case TIFF_SETGET_C16_SINT8:
            case TIFF_SETGET_C32_UINT8:
            case TIFF_SETGET_C32_SINT8:
                pVoid = &auxCharArrayW[i];
                deferredSetField = true;
                break;
            case TIFF_SETGET_C0_UINT16:
            case TIFF_SETGET_C0_SINT16:
            case TIFF_SETGET_C16_UINT16:
            case TIFF_SETGET_C16_SINT16:
            case TIFF_SETGET_C32_UINT16:
            case TIFF_SETGET_C32_SINT16:
                if (tTag == TIFFTAG_EXTRASAMPLES)
                {
                    variableArrayCount = 1;
                    auxShortArrayW[i] = 2;
                }
                pVoid = &auxShortArrayW[i];
                deferredSetField = true;
                break;
            case TIFF_SETGET_C0_UINT32:
            case TIFF_SETGET_C0_SINT32:
            case TIFF_SETGET_C16_UINT32:
            case TIFF_SETGET_C16_SINT32:
            case TIFF_SETGET_C32_UINT32:
            case TIFF_SETGET_C32_SINT32:
                pVoid = &auxInt32ArrayW[i];
                deferredSetField = true;
                break;
            case TIFF_SETGET_C16_IFD8:
                if (tTag == TIFFTAG_EXTRACAMERAPROFILES)
                {
                    uint64_t a = 18;
                    if (!TIFFSetField(tif, tTag, 1, &a))
                    {
                        fprintf(stderr, "Can't write %s\n",
                                tFieldArray->fields[t].field_name);
                        goto failure;
                    }
                }
                else
                {
                    pVoid = &auxInt32ArrayW[i];
                    deferredSetField = true;
                }
                break;
            case TIFF_SETGET_OTHER:
                /* Transferfunction and Colormap to be inserted here. */
                fprintf(stderr,
                        "Writing of TIFF_SETGET_OTHER for tag %s not supported "
                        "yet.\n",
                        tFieldArray->fields[t].field_name);
                break;
            default:
                fprintf(stderr,
                        "SetFieldType %d not defined within writing switch for "
                        "%s.\n",
                        tSetFieldType, tFieldName);
        }; /*-- switch(tSetFieldType) --*/

        if (deferredSetField)
        {
            /* deferredSetField is used to write fixed arrays and
             * variable arrays.
             * pVoid pointer is set above to the corresponding array and
             * some other parameters like variableArrayCount are set for the
             * field, which is written now.
             */
            if (tWriteCount == 1)
            {
                fprintf(stderr,
                        "WriteCount for .set_get_field_type %d should be -1 or "
                        "greater than 1!  %s\n",
                        tSetFieldType, tFieldArray->fields[t].field_name);
            }
            else
            {
                /*-- Either fix or variable array --*/
                /* Now decide between fixed or variable array */
                if (tWriteCount > 1)
                {
                    /* fixed array with needed arraysize defined in
                     * .field_writecount */
                    if (!TIFFSetField(tif, tTag, pVoid))
                    {
                        fprintf(stderr, "Can't write %s\n",
                                tFieldArray->fields[t].field_name);
                        goto failure;
                    }
                }
                else
                {
                    /*-- Special treatment of variable array --
                     * For test, use always arraysize of
                     * VARIABLE_ARRAY_SIZE, apart a few exceptions,
                     * for which variableArrayCount is set differently above.
                     */
                    if (!TIFFSetField(tif, tTag, variableArrayCount, pVoid))
                    {
                        fprintf(stderr, "Can't write %s\n",
                                tFieldArray->fields[t].field_name);
                        goto failure;
                    }
                }
            }
        }
    } /*-- for() --*/

    *iCnt = i;
    return 0;
failure:
    fprintf(stderr, "\n");
    *iCnt = i;
    return 1;
} /*--- write_all_tags() ---*/

/* ==== write_test_tiff() =============================================
 * Performs write and read test of all tags defined within LibTiff
 * to the opened file passed through "tif".
 * All TIFF, GPS and EXIF tags are written with arbitrary values.
 * Finally, the file is closed, re-opened and all tags are read
 * and compared to their written value.
 */

int write_test_tiff(TIFF *tif, const char *filenameRead)
{
    unsigned char buf[SPP] = {0, 127, 255};
    uint16_t auxUint16 = 0;
    uint32_t auxUint32 = 0;
    int i;

    /*-- Fill test data arrays for writing and later comparison when written
     * tags are checked. */
    for (i = 0; i < N_SIZE; i++)
    {
        sprintf(auxTextArrayW[i],
                "N%d-String-%d_tttttttttttttttttttttttttttttx", i, i);
    }
    for (i = 0; i < N_SIZE; i++)
    {
        auxCharArrayW[i] = (char)(i + 1);
    }
    for (i = 0; i < N_SIZE; i++)
    {
        auxShortArrayW[i] = (short)(i + 1) * 7;
    }
    for (i = 0; i < N_SIZE; i++)
    {
        auxInt32ArrayW[i] = (i + 1) * 133;
    }
    for (i = 0; i < N_SIZE; i++)
    {
        auxFloatArrayW[i] = (float)((i + 1) * 133) / 3.3f;
    }
    for (i = 0; i < N_SIZE; i++)
    {
        auxDoubleArrayW[i] = (double)((i + 1) * 3689) / 4.5697;
    }

    /*-- Setup standard tags of a simple tiff file --*/
    fprintf(stderr, "----Write TIFF tags ...\n");
    if (!TIFFSetField(tif, TIFFTAG_IMAGEWIDTH, width))
    {
        fprintf(stderr, "Can't set ImageWidth tag.\n");
        goto failure;
    }
    if (!TIFFSetField(tif, TIFFTAG_IMAGELENGTH, length))
    {
        fprintf(stderr, "Can't set ImageLength tag.\n");
        goto failure;
    }
    if (!TIFFSetField(tif, TIFFTAG_BITSPERSAMPLE, bps))
    {
        fprintf(stderr, "Can't set BitsPerSample tag.\n");
        goto failure;
    }
    if (!TIFFSetField(tif, TIFFTAG_SAMPLESPERPIXEL, SPP))
    {
        fprintf(stderr, "Can't set SamplesPerPixel tag.\n");
        goto failure;
    }
    if (!TIFFSetField(tif, TIFFTAG_ROWSPERSTRIP, rows_per_strip))
    {
        fprintf(stderr, "Can't set SamplesPerPixel tag.\n");
        goto failure;
    }
    if (!TIFFSetField(tif, TIFFTAG_PLANARCONFIG, planarconfig))
    {
        fprintf(stderr, "Can't set PlanarConfiguration tag.\n");
        goto failure;
    }
    if (!TIFFSetField(tif, TIFFTAG_PHOTOMETRIC, photometric))
    {
        fprintf(stderr, "Can't set PhotometricInterpretation tag.\n");
        goto failure;
    }

    /*============ Write GPS and EXIF Dummy tags =====================*/
    /*-- Set dummy EXIF/GPS tag in original tif-structure in order to reserve
     *   space for final dir_offset value,
     *   which is properly written at the end.
     */
    uint64_t dir_offset = 0; /* Zero, in case no Custom-IFD is written */

    if (!TIFFSetField(tif, TIFFTAG_GPSIFD, dir_offset))
    {
        fprintf(stderr, "Can't write TIFFTAG_GPSIFD\n");
    }

    if (!TIFFSetField(tif, TIFFTAG_EXIFIFD, dir_offset))
    {
        fprintf(stderr, "Can't write TIFFTAG_EXIFIFD\n");
    }

    /*============ Write mostly all other TIFF tags ==================*/
    /* Get array, where tag fields are defined. */
    const TIFFFieldArray *tFieldArray = _TIFFGetFields();

    /*-- write_all_tags() writes all tags automatically with the defined
     *   precision according to its set_get_field_type definition. --*/
    uint32_t iDataCnt = 0;
    if (write_all_tags(tif, tFieldArray, listTagsNotToWrite,
                       NUM_ELEMENTS(listTagsNotToWrite), &iDataCnt))
    {
        fprintf(stderr, "Error during TIFF tag writing.\n");
        goto failure;
    }

#ifndef WRITEPIXELLAST
    /*-- Write dummy pixel data. --*/
    if (TIFFWriteScanline(tif, buf, 0, 0) < 0)
    {
        fprintf(stderr, "Can't write image data.\n");
        goto failure;
    }
#endif

    /*================== Save TIFF Directory =====================*/
    /*-- Save current TIFF-directory to file before directory is changed.
     *   Otherwise it will be lost!
     *   The tif-structure is overwritten/ freshly initialized by any
     *   "CreateDirectory".
     *-----  What is needed here ??? ----
     * In custom_dir.c only 	TIFFFreeDirectory( tif );   is used to set
     * fields of another Sub-Directory. It releases storage associated
     * with a directory, especially custom-fields.
     *-- Using only  TIFFFreeDirectory() here leads to an error!!
     *-- Using here TIFFCheckpointDirectory() leads to an additional Main-IFD
     *   because it does not cleanup the tif-structure.
     *-- TIFFWriteDirectory() does cleanup the tif-structure and tries to
     *   write the IFD to the same location.
     */
    /*retCode = TIFFCheckpointDirectory(tif);*/
    if (!TIFFWriteDirectory(tif))
    {
        fprintf(stderr,
                "Can't write TIFF directory after TIFF tags and image data.\n");
        goto failure;
    }

    /*======================= GPS Directory =============================*/
    /*====== Create GPS Directory and write all GPS fields ==============*/
    /* - Create the GPS directory.
     * - Get GPS field array, where tag fields are defined.
     * - Then write all tags automatically according to their set_get_field_type
     *   definition.
     */
    fprintf(stderr, "----Write GPS tags ...\n");
    if (TIFFCreateGPSDirectory(tif) != 0)
    {
        fprintf(stderr, "TIFFCreateGPSDirectory() failed.\n");
        goto failure;
    }

    tFieldArray = _TIFFGetGpsFields();
    if (write_all_tags(tif, tFieldArray, NULL, 0, &iDataCnt))
    {
        fprintf(stderr, "Error during GPS tag writing.\n");
        goto failure;
    }

    /*-- Re-write a valid GPS version ID --*/
    if (!TIFFSetField(tif, GPSTAG_VERSIONID, gpsVersion))
    {
        fprintf(stderr, "Can't write GPSTAG_VERSIONID\n");
        goto failure;
    }

    /*-- GPS - write custom directory GPS into file and
     *   get back the offset of GPS directory.
     */
    uint64_t dir_offset_GPS = 0;
    if (!TIFFWriteCustomDirectory(tif, &dir_offset_GPS))
    {
        fprintf(stderr, "TIFFWriteCustomDirectory() with GPS failed.\n");
        goto failure;
    }

    /*-- Go back to the first (main) directory, and set correct value of the
     *   GPS IFD pointer. (main directory is reloaded from file!)
     */
    if (!TIFFSetDirectory(tif, 0))
    {
        fprintf(stderr, "TIFFSetDirectory(0) after writing GPS failed.\n");
        goto failure;
    }
    /*-- Write GPS tag reference / offset into GPSIFD tag in main directory --*/
    if (!TIFFSetField(tif, TIFFTAG_GPSIFD, dir_offset_GPS))
    {
        fprintf(stderr, "Can't write TIFFTAG_GPSIFD.\n");
        goto failure;
    }

    /*-- Save current TIFF-directory to file before directory is changed.
     * Otherwise it will be lost! The tif-structure is overwritten/ freshly
     * initialized by any "CreateDirectory".
     * TIFFWriteDirectory() does cleanup tif-structure.
     */
    if (!TIFFWriteDirectory(tif))
    {
        fprintf(stderr, "Can't write TIFF directory after GPS tags.\n");
        goto failure;
    }

    /*======================= EXIF Directory ============================*/
    /*====== Create EXIF Directory and write all EXIF fields ============*/
    /* - Create the EXIF directory.
     * - Get EXIF field array, where tag fields are defined.
     * - Then write all tags automatically according to their set_get_field_type
     *   definition.
     */
    fprintf(stderr, "----Write EXIF tags ...\n");
    if (TIFFCreateEXIFDirectory(tif) != 0)
    {
        fprintf(stderr, "TIFFCreateEXIFDirectory() failed.\n");
        goto failure;
    }

    tFieldArray = _TIFFGetExifFields();
    if (write_all_tags(tif, tFieldArray, listTagsNotToWrite,
                       NUM_ELEMENTS(listTagsNotToWrite), &iDataCnt))
    {
        fprintf(stderr, "Error during GPS tag writing.\n");
        goto failure;
    }

    /*--- Set valid EXIF version, which is a 4 byte string --*/
    if (!TIFFSetField(tif, EXIFTAG_EXIFVERSION, exifVersion))
    {
        fprintf(stderr, "Can't write EXIFTAG_EXIFVERSION\n");
        goto failure;
    }

    /*-- EXIF - write custom directory EXIF into file and
     *   get back the offset of EXIF directory.
     */
    uint64_t dir_offset_EXIF = 0;
    if (!TIFFWriteCustomDirectory(tif, &dir_offset_EXIF))
    {
        fprintf(stderr, "TIFFWriteCustomDirectory() with EXIF failed.\n");
        goto failure;
    }

    /*-- Go back to the first (main) directory, and set correct value of the
     *   EXIF IFD pointer. (main directory is reloaded from file!)
     */
    if (!TIFFSetDirectory(tif, 0))
    {
        fprintf(stderr, "TIFFSetDirectory(0) after writing EXIF failed.\n");
        goto failure;
    }
    /*-- Write EXIF tag reference / offset into EXIFIFD tag in main directory
     * --*/
    if (!TIFFSetField(tif, TIFFTAG_EXIFIFD, dir_offset_EXIF))
    {
        fprintf(stderr, "Can't write TIFFTAG_EXIFIFD.\n");
        goto failure;
    }

#ifdef WRITEPIXELLAST
    /*-- Write dummy pixel data at the end of all directories. --*/
    if (TIFFWriteScanline(tif, buf, 0, 0) < 0)
    {
        fprintf(stderr, "Can't write image data after all directories.\n");
        goto failure;
    }
#endif

    /*================= Close TIFF file  ====================*/
    /* Always TIFFWriteDirectory() before using/creating another directory.
     * Not necessary before TIFFClose(), however, TIFFClose() uses
     * TIFFReWriteDirectory(), which forces directory to be written at another
     * location.
     * Therefore, better use TIFFWriteDirectory() just before TIFFCllose().
     */
    if (!TIFFWriteDirectory(tif))
    {
        fprintf(stderr, "Can't write TIFF directory after EXIF tags.\n");
        goto failure;
    }
    TIFFClose(tif);

    fprintf(stderr, "-------- Continue Test  ---------- reading ...\n");

    /*===========  READING  =============  READING ==========================*/
    /* Ok, now test whether we can read written values correctly. */
    tif = TIFFOpen(filenameRead, "r");
    if (!tif)
    {
        fprintf(stderr, "Can't open test TIFF file %s for reading.\n",
                filenameRead);
        goto failure;
    }

    /*-- Read some special parameters out of the main directory --*/
    if (!TIFFGetField(tif, TIFFTAG_IMAGEWIDTH, &auxUint32))
    {
        fprintf(stderr, "Can't read %s.\n", "TIFFTAG_IMAGEWIDTH");
        goto failure;
    }
    if (auxUint32 != width)
    {
        fprintf(stderr,
                "Read value of IMAGEWIDTH %" PRIu32
                " differs from set value %" PRIu16 ".\n",
                auxUint32, width);
        goto failure;
    }
    if (!TIFFGetField(tif, TIFFTAG_IMAGELENGTH, &auxUint32))
    {
        fprintf(stderr, "Can't read %s.\n", "TIFFTAG_IMAGELENGTH");
        goto failure;
    }
    if (auxUint32 != width)
    {
        fprintf(stderr,
                "Read value of TIFFTAG_IMAGELENGTH %" PRIu32
                " differs from set value %" PRIu16 ".\n",
                auxUint32, length);
        goto failure;
    }

    /* TIFFTAG_NUMBEROFINKS is a special tag, which is automatically set when
     * InkNames string is written. */
    if (!TIFFGetField(tif, TIFFTAG_NUMBEROFINKS, &auxUint16))
    {
        fprintf(stderr, "Can't read %s\n", "TIFFTAG_NUMBEROFINKS");
        goto failure;
    }
    else
    {
        if (auxUint16 != NINKS)
        {
            fprintf(stderr,
                    "Read value of TIFFTAG_NUMBEROFINKS %" PRIu32
                    " differs from set value %" PRIu16 ".\n",
                    auxUint16, NINKS);
            goto failure;
        }
    }

    /*================== Reading all TIFF tags =======================*/
    fprintf(stderr, "----Read TIFF tags ...\n");
    tFieldArray = _TIFFGetFields();
    iDataCnt = 0;
    if (read_all_tags(tif, tFieldArray, listTagsNotToWrite,
                      NUM_ELEMENTS(listTagsNotToWrite), &iDataCnt))
    {
        fprintf(stderr, "Error during TIFF tag reading.\n");
        goto failure;
    }

    /*================== Reading GPS tags ============================*/
    /*-- First get offset to GPS-directory and set it active with
     *   TIFFReadGPSDirectory().
     *   (this will destroy previously main directory fields in memory!)
     */
    uint64_t read_dir_offset = 0;
    fprintf(stderr, "----Read GPS tags ...\n");
    if (!TIFFGetField(tif, TIFFTAG_GPSIFD, &read_dir_offset))
    {
        fprintf(stderr, "Can't read %s\n", "TIFFTAG_GPSIFD");
        goto failure;
    }
    if (!TIFFReadGPSDirectory(tif, read_dir_offset))
    {
        fprintf(stderr, "Can't read %s\n", "TIFFReadGPSDirectory()");
        goto failure;
    }

    /*-- Now read and compare tags from GPS-directory --*/
    tFieldArray = _TIFFGetGpsFields();
    if (read_all_tags(tif, tFieldArray, NULL, 0, &iDataCnt))
    {
        fprintf(stderr, "Error during GPS tag reading.\n");
        goto failure;
    }

    /*================== Reading EXIF tags ===========================*/
    /*-- Go back to the first (main) directory using TIFFSetDirectory(),
     * and then get value of the EXIFIFD directory offset.
     * Then read EXIF directory tags from file into tif-structure.
     * Finally, read and compare tags to the written values.
     */
    TIFFSetDirectory(tif, 0);
    fprintf(stderr, "----Read EXIF tags ...\n");
    if (!TIFFGetField(tif, TIFFTAG_EXIFIFD, &read_dir_offset))
    {
        fprintf(stderr, "Can't read %s\n", "TIFFTAG_EXIFIFD");
        goto failure;
    }

    if (!TIFFReadEXIFDirectory(tif, read_dir_offset))
    {
        fprintf(stderr, "Can't read %s\n", "TIFFReadEXIFDirectory()");
        goto failure;
    }

    tFieldArray = _TIFFGetExifFields();
    if (read_all_tags(tif, tFieldArray, NULL, 0, &iDataCnt))
    {
        fprintf(stderr, "Error during EXIF tag reading.\n");
        goto failure;
    }

    TIFFClose(tif);

    /* All tests passed; delete file and exit with success status. */
#ifdef FOR_AUTO_TESTING
    unlink(filenameRead);
#endif
    fprintf(stderr, "-------- Test finished OK ----------\n");
    return 0;

failure:
    /*
     * Something went wrong; close file and return unsuccessful status.
     * Do not remove the file for further manual investigation.
     */
    TIFFClose(tif);
    fprintf(stderr, "-------- Test finished with FAILURE --------\n");
    return 1;
} /*-- write_test_tiff() --*/

int main(int argc, char **argv)
{
#if !HAVE_DECL_OPTARG
    extern int optind;
    extern char *optarg;
#endif
    uint16_t *pages = NULL, npages = 0, pageNumber;
    int c, dowarnings = 0; /* if 1, enable library warnings */
    TIFF *tif;

    while ((c = getopt(argc, argv, "l:p:x:y:W:H:wSh")) != -1)
        switch (c)
        {
            case 'H': /* page height */
                pageHeight = (float)atof(optarg);
                break;
            case 'S': /* scale to page */
                scaleToPage = 1;
                break;
            case 'W': /* page width */
                pageWidth = (float)atof(optarg);
                break;
            case 'p': /* print specific page */
                pageNumber = (uint16_t)atoi(optarg);
                if (pages)
                    pages = (uint16_t *)realloc(pages, (npages + 1) *
                                                           sizeof(uint16_t));
                else
                    pages = (uint16_t *)malloc(sizeof(uint16_t));
                if (pages == NULL)
                {
                    fprintf(stderr, "Out of memory\n");
                    exit(EXIT_FAILURE);
                }
                pages[npages++] = pageNumber;
                break;
            case 'w':
                dowarnings = 1;
                break;
            case 'x':
                defxres = (float)atof(optarg);
                break;
            case 'y':
                defyres = (float)atof(optarg);
                break;
            case 'l':
                maxline = atoi(optarg);
                break;
            case 'h':
                free(pages);
                usage(EXIT_SUCCESS);
                break;
            case '?':
                free(pages);
                usage(EXIT_FAILURE);
        }
    if (npages > 0)
        qsort(pages, npages, sizeof(uint16_t), pcompar);
    if (!dowarnings)
        TIFFSetWarningHandler(0);
    if (optind < argc)
    {
        do
        {
            tif = TIFFOpen(argv[optind], "r");
            if (tif)
            {
                fax2ps(tif, npages, pages, argv[optind]);
                TIFFClose(tif);
            }
            else
                fprintf(stderr, "%s: Can not open, or not a TIFF file.\n",
                        argv[optind]);
        } while (++optind < argc);
    }
    else
    {
        int n;
        FILE *fd;
        char buf[16 * 1024];

        /* Silence Coverity Scan warning about insecure temporary file name. */
        /* coverity[secure_temp:SUPPRESS] */
        fd = tmpfile();
        if (fd == NULL)
        {
            fprintf(stderr, "Could not obtain temporary file.\n");
            free(pages);
            exit(EXIT_FAILURE);
        }
#if defined(HAVE_SETMODE) && defined(O_BINARY)
        setmode(fileno(stdin), O_BINARY);
#endif
        while ((n = read(fileno(stdin), buf, sizeof(buf))) > 0)
        {
            if (write(fileno(fd), buf, n) != n)
            {
                fclose(fd);
                fprintf(stderr, "Could not copy stdin to temporary file.\n");
                free(pages);
                exit(EXIT_FAILURE);
            }
        }
        _TIFF_lseek_f(fileno(fd), 0, SEEK_SET);
#if defined(_WIN32) && defined(USE_WIN32_FILEIO)
        /* Avoid compiler warnings by using successive casts. */
        tif = TIFFFdOpen((int)(intptr_t)(HANDLE)_get_osfhandle(fileno(fd)),
                         "temp", "r");
#else
        tif = TIFFFdOpen(fileno(fd), "temp", "r");
#endif
        if (tif)
        {
            fax2ps(tif, npages, pages, "<stdin>");
            TIFFClose(tif);
        }
        else
            fprintf(stderr, "Can not open, or not a TIFF file.\n");
        fclose(fd);
    }
    printf("%%%%Trailer\n");
    printf("%%%%Pages: %u\n", totalPages);
    printf("%%%%EOF\n");

    free(pages);
    return (EXIT_SUCCESS);
}

static void pack_words(unsigned char *buf, unsigned int smpls, uint16_t bps)
{
    unsigned int s;
    unsigned int in;
    unsigned int out;
    int bits;
    uint32_t t;

    in = 0;
    out = 0;
    bits = 0;
    t = 0;

    for (s = 0; smpls > s; s++)
    {

        t <<= bps;
        t |= (uint32_t)buf[in++] << 8;
        t |= (uint32_t)buf[in++] << 0;

        bits += bps;

        if (16 <= bits)
        {

            bits -= 16;
            buf[out++] = (t >> (bits + 8));
            buf[out++] = (t >> (bits + 0));
        }
    }
    if (0 != bits)
    {
        t <<= 16 - bits;

        buf[out++] = (t >> (0 + 8));
        buf[out++] = (t >> (0 + 0));
    }
}

static int guessSize(int fd, TIFFDataType dtype, _TIFF_off_t hdr_size,
                     uint32_t nbands, int swab, uint32_t *width,
                     uint32_t *length)
{
    const float longt = 40.0; /* maximum possible height/width ratio */
    char *buf1, *buf2;
    _TIFF_stat_s filestat;
    uint32_t w, h, scanlinesize, imagesize;
    uint32_t depth = TIFFDataWidth(dtype);
    double cor_coef = 0, tmp;

    if (_TIFF_fstat_f(fd, &filestat) == -1)
    {
        fprintf(stderr, "Failed to obtain file size.\n");
        return -1;
    }

    if (filestat.st_size < hdr_size)
    {
        fprintf(stderr, "Too large header size specified.\n");
        return -1;
    }

    if (((filestat.st_size - hdr_size) / nbands / depth) > UINT32_MAX)
    {
        fprintf(stderr, "Too large image size calculated.\n");
        return -1;
    }
    else
        imagesize = (uint32_t)((filestat.st_size - hdr_size) / nbands / depth);

    if (*width != 0 && *length == 0)
    {
        fprintf(stderr, "Image height is not specified.\n");

        *length = imagesize / *width;

        fprintf(stderr, "Height is guessed as %" PRIu32 ".\n", *length);

        return 1;
    }
    else if (*width == 0 && *length != 0)
    {
        fprintf(stderr, "Image width is not specified.\n");

        *width = imagesize / *length;

        fprintf(stderr, "Width is guessed as %" PRIu32 ".\n", *width);

        return 1;
    }
    else if (*width == 0 && *length == 0)
    {
        unsigned int fail = 0;
        fprintf(stderr, "Image width and height are not specified.\n");
        w = (uint32_t)sqrt(imagesize / longt);
        if (w == 0)
        {
            fprintf(stderr, "Too small image size.\n");
            return -1;
        }

        for (; w < sqrt(imagesize * longt); w++)
        {
            if (imagesize % w == 0)
            {
                scanlinesize = w * depth;
                h = imagesize / w;
                if (h < 2)
                    continue;
                /* reads 2 lines at the middle of the image and calculate their
                 * correlation. it works for h >= 2. (in this case it will
                 * compare line 0 and line 1 */
                buf1 = _TIFFmalloc(scanlinesize);
                buf2 = _TIFFmalloc(scanlinesize);
                do
                {
                    if (_TIFF_lseek_f(
                            fd, hdr_size + (int)((h - 1) / 2) * scanlinesize,
                            SEEK_SET) == (_TIFF_off_t)-1)
                    {
                        fprintf(stderr, "seek error.\n");
                        fail = 1;
                        break;
                    }
                    /* read line (h-1)/2 */
                    if (read(fd, buf1, scanlinesize) != (long)scanlinesize)
                    {
                        fprintf(stderr, "read error.\n");
                        fail = 1;
                        break;
                    }
                    /* read line ((h-1)/2)+1 */
                    if (read(fd, buf2, scanlinesize) != (long)scanlinesize)
                    {
                        fprintf(stderr, "read error.\n");
                        fail = 1;
                        break;
                    }
                    if (swab)
                    {
                        swapBytesInScanline(buf1, w, dtype);
                        swapBytesInScanline(buf2, w, dtype);
                    }
                    if (0 == memcmp(buf1, buf2, scanlinesize))
                    {
                        *width = w, *length = h;
                    }
                    else
                    {
                        tmp = fabs(correlation(buf1, buf2, w, dtype));
                        if (tmp > cor_coef)
                        {
                            cor_coef = tmp;
                            *width = w, *length = h;
                        }
                    }
                } while (0);

                _TIFFfree(buf1);
                _TIFFfree(buf2);
            }
        }

        if (fail)
        {
            return -1;
        }

        fprintf(stderr,
                "Width is guessed as %" PRIu32 ", height is guessed as %" PRIu32
                ".\n",
                *width, *length);

        return 1;
    }
    else
    {
        if (filestat.st_size <
            (_TIFF_off_t)(hdr_size + (*width) * (*length) * nbands * depth))
        {
            fprintf(stderr, "Input file too small.\n");
            return -1;
        }
    }

    return 1;
}

int main(int argc, char *argv[])
{
    uint32_t width = 0, length = 0, linebytes, bufsize;
    uint32_t nbands = 1;      /* number of bands in input image*/
    _TIFF_off_t hdr_size = 0; /* size of the header to skip */
    TIFFDataType dtype = TIFF_BYTE;
    int16_t depth = 1;                 /* bytes per pixel in input image */
    int swab = 0;                      /* byte swapping flag */
    InterleavingType interleaving = 0; /* interleaving type flag */
    uint32_t rowsperstrip = (uint32_t)-1;
    uint16_t photometric = PHOTOMETRIC_MINISBLACK;
    uint16_t config = PLANARCONFIG_CONTIG;
    uint16_t fillorder = FILLORDER_LSB2MSB;
    int fd;
    char *outfilename = NULL;
    TIFF *out;
    uint32_t temp_limit_check = 0; /* temp for integer overflow checking*/

    uint32_t row, col, band;
    int c;
    unsigned char *buf = NULL, *buf1 = NULL;
#if !HAVE_DECL_OPTARG
    extern int optind;
    extern char *optarg;
#endif

    while ((c = getopt(argc, argv, "c:r:H:w:l:b:d:LMp:si:o:h")) != -1)
    {
        switch (c)
        {
            case 'c': /* compression scheme */
                if (!processCompressOptions(optarg))
                    usage(EXIT_FAILURE);
                break;
            case 'r': /* rows/strip */
                rowsperstrip = atoi(optarg);
                break;
            case 'H': /* size of input image file header */
                hdr_size = atoi(optarg);
                break;
            case 'w': /* input image width */
                width = atoi(optarg);
                break;
            case 'l': /* input image length */
                length = atoi(optarg);
                break;
            case 'b': /* number of bands in input image */
                nbands = atoi(optarg);
                break;
            case 'd': /* type of samples in input image */
                if (strncmp(optarg, "byte", 4) == 0)
                    dtype = TIFF_BYTE;
                else if (strncmp(optarg, "short", 5) == 0)
                    dtype = TIFF_SHORT;
                else if (strncmp(optarg, "long", 4) == 0)
                    dtype = TIFF_LONG;
                else if (strncmp(optarg, "sbyte", 5) == 0)
                    dtype = TIFF_SBYTE;
                else if (strncmp(optarg, "sshort", 6) == 0)
                    dtype = TIFF_SSHORT;
                else if (strncmp(optarg, "slong", 5) == 0)
                    dtype = TIFF_SLONG;
                else if (strncmp(optarg, "float", 5) == 0)
                    dtype = TIFF_FLOAT;
                else if (strncmp(optarg, "double", 6) == 0)
                    dtype = TIFF_DOUBLE;
                else
                    dtype = TIFF_BYTE;
                depth = TIFFDataWidth(dtype);
                break;
            case 'L': /* input has lsb-to-msb fillorder */
                fillorder = FILLORDER_LSB2MSB;
                break;
            case 'M': /* input has msb-to-lsb fillorder */
                fillorder = FILLORDER_MSB2LSB;
                break;
            case 'p': /* photometric interpretation */
                if (strncmp(optarg, "miniswhite", 10) == 0)
                    photometric = PHOTOMETRIC_MINISWHITE;
                else if (strncmp(optarg, "minisblack", 10) == 0)
                    photometric = PHOTOMETRIC_MINISBLACK;
                else if (strncmp(optarg, "rgb", 3) == 0)
                    photometric = PHOTOMETRIC_RGB;
                else if (strncmp(optarg, "cmyk", 4) == 0)
                    photometric = PHOTOMETRIC_SEPARATED;
                else if (strncmp(optarg, "ycbcr", 5) == 0)
                    photometric = PHOTOMETRIC_YCBCR;
                else if (strncmp(optarg, "cielab", 6) == 0)
                    photometric = PHOTOMETRIC_CIELAB;
                else if (strncmp(optarg, "icclab", 6) == 0)
                    photometric = PHOTOMETRIC_ICCLAB;
                else if (strncmp(optarg, "itulab", 6) == 0)
                    photometric = PHOTOMETRIC_ITULAB;
                else
                    photometric = PHOTOMETRIC_MINISBLACK;
                break;
            case 's': /* do we need to swap bytes? */
                swab = 1;
                break;
            case 'i': /* type of interleaving */
                if (strncmp(optarg, "pixel", 4) == 0)
                    interleaving = PIXEL;
                else if (strncmp(optarg, "band", 6) == 0)
                    interleaving = BAND;
                else
                    interleaving = 0;
                break;
            case 'o':
                outfilename = optarg;
                break;
            case 'h':
                usage(EXIT_SUCCESS);
            default:
                break;
        }
    }

    if (argc - optind < 2)
        usage(EXIT_FAILURE);

    fd = open(argv[optind], O_RDONLY | O_BINARY, 0);
    if (fd < 0)
    {
        fprintf(stderr, "%s: %s: Cannot open input file.\n", argv[0],
                argv[optind]);
        return (EXIT_FAILURE);
    }

    if (nbands == 0)
    {
        fprintf(stderr, "The number of bands is illegal.\n");
        close(fd);
        return (-1);
    }

    if (guessSize(fd, dtype, hdr_size, nbands, swab, &width, &length) < 0)
    {
        close(fd);
        return EXIT_FAILURE;
    }

    /* check for integer overflow in */
    /* hdr_size + (*width) * (*length) * nbands * depth */

    if ((width == 0) || (length == 0))
    {
        fprintf(stderr, "Too large nbands value specified.\n");
        close(fd);
        return (EXIT_FAILURE);
    }

    temp_limit_check = nbands * depth;

    if (!temp_limit_check || length > (UINT_MAX / temp_limit_check))
    {
        fprintf(stderr, "Too large length size specified.\n");
        close(fd);
        return (EXIT_FAILURE);
    }
    temp_limit_check = temp_limit_check * length;

    if (!temp_limit_check || width > (UINT_MAX / temp_limit_check))
    {
        fprintf(stderr, "Too large width size specified.\n");
        close(fd);
        return (EXIT_FAILURE);
    }
    temp_limit_check = temp_limit_check * width;

    if (!temp_limit_check || hdr_size > (UINT_MAX - temp_limit_check))
    {
        fprintf(stderr, "Too large header size specified.\n");
        close(fd);
        return (EXIT_FAILURE);
    }

    if (outfilename == NULL)
        outfilename = argv[optind + 1];
    out = TIFFOpen(outfilename, "w");
    if (out == NULL)
    {
        fprintf(stderr, "%s: %s: Cannot open file for output.\n", argv[0],
                outfilename);
        close(fd);
        return (EXIT_FAILURE);
    }
    TIFFSetField(out, TIFFTAG_IMAGEWIDTH, width);
    TIFFSetField(out, TIFFTAG_IMAGELENGTH, length);
    TIFFSetField(out, TIFFTAG_ORIENTATION, ORIENTATION_TOPLEFT);
    TIFFSetField(out, TIFFTAG_SAMPLESPERPIXEL, nbands);
    TIFFSetField(out, TIFFTAG_BITSPERSAMPLE, depth * 8);
    TIFFSetField(out, TIFFTAG_FILLORDER, fillorder);
    TIFFSetField(out, TIFFTAG_PLANARCONFIG, config);
    TIFFSetField(out, TIFFTAG_PHOTOMETRIC, photometric);
    switch (dtype)
    {
        case TIFF_BYTE:
        case TIFF_SHORT:
        case TIFF_LONG:
            TIFFSetField(out, TIFFTAG_SAMPLEFORMAT, SAMPLEFORMAT_UINT);
            break;
        case TIFF_SBYTE:
        case TIFF_SSHORT:
        case TIFF_SLONG:
            TIFFSetField(out, TIFFTAG_SAMPLEFORMAT, SAMPLEFORMAT_INT);
            break;
        case TIFF_FLOAT:
        case TIFF_DOUBLE:
            TIFFSetField(out, TIFFTAG_SAMPLEFORMAT, SAMPLEFORMAT_IEEEFP);
            break;
        default:
            TIFFSetField(out, TIFFTAG_SAMPLEFORMAT, SAMPLEFORMAT_VOID);
            break;
    }
    if (compression == (uint16_t)-1)
        compression = COMPRESSION_PACKBITS;
    TIFFSetField(out, TIFFTAG_COMPRESSION, compression);
    switch (compression)
    {
        case COMPRESSION_JPEG:
            if (photometric == PHOTOMETRIC_RGB &&
                jpegcolormode == JPEGCOLORMODE_RGB)
                photometric = PHOTOMETRIC_YCBCR;
            TIFFSetField(out, TIFFTAG_JPEGQUALITY, quality);
            TIFFSetField(out, TIFFTAG_JPEGCOLORMODE, jpegcolormode);
            break;
        case COMPRESSION_LZW:
        case COMPRESSION_ADOBE_DEFLATE:
        case COMPRESSION_DEFLATE:
            if (predictor != 0)
                TIFFSetField(out, TIFFTAG_PREDICTOR, predictor);
            break;
    }
    switch (interleaving)
    {
        case BAND: /* band interleaved data */
            linebytes = width * depth;
            buf = (unsigned char *)_TIFFmalloc(linebytes);
            break;
        case PIXEL: /* pixel interleaved data */
        default:
            linebytes = width * nbands * depth;
            break;
    }
    bufsize = width * nbands * depth;
    buf1 = (unsigned char *)_TIFFmalloc(bufsize);

    rowsperstrip = TIFFDefaultStripSize(out, rowsperstrip);
    if (rowsperstrip > length)
    {
        rowsperstrip = length;
    }
    TIFFSetField(out, TIFFTAG_ROWSPERSTRIP, rowsperstrip);

    _TIFF_lseek_f(fd, hdr_size, SEEK_SET); /* Skip the file header */
    for (row = 0; row < length; row++)
    {
        switch (interleaving)
        {
            case BAND: /* band interleaved data */
                for (band = 0; band < nbands; band++)
                {
                    if (_TIFF_lseek_f(
                            fd, hdr_size + (length * band + row) * linebytes,
                            SEEK_SET) == (_TIFF_off_t)-1)
                    {
                        fprintf(stderr,
                                "%s: %s: scanline %" PRIu32 ": seek error.\n",
                                argv[0], argv[optind], row);
                        break;
                    }
                    if (read(fd, buf, linebytes) < 0)
                    {
                        fprintf(stderr,
                                "%s: %s: scanline %" PRIu32 ": Read error.\n",
                                argv[0], argv[optind], row);
                        break;
                    }
                    if (swab) /* Swap bytes if needed */
                        swapBytesInScanline(buf, width, dtype);
                    for (col = 0; col < width; col++)
                        memcpy(buf1 + (col * nbands + band) * depth,
                               buf + col * depth, depth);
                }
                break;
            case PIXEL: /* pixel interleaved data */
            default:
                if (read(fd, buf1, bufsize) < 0)
                {
                    fprintf(stderr,
                            "%s: %s: scanline %" PRIu32 ": Read error.\n",
                            argv[0], argv[optind], row);
                    break;
                }
                if (swab) /* Swap bytes if needed */
                    swapBytesInScanline(buf1, width, dtype);
                break;
        }

        if (TIFFWriteScanline(out, buf1, row, 0) < 0)
        {
            fprintf(stderr, "%s: %s: scanline %" PRIu32 ": Write error.\n",
                    argv[0], outfilename, row);
            break;
        }
    }
    if (buf)
        _TIFFfree(buf);
    if (buf1)
        _TIFFfree(buf1);
    TIFFClose(out);
    close(fd);
    return (EXIT_SUCCESS);
}

static int tiffcvt(TIFF *in, TIFF *out)
{
    uint32_t width, height; /* image width & height */
    uint32_t *raster;       /* retrieve RGBA image */
    uint16_t shortv;
    float floatv;
    char *stringv;
    uint32_t longv;
    int result;
    size_t pixel_count;

    TIFFGetField(in, TIFFTAG_IMAGEWIDTH, &width);
    TIFFGetField(in, TIFFTAG_IMAGELENGTH, &height);
    pixel_count = width * height;

    /* XXX: Check the integer overflow. */
    if (!width || !height || SIZE_MAX / width < height)
    {
        TIFFError(TIFFFileName(in),
                  "Malformed input file; "
                  "can't allocate buffer for raster of %" PRIu32 "x%" PRIu32
                  " size",
                  width, height);
        return 0;
    }

    raster = (uint32_t *)_TIFFCheckMalloc(in, pixel_count, sizeof(uint32_t),
                                          "raster buffer");
    if (raster == 0)
    {
        TIFFError(TIFFFileName(in),
                  "Failed to allocate buffer (%" TIFF_SIZE_FORMAT
                  " elements of %" TIFF_SIZE_FORMAT " each)",
                  pixel_count, sizeof(uint32_t));
        return (0);
    }

    if (!TIFFReadRGBAImage(in, width, height, raster, 0))
    {
        _TIFFfree(raster);
        return (0);
    }

    CopyField(TIFFTAG_SUBFILETYPE, longv);
    TIFFSetField(out, TIFFTAG_IMAGEWIDTH, width);
    TIFFSetField(out, TIFFTAG_IMAGELENGTH, height);
    TIFFSetField(out, TIFFTAG_BITSPERSAMPLE, 8);
    TIFFSetField(out, TIFFTAG_COMPRESSION, compression);
    TIFFSetField(out, TIFFTAG_PHOTOMETRIC, PHOTOMETRIC_YCBCR);
    if (compression == COMPRESSION_JPEG)
        TIFFSetField(out, TIFFTAG_JPEGCOLORMODE, JPEGCOLORMODE_RAW);
    CopyField(TIFFTAG_FILLORDER, shortv);
    TIFFSetField(out, TIFFTAG_ORIENTATION, ORIENTATION_TOPLEFT);
    TIFFSetField(out, TIFFTAG_SAMPLESPERPIXEL, 3);
    CopyField(TIFFTAG_XRESOLUTION, floatv);
    CopyField(TIFFTAG_YRESOLUTION, floatv);
    CopyField(TIFFTAG_RESOLUTIONUNIT, shortv);
    TIFFSetField(out, TIFFTAG_PLANARCONFIG, PLANARCONFIG_CONTIG);
    {
        char buf[2048];
        char *cp = strrchr(TIFFFileName(in), '/');
        snprintf(buf, sizeof(buf), "YCbCr conversion of %s",
                 cp ? cp + 1 : TIFFFileName(in));
        TIFFSetField(out, TIFFTAG_IMAGEDESCRIPTION, buf);
    }
    TIFFSetField(out, TIFFTAG_SOFTWARE, TIFFGetVersion());
    CopyField(TIFFTAG_DOCUMENTNAME, stringv);

    TIFFSetField(out, TIFFTAG_REFERENCEBLACKWHITE, refBlackWhite);
    TIFFSetField(out, TIFFTAG_YCBCRSUBSAMPLING, horizSubSampling,
                 vertSubSampling);
    TIFFSetField(out, TIFFTAG_YCBCRPOSITIONING, YCBCRPOSITION_CENTERED);
    TIFFSetField(out, TIFFTAG_YCBCRCOEFFICIENTS, ycbcrCoeffs);
    rowsperstrip = TIFFDefaultStripSize(out, rowsperstrip);
    TIFFSetField(out, TIFFTAG_ROWSPERSTRIP, rowsperstrip);

    result = cvtRaster(out, raster, width, height);
    _TIFFfree(raster);
    return result;
}

static void setrow(uint8_t *row, uint32_t nrows, const uint8_t *rows[])
{
    uint32_t x;
    uint32_t area = nrows * filterWidth;
    for (x = 0; x < tnw; x++)
    {
        uint32_t mask0 = src0[x];
        uint32_t fw = src1[x];
        uint32_t mask1 = src1[x];
        uint32_t off = rowoff[x];
        uint32_t acc = 0;
        uint32_t y, i;
        for (y = 0; y < nrows; y++)
        {
            const uint8_t *src = rows[y] + off;
            acc += bits[*src++ & mask0];
            switch (fw)
            {
                default:
                    for (i = fw; i > 8; i--)
                        acc += bits[*src++];
                    /* fall through... */
                case 8:
                    acc += bits[*src++]; /* fall through */
                case 7:
                    acc += bits[*src++]; /* fall through */
                case 6:
                    acc += bits[*src++]; /* fall through */
                case 5:
                    acc += bits[*src++]; /* fall through */
                case 4:
                    acc += bits[*src++]; /* fall through */
                case 3:
                    acc += bits[*src++]; /* fall through */
                case 2:
                    acc += bits[*src++]; /* fall through */
                case 1:
                    acc += bits[*src++]; /* fall through */
                case 0:
                    break;
            }
            acc += bits[*src & mask1];
        }
        if (255 * acc / area < 256)
        {
            *row++ = cmap[(255 * acc) / area];
        }
        else
        {
            fprintf(stderr, "acc=%d, area=%d\n", acc, area);
            *row++ = cmap[0];
        }
    }
}

static uint32_t _TIFFCastSSizeToUInt32(tmsize_t val, const char *module)
{
    if (val < 0)
    {
        TIFFError(module, "Unsigned integer underflow (negative)");
        return 0;
    }
    /* sizeof(tmsize_t) is determined by SIZEOF_SIZE_T */
#ifdef SIZEOF_SIZE_T
#if SIZEOF_SIZE_T > 4
    if (val > UINT32_MAX)
    {
        TIFFError(module, "Integer overflow");
        return 0;
    }
#endif
#else
#pragma message(                                                               \
    "---- Error: SIZEOF_SIZE_T not defined. Generate a compile error. ----")
    SIZEOF_SIZE_T
#endif
    return (uint32_t)val;
}

void t2p_read_tiff_init(T2P *t2p, TIFF *input)
{

    tdir_t directorycount = 0;
    tdir_t i = 0;
    uint16_t pagen = 0;
    uint16_t paged = 0;
    uint16_t xuint16 = 0;
    uint16_t tiff_transferfunctioncount = 0;
    uint16_t *tiff_transferfunction[3];

    directorycount = TIFFNumberOfDirectories(input);
    if (directorycount > TIFF_DIR_MAX)
    {
        TIFFError(TIFF2PDF_MODULE, "TIFF contains too many directories, %s",
                  TIFFFileName(input));
        t2p->t2p_error = T2P_ERR_ERROR;
        return;
    }
    t2p->tiff_pages = (T2P_PAGE *)_TIFFmalloc(
        TIFFSafeMultiply(tmsize_t, directorycount, sizeof(T2P_PAGE)));
    if (t2p->tiff_pages == NULL)
    {
        TIFFError(TIFF2PDF_MODULE,
                  "Can't allocate %" TIFF_SIZE_FORMAT
                  " bytes of memory for tiff_pages array, %s",
                  sizeof(T2P_PAGE) * directorycount, TIFFFileName(input));
        t2p->t2p_error = T2P_ERR_ERROR;
        return;
    }
    _TIFFmemset(t2p->tiff_pages, 0x00, directorycount * sizeof(T2P_PAGE));
    t2p->tiff_tiles = (T2P_TILES *)_TIFFmalloc(
        TIFFSafeMultiply(tmsize_t, directorycount, sizeof(T2P_TILES)));
    if (t2p->tiff_tiles == NULL)
    {
        TIFFError(TIFF2PDF_MODULE,
                  "Can't allocate %" TIFF_SIZE_FORMAT
                  " bytes of memory for tiff_tiles array, %s",
                  sizeof(T2P_TILES) * directorycount, TIFFFileName(input));
        t2p->t2p_error = T2P_ERR_ERROR;
        return;
    }
    _TIFFmemset(t2p->tiff_tiles, 0x00, directorycount * sizeof(T2P_TILES));
    for (i = 0; i < directorycount; i++)
    {
        uint32_t subfiletype = 0;

        if (!TIFFSetDirectory(input, i))
        {
            TIFFError(TIFF2PDF_MODULE,
                      "Can't set directory %" PRIu16 " of input file %s", i,
                      TIFFFileName(input));
            t2p->t2p_error = T2P_ERR_ERROR;
            return;
        }
        if (TIFFGetField(input, TIFFTAG_PAGENUMBER, &pagen, &paged))
        {
            if ((pagen > paged) && (paged != 0))
            {
                t2p->tiff_pages[t2p->tiff_pagecount].page_number = paged;
            }
            else
            {
                t2p->tiff_pages[t2p->tiff_pagecount].page_number = pagen;
            }
            goto ispage2;
        }
        if (TIFFGetField(input, TIFFTAG_SUBFILETYPE, &subfiletype))
        {
            if (((subfiletype & FILETYPE_PAGE) != 0) || (subfiletype == 0))
            {
                goto ispage;
            }
            else
            {
                goto isnotpage;
            }
        }
        if (TIFFGetField(input, TIFFTAG_OSUBFILETYPE, &subfiletype))
        {
            if ((subfiletype == OFILETYPE_IMAGE) ||
                (subfiletype == OFILETYPE_PAGE) || (subfiletype == 0))
            {
                goto ispage;
            }
            else
            {
                goto isnotpage;
            }
        }
    ispage:
        t2p->tiff_pages[t2p->tiff_pagecount].page_number = t2p->tiff_pagecount;
    ispage2:
        t2p->tiff_pages[t2p->tiff_pagecount].page_directory = i;
        if (TIFFIsTiled(input))
        {
            t2p->tiff_pages[t2p->tiff_pagecount].page_tilecount =
                TIFFNumberOfTiles(input);
        }
        t2p->tiff_pagecount++;
    isnotpage:
        (void)0;
    }

    qsort((void *)t2p->tiff_pages, t2p->tiff_pagecount, sizeof(T2P_PAGE),
          t2p_cmp_t2p_page);

    for (i = 0; i < t2p->tiff_pagecount; i++)
    {
        t2p->pdf_xrefcount += 5;
        TIFFSetDirectory(input, t2p->tiff_pages[i].page_directory);
        if ((TIFFGetField(input, TIFFTAG_PHOTOMETRIC, &xuint16) &&
             (xuint16 == PHOTOMETRIC_PALETTE)) ||
            TIFFGetField(input, TIFFTAG_INDEXED, &xuint16))
        {
            t2p->tiff_pages[i].page_extra++;
            t2p->pdf_xrefcount++;
        }
#ifdef ZIP_SUPPORT
        if (TIFFGetField(input, TIFFTAG_COMPRESSION, &xuint16))
        {
            if ((xuint16 == COMPRESSION_DEFLATE ||
                 xuint16 == COMPRESSION_ADOBE_DEFLATE) &&
                ((t2p->tiff_pages[i].page_tilecount != 0) ||
                 TIFFNumberOfStrips(input) == 1) &&
                (t2p->pdf_nopassthrough == 0))
            {
                if (t2p->pdf_minorversion < 2)
                {
                    t2p->pdf_minorversion = 2;
                }
            }
        }
#endif
        if (TIFFGetField(
                input, TIFFTAG_TRANSFERFUNCTION, &(tiff_transferfunction[0]),
                &(tiff_transferfunction[1]), &(tiff_transferfunction[2])))
        {

            if ((tiff_transferfunction[1] != (uint16_t *)NULL) &&
                (tiff_transferfunction[2] != (uint16_t *)NULL))
            {
                tiff_transferfunctioncount = 3;
            }
            else
            {
                tiff_transferfunctioncount = 1;
            }
        }
        else
        {
            tiff_transferfunctioncount = 0;
        }

        if (i > 0)
        {
            if (tiff_transferfunctioncount != t2p->tiff_transferfunctioncount)
            {
                TIFFError(TIFF2PDF_MODULE,
                          "Different transfer function on page %" PRIu16, i);
                t2p->t2p_error = T2P_ERR_ERROR;
                return;
            }
        }

        t2p->tiff_transferfunctioncount = tiff_transferfunctioncount;
        t2p->tiff_transferfunction[0] = tiff_transferfunction[0];
        t2p->tiff_transferfunction[1] = tiff_transferfunction[1];
        t2p->tiff_transferfunction[2] = tiff_transferfunction[2];
        if (tiff_transferfunctioncount == 3)
        {
            t2p->tiff_pages[i].page_extra += 4;
            t2p->pdf_xrefcount += 4;
            if (t2p->pdf_minorversion < 2)
                t2p->pdf_minorversion = 2;
        }
        else if (tiff_transferfunctioncount == 1)
        {
            t2p->tiff_pages[i].page_extra += 2;
            t2p->pdf_xrefcount += 2;
            if (t2p->pdf_minorversion < 2)
                t2p->pdf_minorversion = 2;
        }

        if (TIFFGetField(input, TIFFTAG_ICCPROFILE,
                         &(t2p->tiff_iccprofilelength),
                         &(t2p->tiff_iccprofile)) != 0)
        {
            t2p->tiff_pages[i].page_extra++;
            t2p->pdf_xrefcount++;
            if (t2p->pdf_minorversion < 3)
            {
                t2p->pdf_minorversion = 3;
            }
        }
        t2p->tiff_tiles[i].tiles_tilecount = t2p->tiff_pages[i].page_tilecount;
        if ((TIFFGetField(input, TIFFTAG_PLANARCONFIG, &xuint16) != 0) &&
            (xuint16 == PLANARCONFIG_SEPARATE))
        {
            if (!TIFFGetField(input, TIFFTAG_SAMPLESPERPIXEL, &xuint16))
            {
                TIFFError(TIFF2PDF_MODULE, "Missing SamplesPerPixel, %s",
                          TIFFFileName(input));
                t2p->t2p_error = T2P_ERR_ERROR;
                return;
            }
            if ((t2p->tiff_tiles[i].tiles_tilecount % xuint16) != 0)
            {
                TIFFError(TIFF2PDF_MODULE, "Invalid tile count, %s",
                          TIFFFileName(input));
                t2p->t2p_error = T2P_ERR_ERROR;
                return;
            }
            t2p->tiff_tiles[i].tiles_tilecount /= xuint16;
        }
        if (t2p->tiff_tiles[i].tiles_tilecount > 0)
        {
            t2p->pdf_xrefcount += (t2p->tiff_tiles[i].tiles_tilecount - 1) * 2;
            TIFFGetField(input, TIFFTAG_TILEWIDTH,
                         &(t2p->tiff_tiles[i].tiles_tilewidth));
            if (t2p->tiff_tiles[i].tiles_tilewidth < 1)
            {
                TIFFError(TIFF2PDF_MODULE, "Invalid tile width (%d), %s",
                          t2p->tiff_tiles[i].tiles_tilewidth,
                          TIFFFileName(input));
                t2p->t2p_error = T2P_ERR_ERROR;
                return;
            }
            TIFFGetField(input, TIFFTAG_TILELENGTH,
                         &(t2p->tiff_tiles[i].tiles_tilelength));
            if (t2p->tiff_tiles[i].tiles_tilelength < 1)
            {
                TIFFError(TIFF2PDF_MODULE, "Invalid tile length (%d), %s",
                          t2p->tiff_tiles[i].tiles_tilelength,
                          TIFFFileName(input));
                t2p->t2p_error = T2P_ERR_ERROR;
                return;
            }
            t2p->tiff_tiles[i].tiles_tiles = (T2P_TILE *)_TIFFmalloc(
                TIFFSafeMultiply(tmsize_t, t2p->tiff_tiles[i].tiles_tilecount,
                                 sizeof(T2P_TILE)));
            if (t2p->tiff_tiles[i].tiles_tiles == NULL)
            {
                TIFFError(TIFF2PDF_MODULE,
                          "Can't allocate %" TIFF_SIZE_FORMAT
                          " bytes of memory for t2p_read_tiff_init, %s",
                          sizeof(T2P_TILE) * t2p->tiff_tiles[i].tiles_tilecount,
                          TIFFFileName(input));
                t2p->t2p_error = T2P_ERR_ERROR;
                return;
            }
        }
    }

    return;
}

void t2p_read_tiff_size(T2P *t2p, TIFF *input)
{

    uint64_t *sbc = NULL;
#if defined(JPEG_SUPPORT) || defined(OJPEG_SUPPORT)
    unsigned char *jpt = NULL;
    tstrip_t i = 0;
    tstrip_t stripcount = 0;
#endif
    uint64_t k = 0;

    if (t2p->pdf_transcode == T2P_TRANSCODE_RAW)
    {
#if defined(CCITT_SUPPORT) || defined(ZIP_SUPPORT)
#if defined(CCITT_SUPPORT) && defined(ZIP_SUPPORT)
        if (t2p->pdf_compression == T2P_COMPRESS_G4 ||
            t2p->pdf_compression == T2P_COMPRESS_ZIP)
#elif defined(CCITT_SUPPORT)
        if (t2p->pdf_compression == T2P_COMPRESS_G4)
#else
        if (t2p->pdf_compression == T2P_COMPRESS_ZIP)
#endif
        {
            if (!TIFFGetField(input, TIFFTAG_STRIPBYTECOUNTS, &sbc))
            {
                TIFFError(
                    TIFF2PDF_MODULE,
                    "Input file %s missing field: TIFFTAG_STRIPBYTECOUNTS",
                    TIFFFileName(input));
                t2p->t2p_error = T2P_ERR_ERROR;
                return;
            }
            t2p_set_tiff_datasize(t2p, sbc[0]);
            return;
        }
#endif
#ifdef OJPEG_SUPPORT
        if (t2p->tiff_compression == COMPRESSION_OJPEG)
        {
            if (!TIFFGetField(input, TIFFTAG_STRIPBYTECOUNTS, &sbc))
            {
                TIFFError(
                    TIFF2PDF_MODULE,
                    "Input file %s missing field: TIFFTAG_STRIPBYTECOUNTS",
                    TIFFFileName(input));
                t2p->t2p_error = T2P_ERR_ERROR;
                return;
            }
            stripcount = TIFFNumberOfStrips(input);
            for (i = 0; i < stripcount; i++)
            {
                k = checkAdd64(k, sbc[i], t2p);
            }
            if (TIFFGetField(input, TIFFTAG_JPEGIFOFFSET,
                             &(t2p->tiff_dataoffset)))
            {
                if (t2p->tiff_dataoffset != 0)
                {
                    if (TIFFGetField(input, TIFFTAG_JPEGIFBYTECOUNT,
                                     &(t2p->tiff_datasize)) != 0)
                    {
                        if ((uint64_t)t2p->tiff_datasize < k)
                        {
                            TIFFWarning(TIFF2PDF_MODULE,
                                        "Input file %s has short JPEG "
                                        "interchange file byte count",
                                        TIFFFileName(input));
                            t2p->pdf_ojpegiflength = _TIFFCastSSizeToUInt32(
                                t2p->tiff_datasize, "t2p_read_tiff_size");
                            k = checkAdd64(k, t2p->tiff_datasize, t2p);
                            k = checkAdd64(k, 6, t2p);
                            k = checkAdd64(k, stripcount, t2p);
                            k = checkAdd64(k, stripcount, t2p);
                            t2p_set_tiff_datasize(t2p, k);
                            return;
                        }
                        return;
                    }
                    else
                    {
                        TIFFError(TIFF2PDF_MODULE,
                                  "Input file %s missing field: "
                                  "TIFFTAG_JPEGIFBYTECOUNT",
                                  TIFFFileName(input));
                        t2p->t2p_error = T2P_ERR_ERROR;
                        return;
                    }
                }
            }
            k = checkAdd64(k, stripcount, t2p);
            k = checkAdd64(k, stripcount, t2p);
            k = checkAdd64(k, 2048, t2p);
            t2p_set_tiff_datasize(t2p, k);
            return;
        }
#endif
#ifdef JPEG_SUPPORT
        if (t2p->tiff_compression == COMPRESSION_JPEG)
        {
            uint32_t count = 0;
            if (TIFFGetField(input, TIFFTAG_JPEGTABLES, &count, &jpt) != 0)
            {
                if (count > 4)
                {
                    k += count;
                    k -= 2; /* don't use EOI of header */
                }
            }
            else
            {
                k = 2; /* SOI for first strip */
            }
            stripcount = TIFFNumberOfStrips(input);
            if (!TIFFGetField(input, TIFFTAG_STRIPBYTECOUNTS, &sbc))
            {
                TIFFError(
                    TIFF2PDF_MODULE,
                    "Input file %s missing field: TIFFTAG_STRIPBYTECOUNTS",
                    TIFFFileName(input));
                t2p->t2p_error = T2P_ERR_ERROR;
                return;
            }
            for (i = 0; i < stripcount; i++)
            {
                k = checkAdd64(k, sbc[i], t2p);
                /* Keep next two comments just for information: */
                /* k -= 2; don't use EOI of strip */
                /* k += 2; add space for restart marker */
            }
            k = checkAdd64(k, 2, t2p); /* use EOI of last strip */
            t2p_set_tiff_datasize(t2p, k);
            return;
        }
#endif
        (void)0;
    }
#ifdef JPEG_SUPPORT
    if (t2p->pdf_compression == T2P_COMPRESS_JPEG &&
        t2p->tiff_photometric == PHOTOMETRIC_YCBCR)
    {
        k = checkMultiply64(TIFFNumberOfStrips(input), TIFFStripSize(input),
                            t2p);
    }
    else
#endif
    {
        k = checkMultiply64(TIFFScanlineSize(input), t2p->tiff_length, t2p);
        if (t2p->tiff_planar == PLANARCONFIG_SEPARATE)
        {
            k = checkMultiply64(k, t2p->tiff_samplesperpixel, t2p);
        }
    }
    if (k == 0)
    {
        /* Assume we had overflow inside TIFFScanlineSize */
        t2p->t2p_error = T2P_ERR_ERROR;
    }

    t2p_set_tiff_datasize(t2p, k);

    return;
}

void t2p_read_tiff_size_tile(T2P *t2p, TIFF *input, ttile_t tile)
{

    uint64_t *tbc = NULL;
    uint16_t edge = 0;
#ifdef JPEG_SUPPORT
    unsigned char *jpt;
#endif
    uint64_t k;

    edge |= t2p_tile_is_right_edge(t2p->tiff_tiles[t2p->pdf_page], tile);
    edge |= t2p_tile_is_bottom_edge(t2p->tiff_tiles[t2p->pdf_page], tile);

    if (t2p->pdf_transcode == T2P_TRANSCODE_RAW)
    {
        if (edge
#if defined(JPEG_SUPPORT) || defined(OJPEG_SUPPORT)
            && !(t2p->pdf_compression == T2P_COMPRESS_JPEG)
#endif
        )
        {
            t2p->tiff_datasize = TIFFTileSize(input);
            if (t2p->tiff_datasize == 0)
            {
                /* Assume we had overflow inside TIFFTileSize */
                t2p->t2p_error = T2P_ERR_ERROR;
            }
            return;
        }
        else
        {
            TIFFGetField(input, TIFFTAG_TILEBYTECOUNTS, &tbc);
            if (!tbc)
            {
                t2p->t2p_error = T2P_ERR_ERROR;
                t2p_set_tiff_datasize(t2p, 0);
                return;
            }
            k = tbc[tile];
#ifdef OJPEG_SUPPORT
            if (t2p->tiff_compression == COMPRESSION_OJPEG)
            {
                k = checkAdd64(k, 2048, t2p);
            }
#endif
#ifdef JPEG_SUPPORT
            if (t2p->tiff_compression == COMPRESSION_JPEG)
            {
                uint32_t count = 0;
                if (TIFFGetField(input, TIFFTAG_JPEGTABLES, &count, &jpt) != 0)
                {
                    if (count > 4)
                    {
                        k = checkAdd64(k, count, t2p);
                        /* Coverity Scan false positive because here k>4 */
                        /* coverity[overflow_const:FALSE] */
                        k -= 2; /* don't use EOI of header or SOI of tile */
                    }
                }
            }
#endif
            t2p_set_tiff_datasize(t2p, k);
            return;
        }
    }
    k = TIFFTileSize(input);
    if (t2p->tiff_planar == PLANARCONFIG_SEPARATE)
    {
        k = checkMultiply64(k, t2p->tiff_samplesperpixel, t2p);
    }
    if (k == 0)
    {
        /* Assume we had overflow inside TIFFTileSize */
        t2p->t2p_error = T2P_ERR_ERROR;
    }

    t2p_set_tiff_datasize(t2p, k);

    return;
}

tsize_t t2p_readwrite_pdf_image(T2P *t2p, TIFF *input, TIFF *output)
{

    tsize_t written = 0;
    unsigned char *buffer = NULL;
    unsigned char *samplebuffer = NULL;
    tsize_t bufferoffset = 0;
    tsize_t samplebufferoffset = 0;
    tsize_t read = 0;
    tstrip_t i = 0;
    tstrip_t j = 0;
    tstrip_t stripcount = 0;
    tsize_t stripsize = 0;
    tsize_t sepstripcount = 0;
    tsize_t sepstripsize = 0;
#ifdef OJPEG_SUPPORT
    toff_t inputoffset = 0;
    uint16_t h_samp = 1;
    uint16_t v_samp = 1;
    uint16_t ri = 1;
    uint32_t rows = 0;
#endif /* ifdef OJPEG_SUPPORT */
#ifdef JPEG_SUPPORT
    unsigned char *jpt;
    float *xfloatp;
    uint64_t *sbc;
    unsigned char *stripbuffer;
    tsize_t striplength = 0;
    uint64_t max_striplength = 0;
#endif /* ifdef JPEG_SUPPORT */
    const char mod[] = "t2p_readwrite_pdf_image()";
    tsize_t tsdummy = 0;

    /* Fail if prior error (in particular, can't trust tiff_datasize) */
    if (t2p->t2p_error != T2P_ERR_OK)
        return (0);

    if (t2p->pdf_transcode == T2P_TRANSCODE_RAW)
    {
#ifdef CCITT_SUPPORT
        if (t2p->pdf_compression == T2P_COMPRESS_G4)
        {
            buffer = (unsigned char *)_TIFFmalloc(t2p->tiff_datasize);
            if (buffer == NULL)
            {
                TIFFError(TIFF2PDF_MODULE,
                          "Can't allocate %" TIFF_SSIZE_FORMAT
                          " bytes of memory for "
                          "t2p_readwrite_pdf_image, %s",
                          t2p->tiff_datasize, TIFFFileName(input));
                t2p->t2p_error = T2P_ERR_ERROR;
                return (0);
            }
            memset(buffer, 0, t2p->tiff_datasize);
            if (TIFFReadRawStrip(input, 0, (tdata_t)buffer,
                                 t2p->tiff_datasize) < 0)
            {
                TIFFError(TIFF2PDF_MODULE, "TIFFReadRawStrip() failed");
                _TIFFfree(buffer);
                return (0);
            }
            if (t2p->tiff_fillorder == FILLORDER_LSB2MSB)
            {
                /*
                 * make sure is lsb-to-msb
                 * bit-endianness fill order
                 */
                TIFFReverseBits(buffer, t2p->tiff_datasize);
            }
            add_t2pWriteFile_check(output, (tdata_t)buffer, t2p->tiff_datasize,
                                   mod, tsdummy);
            _TIFFfree(buffer);
            return (t2p->tiff_datasize);
        }
#endif /* ifdef CCITT_SUPPORT */
#ifdef ZIP_SUPPORT
        if (t2p->pdf_compression == T2P_COMPRESS_ZIP)
        {
            buffer = (unsigned char *)_TIFFmalloc(t2p->tiff_datasize);
            if (buffer == NULL)
            {
                TIFFError(TIFF2PDF_MODULE,
                          "Can't allocate %" TIFF_SSIZE_FORMAT
                          " bytes of memory for t2p_readwrite_pdf_image, %s",
                          t2p->tiff_datasize, TIFFFileName(input));
                t2p->t2p_error = T2P_ERR_ERROR;
                return (0);
            }
            memset(buffer, 0, t2p->tiff_datasize);
            if (TIFFReadRawStrip(input, 0, (tdata_t)buffer,
                                 t2p->tiff_datasize) < 0)
            {
                TIFFError(TIFF2PDF_MODULE, "TIFFReadRawStrip() failed");
                _TIFFfree(buffer);
                return (0);
            }
            if (t2p->tiff_fillorder == FILLORDER_LSB2MSB)
            {
                TIFFReverseBits(buffer, t2p->tiff_datasize);
            }
            add_t2pWriteFile_check(output, (tdata_t)buffer, t2p->tiff_datasize,
                                   mod, tsdummy);
            _TIFFfree(buffer);
            return (t2p->tiff_datasize);
        }
#endif /* ifdef ZIP_SUPPORT */
#ifdef OJPEG_SUPPORT
        if (t2p->tiff_compression == COMPRESSION_OJPEG)
        {

            if (t2p->tiff_dataoffset != 0)
            {
                buffer = (unsigned char *)_TIFFmalloc(t2p->tiff_datasize);
                if (buffer == NULL)
                {
                    TIFFError(
                        TIFF2PDF_MODULE,
                        "Can't allocate %" TIFF_SSIZE_FORMAT
                        " bytes of memory for t2p_readwrite_pdf_image, %s",
                        t2p->tiff_datasize, TIFFFileName(input));
                    t2p->t2p_error = T2P_ERR_ERROR;
                    return (0);
                }
                memset(buffer, 0, t2p->tiff_datasize);
                if (t2p->pdf_ojpegiflength == 0)
                {
                    inputoffset = t2pSeekFile(input, 0, SEEK_CUR);
                    t2pSeekFile(input, t2p->tiff_dataoffset, SEEK_SET);
                    t2pReadFile(input, (tdata_t)buffer, t2p->tiff_datasize);
                    t2pSeekFile(input, inputoffset, SEEK_SET);
                    add_t2pWriteFile_check(output, (tdata_t)buffer,
                                           t2p->tiff_datasize, mod, tsdummy);
                    _TIFFfree(buffer);
                    return (t2p->tiff_datasize);
                }
                else
                {
                    inputoffset = t2pSeekFile(input, 0, SEEK_CUR);
                    t2pSeekFile(input, t2p->tiff_dataoffset, SEEK_SET);
                    bufferoffset = t2pReadFile(input, (tdata_t)buffer,
                                               t2p->pdf_ojpegiflength);
                    t2p->pdf_ojpegiflength = 0;
                    t2pSeekFile(input, inputoffset, SEEK_SET);
                    TIFFGetField(input, TIFFTAG_YCBCRSUBSAMPLING, &h_samp,
                                 &v_samp);
                    /* The only valid values for h_samp and v_samp are 1, 2
                     * or 4. Cf tif_jpeg.c line 960. However just a simple check
                     * to avoid division by zero below. */
                    if (h_samp == 0 || h_samp > 4 || v_samp == 0 || v_samp > 4)
                    {
                        TIFFError(
                            TIFF2PDF_MODULE,
                            "YCBRSUBSAMPLING value outside allowed range (1, "
                            "2, 4). h_samp= %" PRIu16 " v_samp= %" PRIu16,
                            h_samp, v_samp);
                        _TIFFfree(buffer);
                        t2p->t2p_error = T2P_ERR_ERROR;
                        return (0);
                    }
                    buffer[bufferoffset++] = 0xff;
                    buffer[bufferoffset++] = 0xdd;
                    buffer[bufferoffset++] = 0x00;
                    buffer[bufferoffset++] = 0x04;
                    h_samp *= 8;
                    v_samp *= 8;
                    ri = (t2p->tiff_width + h_samp - 1) / h_samp;
                    TIFFGetField(input, TIFFTAG_ROWSPERSTRIP, &rows);
                    ri *= (rows + v_samp - 1) / v_samp;
                    buffer[bufferoffset++] = (ri >> 8) & 0xff;
                    buffer[bufferoffset++] = ri & 0xff;
                    stripcount = TIFFNumberOfStrips(input);
                    for (i = 0; i < stripcount; i++)
                    {
                        tsize_t retTIFFReadRawStrip;
                        if (i != 0)
                        {
                            buffer[bufferoffset++] = 0xff;
                            buffer[bufferoffset++] = (0xd0 | ((i - 1) % 8));
                        }
                        retTIFFReadRawStrip = TIFFReadRawStrip(
                            input, i,
                            (tdata_t) &
                                (((unsigned char *)buffer)[bufferoffset]),
                            -1);
                        if (retTIFFReadRawStrip < 0)
                        {
                            TIFFError(TIFF2PDF_MODULE, "TIFFReadRawStrip()");
                            _TIFFfree(buffer);
                            t2p->t2p_error = T2P_ERR_ERROR;
                            return (0);
                        }
                        bufferoffset += retTIFFReadRawStrip;
                    }
                    add_t2pWriteFile_check(output, (tdata_t)buffer,
                                           bufferoffset, mod, tsdummy);
                    _TIFFfree(buffer);
                    return (bufferoffset);
                }
            }
            else
            {
                if (!t2p->pdf_ojpegdata)
                {
                    TIFFError(TIFF2PDF_MODULE,
                              "No support for OJPEG image %s with bad tables",
                              TIFFFileName(input));
                    t2p->t2p_error = T2P_ERR_ERROR;
                    return (0);
                }
                buffer = (unsigned char *)_TIFFmalloc(t2p->tiff_datasize);
                if (buffer == NULL)
                {
                    TIFFError(
                        TIFF2PDF_MODULE,
                        "Can't allocate %" TIFF_SSIZE_FORMAT
                        " bytes of memory for t2p_readwrite_pdf_image, %s",
                        t2p->tiff_datasize, TIFFFileName(input));
                    t2p->t2p_error = T2P_ERR_ERROR;
                    return (0);
                }
                memset(buffer, 0, t2p->tiff_datasize);
                _TIFFmemcpy(buffer, t2p->pdf_ojpegdata,
                            t2p->pdf_ojpegdatalength);
                bufferoffset = t2p->pdf_ojpegdatalength;
                stripcount = TIFFNumberOfStrips(input);
                for (i = 0; i < stripcount; i++)
                {
                    tsize_t retTIFFReadRawStrip;
                    if (i != 0)
                    {
                        buffer[bufferoffset++] = 0xff;
                        buffer[bufferoffset++] = (0xd0 | ((i - 1) % 8));
                    }
                    retTIFFReadRawStrip = TIFFReadRawStrip(
                        input, i,
                        (tdata_t) & (((unsigned char *)buffer)[bufferoffset]),
                        -1);
                    if (retTIFFReadRawStrip < 0)
                    {
                        TIFFError(TIFF2PDF_MODULE, "TIFFReadRawStrip()");
                        _TIFFfree(buffer);
                        t2p->t2p_error = T2P_ERR_ERROR;
                        return (0);
                    }
                    bufferoffset += retTIFFReadRawStrip;
                }
                add_t2pWriteFile_check(output, (tdata_t)buffer, bufferoffset,
                                       mod, tsdummy);
                if (!((buffer[bufferoffset - 1] == 0xd9) &&
                      (buffer[bufferoffset - 2] == 0xff)))
                {
                    add_t2pWriteFile_check(output, (tdata_t)jpeg_eof_marker,
                                           sizeof(jpeg_eof_marker), mod,
                                           tsdummy);
                }
                _TIFFfree(buffer);
                return (bufferoffset);
#if 0
                                /*
                                  This hunk of code removed code is clearly
                                  mis-placed and we are not sure where it
                                  should be (if anywhere)
                                */
				TIFFError(TIFF2PDF_MODULE, 
	"No support for OJPEG image %s with no JPEG File Interchange offset", 
					TIFFFileName(input));
				t2p->t2p_error = T2P_ERR_ERROR;
				return(0);
#endif
            }
        }
#endif /* ifdef OJPEG_SUPPORT */
#ifdef JPEG_SUPPORT
        if (t2p->tiff_compression == COMPRESSION_JPEG)
        {
            uint32_t count = 0;
            buffer = (unsigned char *)_TIFFmalloc(t2p->tiff_datasize);
            if (buffer == NULL)
            {
                TIFFError(TIFF2PDF_MODULE,
                          "Can't allocate %" TIFF_SSIZE_FORMAT
                          " bytes of memory for t2p_readwrite_pdf_image, %s",
                          t2p->tiff_datasize, TIFFFileName(input));
                t2p->t2p_error = T2P_ERR_ERROR;
                return (0);
            }
            memset(buffer, 0, t2p->tiff_datasize);
            if (TIFFGetField(input, TIFFTAG_JPEGTABLES, &count, &jpt) != 0)
            {
                if (count > 4)
                {
                    _TIFFmemcpy(buffer, jpt, count);
                    bufferoffset += count - 2;
                }
            }
            stripcount = TIFFNumberOfStrips(input);
            TIFFGetField(input, TIFFTAG_STRIPBYTECOUNTS, &sbc);
            for (i = 0; i < stripcount; i++)
            {
                if (sbc[i] > max_striplength)
                    max_striplength = sbc[i];
            }
            stripbuffer = (unsigned char *)_TIFFmalloc(max_striplength);
            if (stripbuffer == NULL)
            {
                TIFFError(TIFF2PDF_MODULE,
                          "Can't allocate %" PRId64
                          " bytes of memory for t2p_readwrite_pdf_image, %s",
                          max_striplength, TIFFFileName(input));
                _TIFFfree(buffer);
                t2p->t2p_error = T2P_ERR_ERROR;
                return (0);
            }
            memset(stripbuffer, 0, max_striplength);
            for (i = 0; i < stripcount; i++)
            {
                striplength =
                    TIFFReadRawStrip(input, i, (tdata_t)stripbuffer, -1);
                if (striplength < 0)
                {
                    TIFFError(TIFF2PDF_MODULE, "TIFFReadRawStrip() failed");
                    _TIFFfree(samplebuffer);
                    _TIFFfree(buffer);
                    t2p->t2p_error = T2P_ERR_ERROR;
                    return (0);
                }
                if (!t2p_process_jpeg_strip(stripbuffer, &striplength, buffer,
                                            t2p->tiff_datasize, &bufferoffset,
                                            i, t2p->tiff_length))
                {
                    TIFFError(TIFF2PDF_MODULE,
                              "Can't process JPEG data in input file %s",
                              TIFFFileName(input));
                    _TIFFfree(samplebuffer);
                    _TIFFfree(buffer);
                    t2p->t2p_error = T2P_ERR_ERROR;
                    return (0);
                }
            }
            add_t2pWriteFile_check(output, (tdata_t)buffer, bufferoffset, mod,
                                   tsdummy);
            add_t2pWriteFile_check(output, (tdata_t)jpeg_eof_marker,
                                   sizeof(jpeg_eof_marker), mod, tsdummy);
            _TIFFfree(stripbuffer);
            _TIFFfree(buffer);
            return (bufferoffset);
        }
#endif /* ifdef JPEG_SUPPORT */
        (void)0;
    }

    if (t2p->pdf_sample == T2P_SAMPLE_NOTHING)
    {
        buffer = (unsigned char *)_TIFFmalloc(t2p->tiff_datasize);
        if (buffer == NULL)
        {
            TIFFError(TIFF2PDF_MODULE,
                      "Can't allocate %" TIFF_SSIZE_FORMAT
                      " bytes of memory for t2p_readwrite_pdf_image, %s",
                      t2p->tiff_datasize, TIFFFileName(input));
            t2p->t2p_error = T2P_ERR_ERROR;
            return (0);
        }
        memset(buffer, 0, t2p->tiff_datasize);
        stripsize = TIFFStripSize(input);
        stripcount = TIFFNumberOfStrips(input);
        for (i = 0; i < stripcount; i++)
        {
            read = TIFFReadEncodedStrip(
                input, i, (tdata_t)&buffer[bufferoffset],
                TIFFmin(stripsize, t2p->tiff_datasize - bufferoffset));
            if (read == -1)
            {
                TIFFError(TIFF2PDF_MODULE,
                          "Error on decoding strip %" PRIu32 " of %s", i,
                          TIFFFileName(input));
                _TIFFfree(buffer);
                t2p->t2p_error = T2P_ERR_ERROR;
                return (0);
            }
            bufferoffset += read;
        }
    }
    else
    {
        if (t2p->pdf_sample & T2P_SAMPLE_PLANAR_SEPARATE_TO_CONTIG)
        {

            sepstripsize = TIFFStripSize(input);
            sepstripcount = TIFFNumberOfStrips(input);

            stripsize = sepstripsize * t2p->tiff_samplesperpixel;
            stripcount = _TIFFCastSSizeToUInt32(sepstripcount /
                                                    t2p->tiff_samplesperpixel,
                                                "t2p_readwrite_pdf_image");

            buffer = (unsigned char *)_TIFFmalloc(t2p->tiff_datasize);
            if (buffer == NULL)
            {
                TIFFError(TIFF2PDF_MODULE,
                          "Can't allocate %" TIFF_SSIZE_FORMAT
                          " bytes of memory for t2p_readwrite_pdf_image, %s",
                          t2p->tiff_datasize, TIFFFileName(input));
                t2p->t2p_error = T2P_ERR_ERROR;
                return (0);
            }
            memset(buffer, 0, t2p->tiff_datasize);
            samplebuffer = (unsigned char *)_TIFFmalloc(stripsize);
            if (samplebuffer == NULL)
            {
                TIFFError(TIFF2PDF_MODULE,
                          "Can't allocate %" TIFF_SSIZE_FORMAT
                          " bytes of memory for t2p_readwrite_pdf_image, %s",
                          t2p->tiff_datasize, TIFFFileName(input));
                t2p->t2p_error = T2P_ERR_ERROR;
                _TIFFfree(buffer);
                return (0);
            }
            for (i = 0; i < stripcount; i++)
            {
                samplebufferoffset = 0;
                for (j = 0; j < t2p->tiff_samplesperpixel; j++)
                {
                    read = TIFFReadEncodedStrip(
                        input, i + j * stripcount,
                        (tdata_t) & (samplebuffer[samplebufferoffset]),
                        TIFFmin(sepstripsize, stripsize - samplebufferoffset));
                    if (read == -1)
                    {
                        TIFFError(TIFF2PDF_MODULE,
                                  "Error on decoding strip %" PRIu32 " of %s",
                                  i + j * stripcount, TIFFFileName(input));
                        t2p->t2p_error = T2P_ERR_ERROR;
                        _TIFFfree(samplebuffer);
                        _TIFFfree(buffer);
                        return (0);
                    }
                    samplebufferoffset += read;
                }
                t2p_sample_planar_separate_to_contig(
                    t2p, &(buffer[bufferoffset]), samplebuffer,
                    samplebufferoffset);
                bufferoffset += samplebufferoffset;
            }
            _TIFFfree(samplebuffer);
            goto dataready;
        }

        buffer = (unsigned char *)_TIFFmalloc(t2p->tiff_datasize);
        if (buffer == NULL)
        {
            TIFFError(TIFF2PDF_MODULE,
                      "Can't allocate %" TIFF_SSIZE_FORMAT
                      " bytes of memory for t2p_readwrite_pdf_image, %s",
                      t2p->tiff_datasize, TIFFFileName(input));
            t2p->t2p_error = T2P_ERR_ERROR;
            return (0);
        }
        memset(buffer, 0, t2p->tiff_datasize);
        stripsize = TIFFStripSize(input);
        stripcount = TIFFNumberOfStrips(input);
        for (i = 0; i < stripcount; i++)
        {
            read = TIFFReadEncodedStrip(
                input, i, (tdata_t)&buffer[bufferoffset],
                TIFFmin(stripsize, t2p->tiff_datasize - bufferoffset));
            if (read == -1)
            {
                TIFFError(TIFF2PDF_MODULE,
                          "Error on decoding strip %" PRIu32 " of %s", i,
                          TIFFFileName(input));
                _TIFFfree(samplebuffer);
                _TIFFfree(buffer);
                t2p->t2p_error = T2P_ERR_ERROR;
                return (0);
            }
            bufferoffset += read;
        }

        if (t2p->pdf_sample & T2P_SAMPLE_REALIZE_PALETTE)
        {
            // FIXME: overflow?
            samplebuffer = (unsigned char *)_TIFFrealloc(
                (tdata_t)buffer,
                t2p->tiff_datasize * t2p->tiff_samplesperpixel);
            if (samplebuffer == NULL)
            {
                TIFFError(TIFF2PDF_MODULE,
                          "Can't allocate %" TIFF_SSIZE_FORMAT
                          " bytes of memory for t2p_readwrite_pdf_image, %s",
                          t2p->tiff_datasize, TIFFFileName(input));
                t2p->t2p_error = T2P_ERR_ERROR;
                _TIFFfree(buffer);
                return (0);
            }
            else
            {
                buffer = samplebuffer;
                t2p->tiff_datasize *= t2p->tiff_samplesperpixel;
            }
            t2p_sample_realize_palette(t2p, buffer);
        }

        if (t2p->pdf_sample & T2P_SAMPLE_RGBA_TO_RGB)
        {
            t2p->tiff_datasize = t2p_sample_rgba_to_rgb(
                (tdata_t)buffer, t2p->tiff_width * t2p->tiff_length);
        }

        if (t2p->pdf_sample & T2P_SAMPLE_RGBAA_TO_RGB)
        {
            t2p->tiff_datasize = t2p_sample_rgbaa_to_rgb(
                (tdata_t)buffer, t2p->tiff_width * t2p->tiff_length);
        }

        if (t2p->pdf_sample & T2P_SAMPLE_YCBCR_TO_RGB)
        {
            samplebuffer = (unsigned char *)_TIFFrealloc(
                (tdata_t)buffer, t2p->tiff_width * t2p->tiff_length * 4);
            if (samplebuffer == NULL)
            {
                TIFFError(TIFF2PDF_MODULE,
                          "Can't allocate %" TIFF_SSIZE_FORMAT
                          " bytes of memory for t2p_readwrite_pdf_image, %s",
                          t2p->tiff_datasize, TIFFFileName(input));
                t2p->t2p_error = T2P_ERR_ERROR;
                _TIFFfree(buffer);
                return (0);
            }
            else
            {
                buffer = samplebuffer;
            }
            if (!TIFFReadRGBAImageOriented(input, t2p->tiff_width,
                                           t2p->tiff_length, (uint32_t *)buffer,
                                           ORIENTATION_TOPLEFT, 0))
            {
                TIFFError(TIFF2PDF_MODULE,
                          "Can't use TIFFReadRGBAImageOriented to extract RGB "
                          "image from %s",
                          TIFFFileName(input));
                t2p->t2p_error = T2P_ERR_ERROR;
                return (0);
            }
            t2p->tiff_datasize = t2p_sample_abgr_to_rgb(
                (tdata_t)buffer, t2p->tiff_width * t2p->tiff_length);
        }

        if (t2p->pdf_sample & T2P_SAMPLE_LAB_SIGNED_TO_UNSIGNED)
        {
            t2p->tiff_datasize = t2p_sample_lab_signed_to_unsigned(
                (tdata_t)buffer, t2p->tiff_width * t2p->tiff_length);
        }
    }

dataready:

    t2p_disable(output);
    TIFFSetField(output, TIFFTAG_PHOTOMETRIC, t2p->tiff_photometric);
    TIFFSetField(output, TIFFTAG_BITSPERSAMPLE, t2p->tiff_bitspersample);
    TIFFSetField(output, TIFFTAG_SAMPLESPERPIXEL, t2p->tiff_samplesperpixel);
    TIFFSetField(output, TIFFTAG_IMAGEWIDTH, t2p->tiff_width);
    TIFFSetField(output, TIFFTAG_IMAGELENGTH, t2p->tiff_length);
    TIFFSetField(output, TIFFTAG_ROWSPERSTRIP, t2p->tiff_length);
    TIFFSetField(output, TIFFTAG_PLANARCONFIG, t2p->tiff_planar);
    TIFFSetField(output, TIFFTAG_FILLORDER, FILLORDER_MSB2LSB);

    switch (t2p->pdf_compression)
    {
        case T2P_COMPRESS_NONE:
            TIFFSetField(output, TIFFTAG_COMPRESSION, COMPRESSION_NONE);
            break;
#ifdef CCITT_SUPPORT
        case T2P_COMPRESS_G4:
            TIFFSetField(output, TIFFTAG_COMPRESSION, COMPRESSION_CCITTFAX4);
            break;
#endif /* ifdef CCITT_SUPPORT */
#ifdef JPEG_SUPPORT
        case T2P_COMPRESS_JPEG:
            if (t2p->tiff_photometric == PHOTOMETRIC_YCBCR)
            {
                uint16_t hor = 0, ver = 0;
                if (TIFFGetField(input, TIFFTAG_YCBCRSUBSAMPLING, &hor, &ver) !=
                    0)
                {
                    if (hor != 0 && ver != 0)
                    {
                        TIFFSetField(output, TIFFTAG_YCBCRSUBSAMPLING, hor,
                                     ver);
                    }
                }
                if (TIFFGetField(input, TIFFTAG_REFERENCEBLACKWHITE,
                                 &xfloatp) != 0)
                {
                    TIFFSetField(output, TIFFTAG_REFERENCEBLACKWHITE, xfloatp);
                }
            }
            if (TIFFSetField(output, TIFFTAG_COMPRESSION, COMPRESSION_JPEG) ==
                0)
            {
                TIFFError(
                    TIFF2PDF_MODULE,
                    "Unable to use JPEG compression for input %s and output %s",
                    TIFFFileName(input), TIFFFileName(output));
                _TIFFfree(buffer);
                t2p->t2p_error = T2P_ERR_ERROR;
                return (0);
            }
            TIFFSetField(output, TIFFTAG_JPEGTABLESMODE, 0);

            if (t2p->pdf_colorspace & (T2P_CS_RGB | T2P_CS_LAB))
            {
                TIFFSetField(output, TIFFTAG_PHOTOMETRIC, PHOTOMETRIC_YCBCR);
                if (t2p->tiff_photometric != PHOTOMETRIC_YCBCR)
                {
                    TIFFSetField(output, TIFFTAG_JPEGCOLORMODE,
                                 JPEGCOLORMODE_RGB);
                }
                else
                {
                    TIFFSetField(output, TIFFTAG_JPEGCOLORMODE,
                                 JPEGCOLORMODE_RAW);
                }
            }
            if (t2p->pdf_colorspace & T2P_CS_GRAY)
            {
                (void)0;
            }
            if (t2p->pdf_colorspace & T2P_CS_CMYK)
            {
                (void)0;
            }
            if (t2p->pdf_defaultcompressionquality != 0)
            {
                TIFFSetField(output, TIFFTAG_JPEGQUALITY,
                             t2p->pdf_defaultcompressionquality);
            }

            break;
#endif /* ifdef JPEG_SUPPORT */
#ifdef ZIP_SUPPORT
        case T2P_COMPRESS_ZIP:
            TIFFSetField(output, TIFFTAG_COMPRESSION,
                         COMPRESSION_ADOBE_DEFLATE);
            if (t2p->pdf_defaultcompressionquality % 100 != 0)
            {
                TIFFSetField(output, TIFFTAG_PREDICTOR,
                             t2p->pdf_defaultcompressionquality % 100);
            }
            if (t2p->pdf_defaultcompressionquality / 100 != 0)
            {
                TIFFSetField(output, TIFFTAG_ZIPQUALITY,
                             (t2p->pdf_defaultcompressionquality / 100));
            }
            break;
#endif /* ifdef ZIP_SUPPORT */
        default:
            break;
    }

    t2p_enable(output);
    t2p->outputwritten = 0;
#ifdef JPEG_SUPPORT
    if (t2p->pdf_compression == T2P_COMPRESS_JPEG &&
        t2p->tiff_photometric == PHOTOMETRIC_YCBCR)
    {
        bufferoffset = TIFFWriteEncodedStrip(output, (tstrip_t)0, buffer,
                                             stripsize * stripcount);
    }
    else
#endif /* ifdef JPEG_SUPPORT */
    {
        bufferoffset = TIFFWriteEncodedStrip(output, (tstrip_t)0, buffer,
                                             t2p->tiff_datasize);
    }
    if (buffer != NULL)
    {
        _TIFFfree(buffer);
        buffer = NULL;
    }

    if (bufferoffset == (tsize_t)-1)
    {
        TIFFError(TIFF2PDF_MODULE,
                  "Error writing encoded strip to output PDF %s",
                  TIFFFileName(output));
        t2p->t2p_error = T2P_ERR_ERROR;
        return (0);
    }

    written = t2p->outputwritten;
    return (written);
}

tsize_t t2p_readwrite_pdf_image_tile(T2P *t2p, TIFF *input, TIFF *output,
                                     ttile_t tile)
{

    uint16_t edge = 0;
    tsize_t written = 0;
    unsigned char *buffer = NULL;
    tsize_t bufferoffset = 0;
    unsigned char *samplebuffer = NULL;
    tsize_t samplebufferoffset = 0;
    tsize_t read = 0;
    uint16_t i = 0;
    ttile_t tilecount = 0;
    /* tsize_t tilesize=0; */
    ttile_t septilecount = 0;
    tsize_t septilesize = 0;
#ifdef JPEG_SUPPORT
    unsigned char *jpt;
    float *xfloatp;
    tmsize_t xint = 0;
#endif
    const char mod[] = "t2p_readwrite_pdf_image_tile()";
    tsize_t tsdummy = 0;

    /* Fail if prior error (in particular, can't trust tiff_datasize) */
    if (t2p->t2p_error != T2P_ERR_OK)
        return (0);

    edge |= t2p_tile_is_right_edge(t2p->tiff_tiles[t2p->pdf_page], tile);
    edge |= t2p_tile_is_bottom_edge(t2p->tiff_tiles[t2p->pdf_page], tile);

    if ((t2p->pdf_transcode == T2P_TRANSCODE_RAW) &&
        ((edge == 0)
#if defined(JPEG_SUPPORT) || defined(OJPEG_SUPPORT)
         || (t2p->pdf_compression == T2P_COMPRESS_JPEG)
#endif
             ))
    {
#ifdef CCITT_SUPPORT
        if (t2p->pdf_compression == T2P_COMPRESS_G4)
        {
            buffer = (unsigned char *)_TIFFmalloc(t2p->tiff_datasize);
            if (buffer == NULL)
            {
                TIFFError(TIFF2PDF_MODULE,
                          "Can't allocate %" TIFF_SSIZE_FORMAT
                          " bytes of memory "
                          "for t2p_readwrite_pdf_image_tile, %s",
                          t2p->tiff_datasize, TIFFFileName(input));
                t2p->t2p_error = T2P_ERR_ERROR;
                return (0);
            }
            memset(buffer, 0, t2p->tiff_datasize);
            if (TIFFReadRawTile(input, tile, (tdata_t)buffer,
                                t2p->tiff_datasize) < 0)
            {
                TIFFError(TIFF2PDF_MODULE, "TIFFReadRawTile() failed");
                _TIFFfree(buffer);
                t2p->t2p_error = T2P_ERR_ERROR;
                return (0);
            }
            if (t2p->tiff_fillorder == FILLORDER_LSB2MSB)
            {
                TIFFReverseBits(buffer, t2p->tiff_datasize);
            }
            add_t2pWriteFile_check(output, (tdata_t)buffer, t2p->tiff_datasize,
                                   mod, tsdummy);
            _TIFFfree(buffer);
            return (t2p->tiff_datasize);
        }
#endif
#ifdef ZIP_SUPPORT
        if (t2p->pdf_compression == T2P_COMPRESS_ZIP)
        {
            buffer = (unsigned char *)_TIFFmalloc(t2p->tiff_datasize);
            if (buffer == NULL)
            {
                TIFFError(TIFF2PDF_MODULE,
                          "Can't allocate %" TIFF_SSIZE_FORMAT
                          " bytes of memory "
                          "for t2p_readwrite_pdf_image_tile, %s",
                          t2p->tiff_datasize, TIFFFileName(input));
                t2p->t2p_error = T2P_ERR_ERROR;
                return (0);
            }
            memset(buffer, 0, t2p->tiff_datasize);
            if (TIFFReadRawTile(input, tile, (tdata_t)buffer,
                                t2p->tiff_datasize) < 0)
            {
                TIFFError(TIFF2PDF_MODULE, "TIFFReadRawTile() failed");
                _TIFFfree(buffer);
                t2p->t2p_error = T2P_ERR_ERROR;
                return (0);
            }
            if (t2p->tiff_fillorder == FILLORDER_LSB2MSB)
            {
                TIFFReverseBits(buffer, t2p->tiff_datasize);
            }
            add_t2pWriteFile_check(output, (tdata_t)buffer, t2p->tiff_datasize,
                                   mod, tsdummy);
            _TIFFfree(buffer);
            return (t2p->tiff_datasize);
        }
#endif
#ifdef OJPEG_SUPPORT
        if (t2p->tiff_compression == COMPRESSION_OJPEG)
        {
            tsize_t retTIFFReadRawTile;
            if (!t2p->pdf_ojpegdata)
            {
                TIFFError(TIFF2PDF_MODULE,
                          "No support for OJPEG image %s with "
                          "bad tables",
                          TIFFFileName(input));
                t2p->t2p_error = T2P_ERR_ERROR;
                return (0);
            }
            buffer = (unsigned char *)_TIFFmalloc(t2p->tiff_datasize);
            if (buffer == NULL)
            {
                TIFFError(TIFF2PDF_MODULE,
                          "Can't allocate %" TIFF_SSIZE_FORMAT
                          " bytes of memory "
                          "for t2p_readwrite_pdf_image, %s",
                          t2p->tiff_datasize, TIFFFileName(input));
                t2p->t2p_error = T2P_ERR_ERROR;
                return (0);
            }
            memset(buffer, 0, t2p->tiff_datasize);
            _TIFFmemcpy(buffer, t2p->pdf_ojpegdata, t2p->pdf_ojpegdatalength);
            if (edge != 0)
            {
                if (t2p_tile_is_bottom_edge(t2p->tiff_tiles[t2p->pdf_page],
                                            tile))
                {
                    buffer[7] =
                        (t2p->tiff_tiles[t2p->pdf_page].tiles_edgetilelength >>
                         8) &
                        0xff;
                    buffer[8] =
                        (t2p->tiff_tiles[t2p->pdf_page].tiles_edgetilelength) &
                        0xff;
                }
                if (t2p_tile_is_right_edge(t2p->tiff_tiles[t2p->pdf_page],
                                           tile))
                {
                    buffer[9] =
                        (t2p->tiff_tiles[t2p->pdf_page].tiles_edgetilewidth >>
                         8) &
                        0xff;
                    buffer[10] =
                        (t2p->tiff_tiles[t2p->pdf_page].tiles_edgetilewidth) &
                        0xff;
                }
            }
            bufferoffset = t2p->pdf_ojpegdatalength;
            retTIFFReadRawTile = TIFFReadRawTile(
                input, tile,
                (tdata_t) & (((unsigned char *)buffer)[bufferoffset]), -1);
            if (retTIFFReadRawTile < 0)
            {
                TIFFError(TIFF2PDF_MODULE, "TIFFReadRawTile() failed");
                _TIFFfree(buffer);
                t2p->t2p_error = T2P_ERR_ERROR;
                return (0);
            }
            bufferoffset += retTIFFReadRawTile;
            add_t2pWriteFile_check(output, (tdata_t)buffer, bufferoffset, mod,
                                   tsdummy);
            add_t2pWriteFile_check(output, (tdata_t)jpeg_eof_marker,
                                   sizeof(jpeg_eof_marker), mod, tsdummy);
            _TIFFfree(buffer);
            return (bufferoffset);
        }
#endif
#ifdef JPEG_SUPPORT
        if (t2p->tiff_compression == COMPRESSION_JPEG)
        {
            unsigned char table_end[2];
            uint32_t count = 0;
            buffer = (unsigned char *)_TIFFmalloc(t2p->tiff_datasize);
            if (buffer == NULL)
            {
                TIFFError(TIFF2PDF_MODULE,
                          "Can't allocate %" TIFF_SSIZE_FORMAT
                          " bytes of memory "
                          "for t2p_readwrite_pdf_image_tile, %s",
                          t2p->tiff_datasize, TIFFFileName(input));
                t2p->t2p_error = T2P_ERR_ERROR;
                return (0);
            }
            memset(buffer, 0, t2p->tiff_datasize);
            if (TIFFGetField(input, TIFFTAG_JPEGTABLES, &count, &jpt) != 0)
            {
                if (count > 4)
                {
                    tsize_t retTIFFReadRawTile;
                    /* Ignore EOI marker of JpegTables */
                    _TIFFmemcpy(buffer, jpt, count - 2);
                    bufferoffset += count - 2;
                    /* Store last 2 bytes of the JpegTables */
                    table_end[0] = buffer[bufferoffset - 2];
                    table_end[1] = buffer[bufferoffset - 1];
                    xint = bufferoffset;
                    bufferoffset -= 2;
                    retTIFFReadRawTile = TIFFReadRawTile(
                        input, tile,
                        (tdata_t) & (((unsigned char *)buffer)[bufferoffset]),
                        -1);
                    if (retTIFFReadRawTile < 0)
                    {
                        _TIFFfree(buffer);
                        t2p->t2p_error = T2P_ERR_ERROR;
                        return (0);
                    }
                    bufferoffset += retTIFFReadRawTile;
                    /* Overwrite SOI marker of image scan with previously */
                    /* saved end of JpegTables */
                    buffer[xint - 2] = table_end[0];
                    buffer[xint - 1] = table_end[1];
                }
            }
            add_t2pWriteFile_check(output, (tdata_t)buffer, bufferoffset, mod,
                                   tsdummy);
            _TIFFfree(buffer);
            return (bufferoffset);
        }
#endif
        (void)0;
    }

    if (t2p->pdf_sample == T2P_SAMPLE_NOTHING)
    {
        buffer = (unsigned char *)_TIFFmalloc(t2p->tiff_datasize);
        if (buffer == NULL)
        {
            TIFFError(TIFF2PDF_MODULE,
                      "Can't allocate %" TIFF_SSIZE_FORMAT
                      " bytes of memory for "
                      "t2p_readwrite_pdf_image_tile, %s",
                      t2p->tiff_datasize, TIFFFileName(input));
            t2p->t2p_error = T2P_ERR_ERROR;
            return (0);
        }
        memset(buffer, 0, t2p->tiff_datasize);

        read = TIFFReadEncodedTile(input, tile, (tdata_t)&buffer[bufferoffset],
                                   t2p->tiff_datasize);
        if (read == -1)
        {
            TIFFError(TIFF2PDF_MODULE,
                      "Error on decoding tile %" PRIu32 " of %s", tile,
                      TIFFFileName(input));
            _TIFFfree(buffer);
            t2p->t2p_error = T2P_ERR_ERROR;
            return (0);
        }
    }
    else
    {

        if (t2p->pdf_sample == T2P_SAMPLE_PLANAR_SEPARATE_TO_CONTIG)
        {
            septilesize = TIFFTileSize(input);
            septilecount = TIFFNumberOfTiles(input);
            /* tilesize=septilesize*t2p->tiff_samplesperpixel; */
            tilecount = septilecount / t2p->tiff_samplesperpixel;
            buffer = (unsigned char *)_TIFFmalloc(t2p->tiff_datasize);
            if (buffer == NULL)
            {
                TIFFError(TIFF2PDF_MODULE,
                          "Can't allocate %" TIFF_SSIZE_FORMAT
                          " bytes of memory "
                          "for t2p_readwrite_pdf_image_tile, %s",
                          t2p->tiff_datasize, TIFFFileName(input));
                t2p->t2p_error = T2P_ERR_ERROR;
                return (0);
            }
            memset(buffer, 0, t2p->tiff_datasize);
            samplebuffer = (unsigned char *)_TIFFmalloc(t2p->tiff_datasize);
            if (samplebuffer == NULL)
            {
                TIFFError(TIFF2PDF_MODULE,
                          "Can't allocate %" TIFF_SSIZE_FORMAT
                          " bytes of memory "
                          "for t2p_readwrite_pdf_image_tile, %s",
                          t2p->tiff_datasize, TIFFFileName(input));
                _TIFFfree(buffer);
                t2p->t2p_error = T2P_ERR_ERROR;
                return (0);
            }
            memset(samplebuffer, 0, t2p->tiff_datasize);
            samplebufferoffset = 0;
            for (i = 0; i < t2p->tiff_samplesperpixel; i++)
            {
                read = TIFFReadEncodedTile(
                    input, tile + i * tilecount,
                    (tdata_t) & (samplebuffer[samplebufferoffset]),
                    septilesize);
                if (read == -1)
                {
                    TIFFError(TIFF2PDF_MODULE,
                              "Error on decoding tile %" PRIu32 " of %s",
                              tile + i * tilecount, TIFFFileName(input));
                    _TIFFfree(samplebuffer);
                    _TIFFfree(buffer);
                    t2p->t2p_error = T2P_ERR_ERROR;
                    return (0);
                }
                samplebufferoffset += read;
            }
            t2p_sample_planar_separate_to_contig(
                t2p, &(buffer[bufferoffset]), samplebuffer, samplebufferoffset);
            bufferoffset += samplebufferoffset;
            _TIFFfree(samplebuffer);
        }

        if (buffer == NULL)
        {
            buffer = (unsigned char *)_TIFFmalloc(t2p->tiff_datasize);
            if (buffer == NULL)
            {
                TIFFError(TIFF2PDF_MODULE,
                          "Can't allocate %" TIFF_SSIZE_FORMAT
                          " bytes of memory "
                          "for t2p_readwrite_pdf_image_tile, %s",
                          t2p->tiff_datasize, TIFFFileName(input));
                t2p->t2p_error = T2P_ERR_ERROR;
                return (0);
            }
            memset(buffer, 0, t2p->tiff_datasize);
            read =
                TIFFReadEncodedTile(input, tile, (tdata_t)&buffer[bufferoffset],
                                    t2p->tiff_datasize);
            if (read == -1)
            {
                TIFFError(TIFF2PDF_MODULE,
                          "Error on decoding tile %" PRIu32 " of %s", tile,
                          TIFFFileName(input));
                _TIFFfree(buffer);
                t2p->t2p_error = T2P_ERR_ERROR;
                return (0);
            }
        }

        if (t2p->pdf_sample & T2P_SAMPLE_RGBA_TO_RGB)
        {
            t2p->tiff_datasize = t2p_sample_rgba_to_rgb(
                (tdata_t)buffer,
                t2p->tiff_tiles[t2p->pdf_page].tiles_tilewidth *
                    t2p->tiff_tiles[t2p->pdf_page].tiles_tilelength);
        }

        if (t2p->pdf_sample & T2P_SAMPLE_RGBAA_TO_RGB)
        {
            t2p->tiff_datasize = t2p_sample_rgbaa_to_rgb(
                (tdata_t)buffer,
                t2p->tiff_tiles[t2p->pdf_page].tiles_tilewidth *
                    t2p->tiff_tiles[t2p->pdf_page].tiles_tilelength);
        }

        if (t2p->pdf_sample & T2P_SAMPLE_YCBCR_TO_RGB)
        {
            TIFFError(TIFF2PDF_MODULE,
                      "No support for YCbCr to RGB in tile for %s",
                      TIFFFileName(input));
            _TIFFfree(buffer);
            t2p->t2p_error = T2P_ERR_ERROR;
            return (0);
        }

        if (t2p->pdf_sample & T2P_SAMPLE_LAB_SIGNED_TO_UNSIGNED)
        {
            t2p->tiff_datasize = t2p_sample_lab_signed_to_unsigned(
                (tdata_t)buffer,
                t2p->tiff_tiles[t2p->pdf_page].tiles_tilewidth *
                    t2p->tiff_tiles[t2p->pdf_page].tiles_tilelength);
        }
    }

    if (t2p_tile_is_right_edge(t2p->tiff_tiles[t2p->pdf_page], tile) != 0)
    {
        if ((uint64_t)t2p->tiff_datasize <
            (uint64_t)TIFFTileRowSize(input) *
                (uint64_t)t2p->tiff_tiles[t2p->pdf_page].tiles_tilelength)
        {
            /* we don't know how to handle PLANARCONFIG_CONTIG,
             * PHOTOMETRIC_YCBCR with 3 samples per pixel */
            TIFFWarning(TIFF2PDF_MODULE,
                        "Don't know how to collapse tile to the left");
        }
        else
        {
            t2p_tile_collapse_left(
                buffer, TIFFTileRowSize(input),
                t2p->tiff_tiles[t2p->pdf_page].tiles_tilewidth,
                t2p->tiff_tiles[t2p->pdf_page].tiles_edgetilewidth,
                t2p->tiff_tiles[t2p->pdf_page].tiles_tilelength);
        }
    }

    t2p_disable(output);
    TIFFSetField(output, TIFFTAG_PHOTOMETRIC, t2p->tiff_photometric);
    TIFFSetField(output, TIFFTAG_BITSPERSAMPLE, t2p->tiff_bitspersample);
    TIFFSetField(output, TIFFTAG_SAMPLESPERPIXEL, t2p->tiff_samplesperpixel);
    if (t2p_tile_is_right_edge(t2p->tiff_tiles[t2p->pdf_page], tile) == 0)
    {
        TIFFSetField(output, TIFFTAG_IMAGEWIDTH,
                     t2p->tiff_tiles[t2p->pdf_page].tiles_tilewidth);
    }
    else
    {
        TIFFSetField(output, TIFFTAG_IMAGEWIDTH,
                     t2p->tiff_tiles[t2p->pdf_page].tiles_edgetilewidth);
    }
    if (t2p_tile_is_bottom_edge(t2p->tiff_tiles[t2p->pdf_page], tile) == 0)
    {
        TIFFSetField(output, TIFFTAG_IMAGELENGTH,
                     t2p->tiff_tiles[t2p->pdf_page].tiles_tilelength);
        TIFFSetField(output, TIFFTAG_ROWSPERSTRIP,
                     t2p->tiff_tiles[t2p->pdf_page].tiles_tilelength);
    }
    else
    {
        TIFFSetField(output, TIFFTAG_IMAGELENGTH,
                     t2p->tiff_tiles[t2p->pdf_page].tiles_edgetilelength);
        TIFFSetField(output, TIFFTAG_ROWSPERSTRIP,
                     t2p->tiff_tiles[t2p->pdf_page].tiles_edgetilelength);
    }
    TIFFSetField(output, TIFFTAG_PLANARCONFIG, t2p->tiff_planar);
    TIFFSetField(output, TIFFTAG_FILLORDER, FILLORDER_MSB2LSB);

    switch (t2p->pdf_compression)
    {
        case T2P_COMPRESS_NONE:
            TIFFSetField(output, TIFFTAG_COMPRESSION, COMPRESSION_NONE);
            break;
#ifdef CCITT_SUPPORT
        case T2P_COMPRESS_G4:
            TIFFSetField(output, TIFFTAG_COMPRESSION, COMPRESSION_CCITTFAX4);
            break;
#endif
#ifdef JPEG_SUPPORT
        case T2P_COMPRESS_JPEG:
            if (t2p->tiff_photometric == PHOTOMETRIC_YCBCR)
            {
                uint16_t hor = 0, ver = 0;
                if (TIFFGetField(input, TIFFTAG_YCBCRSUBSAMPLING, &hor, &ver) !=
                    0)
                {
                    if (hor != 0 && ver != 0)
                    {
                        TIFFSetField(output, TIFFTAG_YCBCRSUBSAMPLING, hor,
                                     ver);
                    }
                }
                if (TIFFGetField(input, TIFFTAG_REFERENCEBLACKWHITE,
                                 &xfloatp) != 0)
                {
                    TIFFSetField(output, TIFFTAG_REFERENCEBLACKWHITE, xfloatp);
                }
            }
            TIFFSetField(output, TIFFTAG_COMPRESSION, COMPRESSION_JPEG);
            TIFFSetField(output, TIFFTAG_JPEGTABLESMODE,
                         0); /* JPEGTABLESMODE_NONE */
            if (t2p->pdf_colorspace & (T2P_CS_RGB | T2P_CS_LAB))
            {
                TIFFSetField(output, TIFFTAG_PHOTOMETRIC, PHOTOMETRIC_YCBCR);
                if (t2p->tiff_photometric != PHOTOMETRIC_YCBCR)
                {
                    TIFFSetField(output, TIFFTAG_JPEGCOLORMODE,
                                 JPEGCOLORMODE_RGB);
                }
                else
                {
                    TIFFSetField(output, TIFFTAG_JPEGCOLORMODE,
                                 JPEGCOLORMODE_RAW);
                }
            }
            if (t2p->pdf_colorspace & T2P_CS_GRAY)
            {
                (void)0;
            }
            if (t2p->pdf_colorspace & T2P_CS_CMYK)
            {
                (void)0;
            }
            if (t2p->pdf_defaultcompressionquality != 0)
            {
                TIFFSetField(output, TIFFTAG_JPEGQUALITY,
                             t2p->pdf_defaultcompressionquality);
            }
            break;
#endif
#ifdef ZIP_SUPPORT
        case T2P_COMPRESS_ZIP:
            TIFFSetField(output, TIFFTAG_COMPRESSION,
                         COMPRESSION_ADOBE_DEFLATE);
            if (t2p->pdf_defaultcompressionquality % 100 != 0)
            {
                TIFFSetField(output, TIFFTAG_PREDICTOR,
                             t2p->pdf_defaultcompressionquality % 100);
            }
            if (t2p->pdf_defaultcompressionquality / 100 != 0)
            {
                TIFFSetField(output, TIFFTAG_ZIPQUALITY,
                             (t2p->pdf_defaultcompressionquality / 100));
            }
            break;
#endif
        default:
            break;
    }

    if (TIFFStripSize(output) > t2p->tiff_datasize)
    {
        TIFFError(TIFF2PDF_MODULE,
                  "Size mismatch input %" PRId64 ", output %" PRId64,
                  (int64_t)t2p->tiff_datasize, (int64_t)TIFFStripSize(output));
        _TIFFfree(buffer);
        t2p->t2p_error = T2P_ERR_ERROR;
        return (0);
    }
    t2p_enable(output);
    t2p->outputwritten = 0;
    bufferoffset = TIFFWriteEncodedStrip(output, (tstrip_t)0, buffer,
                                         TIFFStripSize(output));
    if (buffer != NULL)
    {
        _TIFFfree(buffer);
        buffer = NULL;
    }
    if (bufferoffset == -1)
    {
        TIFFError(TIFF2PDF_MODULE,
                  "Error writing encoded tile to output PDF %s",
                  TIFFFileName(output));
        t2p->t2p_error = T2P_ERR_ERROR;
        return (0);
    }

    written = t2p->outputwritten;

    return (written);
}

tsize_t t2p_write_pdf(T2P *t2p, TIFF *input, TIFF *output)
{

    tsize_t written = 0;
    ttile_t i2 = 0;
    tsize_t streamlen = 0;
    uint16_t i = 0;

    t2p_read_tiff_init(t2p, input);
    if (t2p->t2p_error != T2P_ERR_OK)
    {
        return (0);
    }
    t2p->pdf_xrefoffsets = (uint32_t *)_TIFFmalloc(
        TIFFSafeMultiply(tmsize_t, t2p->pdf_xrefcount, sizeof(uint32_t)));
    if (t2p->pdf_xrefoffsets == NULL)
    {
        TIFFError(TIFF2PDF_MODULE,
                  "Can't allocate %" TIFF_SIZE_FORMAT
                  " bytes of memory for t2p_write_pdf",
                  sizeof(uint32_t) * t2p->pdf_xrefcount);
        t2p->t2p_error = T2P_ERR_ERROR;
        return (written);
    }
    t2p->pdf_xrefcount = 0;
    t2p->pdf_catalog = 1;
    t2p->pdf_info = 2;
    t2p->pdf_pages = 3;
    written += t2p_write_pdf_header(t2p, output);
    t2p->pdf_xrefoffsets[t2p->pdf_xrefcount++] =
        _TIFFCastSSizeToUInt32(written, "t2p_write_pdf");
    t2p->pdf_catalog = t2p->pdf_xrefcount;
    written += t2p_write_pdf_obj_start(t2p->pdf_xrefcount, output);
    written += t2p_write_pdf_catalog(t2p, output);
    written += t2p_write_pdf_obj_end(output);
    t2p->pdf_xrefoffsets[t2p->pdf_xrefcount++] =
        _TIFFCastSSizeToUInt32(written, "t2p_write_pdf");
    t2p->pdf_info = t2p->pdf_xrefcount;
    written += t2p_write_pdf_obj_start(t2p->pdf_xrefcount, output);
    written += t2p_write_pdf_info(t2p, input, output);
    written += t2p_write_pdf_obj_end(output);
    t2p->pdf_xrefoffsets[t2p->pdf_xrefcount++] =
        _TIFFCastSSizeToUInt32(written, "t2p_write_pdf");
    t2p->pdf_pages = t2p->pdf_xrefcount;
    written += t2p_write_pdf_obj_start(t2p->pdf_xrefcount, output);
    written += t2p_write_pdf_pages(t2p, output);
    written += t2p_write_pdf_obj_end(output);
    for (t2p->pdf_page = 0; t2p->pdf_page < t2p->tiff_pagecount;
         t2p->pdf_page++)
    {
        t2p_read_tiff_data(t2p, input);
        if (t2p->t2p_error != T2P_ERR_OK)
        {
            return (0);
        }
        t2p->pdf_xrefoffsets[t2p->pdf_xrefcount++] =
            _TIFFCastSSizeToUInt32(written, "t2p_write_pdf");
        written += t2p_write_pdf_obj_start(t2p->pdf_xrefcount, output);
        written += t2p_write_pdf_page(t2p->pdf_xrefcount, t2p, output);
        written += t2p_write_pdf_obj_end(output);
        t2p->pdf_xrefoffsets[t2p->pdf_xrefcount++] =
            _TIFFCastSSizeToUInt32(written, "t2p_write_pdf");
        written += t2p_write_pdf_obj_start(t2p->pdf_xrefcount, output);
        written += t2p_write_pdf_stream_dict_start(output);
        written += t2p_write_pdf_stream_dict(0, t2p->pdf_xrefcount + 1, output);
        written += t2p_write_pdf_stream_dict_end(output);
        written += t2p_write_pdf_stream_start(output);
        streamlen = written;
        written += t2p_write_pdf_page_content_stream(t2p, output);
        streamlen = written - streamlen;
        written += t2p_write_pdf_stream_end(output);
        written += t2p_write_pdf_obj_end(output);
        t2p->pdf_xrefoffsets[t2p->pdf_xrefcount++] =
            _TIFFCastSSizeToUInt32(written, "t2p_write_pdf");
        written += t2p_write_pdf_obj_start(t2p->pdf_xrefcount, output);
        written += t2p_write_pdf_stream_length(streamlen, output);
        written += t2p_write_pdf_obj_end(output);
        if (t2p->tiff_transferfunctioncount != 0)
        {
            t2p->pdf_xrefoffsets[t2p->pdf_xrefcount++] =
                _TIFFCastSSizeToUInt32(written, "t2p_write_pdf");
            written += t2p_write_pdf_obj_start(t2p->pdf_xrefcount, output);
            written += t2p_write_pdf_transfer(t2p, output);
            written += t2p_write_pdf_obj_end(output);
            for (i = 0; i < t2p->tiff_transferfunctioncount; i++)
            {
                t2p->pdf_xrefoffsets[t2p->pdf_xrefcount++] =
                    _TIFFCastSSizeToUInt32(written, "t2p_write_pdf");
                written += t2p_write_pdf_obj_start(t2p->pdf_xrefcount, output);
                written += t2p_write_pdf_stream_dict_start(output);
                written += t2p_write_pdf_transfer_dict(t2p, output, i);
                written += t2p_write_pdf_stream_dict_end(output);
                written += t2p_write_pdf_stream_start(output);
                /* streamlen=written; */ /* value not used */
                written += t2p_write_pdf_transfer_stream(t2p, output, i);
                /* streamlen=written-streamlen; */ /* value not used */
                written += t2p_write_pdf_stream_end(output);
                written += t2p_write_pdf_obj_end(output);
            }
        }
        if ((t2p->pdf_colorspace & T2P_CS_PALETTE) != 0)
        {
            t2p->pdf_xrefoffsets[t2p->pdf_xrefcount++] =
                _TIFFCastSSizeToUInt32(written, "t2p_write_pdf");
            t2p->pdf_palettecs = t2p->pdf_xrefcount;
            written += t2p_write_pdf_obj_start(t2p->pdf_xrefcount, output);
            written += t2p_write_pdf_stream_dict_start(output);
            written +=
                t2p_write_pdf_stream_dict(t2p->pdf_palettesize, 0, output);
            written += t2p_write_pdf_stream_dict_end(output);
            written += t2p_write_pdf_stream_start(output);
            /* streamlen=written; */ /* value not used */
            written += t2p_write_pdf_xobject_palettecs_stream(t2p, output);
            /* streamlen=written-streamlen; */ /* value not used */
            written += t2p_write_pdf_stream_end(output);
            written += t2p_write_pdf_obj_end(output);
        }
        if ((t2p->pdf_colorspace & T2P_CS_ICCBASED) != 0)
        {
            t2p->pdf_xrefoffsets[t2p->pdf_xrefcount++] =
                _TIFFCastSSizeToUInt32(written, "t2p_write_pdf");
            t2p->pdf_icccs = t2p->pdf_xrefcount;
            written += t2p_write_pdf_obj_start(t2p->pdf_xrefcount, output);
            written += t2p_write_pdf_stream_dict_start(output);
            written += t2p_write_pdf_xobject_icccs_dict(t2p, output);
            written += t2p_write_pdf_stream_dict_end(output);
            written += t2p_write_pdf_stream_start(output);
            /* streamlen=written; */ /* value not used */
            written += t2p_write_pdf_xobject_icccs_stream(t2p, output);
            /* streamlen=written-streamlen; */ /* value not used */
            written += t2p_write_pdf_stream_end(output);
            written += t2p_write_pdf_obj_end(output);
        }
        if (t2p->tiff_tiles[t2p->pdf_page].tiles_tilecount != 0)
        {
            for (i2 = 0; i2 < t2p->tiff_tiles[t2p->pdf_page].tiles_tilecount;
                 i2++)
            {
                t2p->pdf_xrefoffsets[t2p->pdf_xrefcount++] =
                    _TIFFCastSSizeToUInt32(written, "t2p_write_pdf");
                written += t2p_write_pdf_obj_start(t2p->pdf_xrefcount, output);
                written += t2p_write_pdf_stream_dict_start(output);
                written +=
                    t2p_write_pdf_xobject_stream_dict(i2 + 1, t2p, output);
                written += t2p_write_pdf_stream_dict_end(output);
                written += t2p_write_pdf_stream_start(output);
                streamlen = written;
                t2p_read_tiff_size_tile(t2p, input, i2);
                if (t2p->tiff_maxdatasize &&
                    (t2p->tiff_datasize > t2p->tiff_maxdatasize))
                {
                    TIFFError(TIFF2PDF_MODULE,
                              "Allocation of %" PRIu64
                              " bytes is forbidden. Limit is %" PRIu64
                              ". Use -m option to change limit",
                              (uint64_t)t2p->tiff_datasize,
                              (uint64_t)t2p->tiff_maxdatasize);
                    t2p->t2p_error = T2P_ERR_ERROR;
                    return (0);
                }
                written += t2p_readwrite_pdf_image_tile(t2p, input, output, i2);
                t2p_write_advance_directory(t2p, output);
                if (t2p->t2p_error != T2P_ERR_OK)
                {
                    return (0);
                }
                streamlen = written - streamlen;
                written += t2p_write_pdf_stream_end(output);
                written += t2p_write_pdf_obj_end(output);
                t2p->pdf_xrefoffsets[t2p->pdf_xrefcount++] =
                    _TIFFCastSSizeToUInt32(written, "t2p_write_pdf");
                written += t2p_write_pdf_obj_start(t2p->pdf_xrefcount, output);
                written += t2p_write_pdf_stream_length(streamlen, output);
                written += t2p_write_pdf_obj_end(output);
            }
        }
        else
        {
            t2p->pdf_xrefoffsets[t2p->pdf_xrefcount++] =
                _TIFFCastSSizeToUInt32(written, "t2p_write_pdf");
            written += t2p_write_pdf_obj_start(t2p->pdf_xrefcount, output);
            written += t2p_write_pdf_stream_dict_start(output);
            written += t2p_write_pdf_xobject_stream_dict(0, t2p, output);
            written += t2p_write_pdf_stream_dict_end(output);
            written += t2p_write_pdf_stream_start(output);
            streamlen = written;
            t2p_read_tiff_size(t2p, input);
            if (t2p->tiff_maxdatasize &&
                (t2p->tiff_datasize > t2p->tiff_maxdatasize))
            {
                TIFFError(TIFF2PDF_MODULE,
                          "Allocation of %" PRIu64
                          " bytes is forbidden. Limit is %" PRIu64
                          ". Use -m option to change limit",
                          (uint64_t)t2p->tiff_datasize,
                          (uint64_t)t2p->tiff_maxdatasize);
                t2p->t2p_error = T2P_ERR_ERROR;
                return (0);
            }
            written += t2p_readwrite_pdf_image(t2p, input, output);
            t2p_write_advance_directory(t2p, output);
            if (t2p->t2p_error != T2P_ERR_OK)
            {
                return (0);
            }
            streamlen = written - streamlen;
            written += t2p_write_pdf_stream_end(output);
            written += t2p_write_pdf_obj_end(output);
            t2p->pdf_xrefoffsets[t2p->pdf_xrefcount++] =
                _TIFFCastSSizeToUInt32(written, "t2p_write_pdf");
            written += t2p_write_pdf_obj_start(t2p->pdf_xrefcount, output);
            written += t2p_write_pdf_stream_length(streamlen, output);
            written += t2p_write_pdf_obj_end(output);
        }
    }
    t2p->pdf_startxref = _TIFFCastSSizeToUInt32(written, "t2p_write_pdf");
    written += t2p_write_pdf_xreftable(t2p, output);
    written += t2p_write_pdf_trailer(t2p, output);
    t2p_disable(output);

    return (written);
}

void PSColorSeparatePreamble(FILE *fd, uint32_t w, uint32_t h, int nc)
{
